function isFormActionElement(element) {
  if (!element?.tagName) return false;
  const tag = String(element.tagName).toUpperCase();
  return tag === "INPUT" || tag === "SELECT" || tag === "TEXTAREA";
}

function getAppRootElement(appOrElement) {
  if (!appOrElement) return null;
  const candidate = appOrElement?.element ?? appOrElement;
  if (candidate?.querySelector) return candidate;
  if (candidate?.[0]?.querySelector) return candidate[0];
  return null;
}

function isEditableTypingElement(element) {
  if (!(element instanceof HTMLElement)) return false;
  if (element instanceof HTMLTextAreaElement) {
    return !element.disabled && !element.readOnly;
  }
  if (element instanceof HTMLInputElement) {
    if (element.disabled || element.readOnly) return false;
    const type = String(element.type ?? "text").trim().toLowerCase();
    const typingTypes = new Set(["text", "search", "email", "url", "tel", "password", "number"]);
    return typingTypes.has(type);
  }
  if (element instanceof HTMLSelectElement) return false;
  return element.isContentEditable;
}

function appHasFocusedTypingInput(appOrElement) {
  const root = getAppRootElement(appOrElement);
  const active = document?.activeElement;
  if (!root || !(active instanceof HTMLElement)) return false;
  if (!root.contains(active)) return false;
  return isEditableTypingElement(active);
}

const throttledUiNoticeCache = new Map();

function shouldEmitThrottledUiNotice(cacheKey, ttlMs) {
  const key = String(cacheKey ?? "").trim() || "notice";
  const ttl = Math.max(50, Number(ttlMs ?? 1200) || 1200);
  const now = Date.now();
  const last = Number(throttledUiNoticeCache.get(key) ?? 0);
  if (now - last < ttl) return false;
  throttledUiNoticeCache.set(key, now);
  return true;
}

function notifyUiWarnThrottled(message, options = {}) {
  const text = String(message ?? "").trim();
  if (!text) return;
  const key = String(options.key ?? text);
  const ttlMs = Number(options.ttlMs ?? 1200);
  if (!shouldEmitThrottledUiNotice(`warn:${key}`, ttlMs)) return;
  if (
    text.includes("GM permissions are required")
    || text.includes("Only the GM can")
    || text.includes("change blocked")
  ) {
    logPlayerPermissionDebug("ui-warning", text, {
      key,
      ttlMs
    });
  }
  ui.notifications?.warn(text);
}

function notifyUiInfoThrottled(message, options = {}) {
  const text = String(message ?? "").trim();
  if (!text) return;
  const key = String(options.key ?? text);
  const ttlMs = Number(options.ttlMs ?? 1200);
  if (!shouldEmitThrottledUiNotice(`info:${key}`, ttlMs)) return;
  ui.notifications?.info(text);
}

function refreshTabAccessibility(root) {
  if (!root?.querySelectorAll) return;
  const tablists = Array.from(root.querySelectorAll("[role='tablist']"));
  for (const tablist of tablists) {
    const tabs = Array.from(tablist.querySelectorAll(".po-tab"));
    if (tabs.length === 0) continue;

    const activeTab = tabs.find((tab) => tab.classList.contains("is-active")) ?? tabs[0];
    for (const tab of tabs) {
      const isActive = tab === activeTab;
      tab.setAttribute("role", "tab");
      tab.setAttribute("aria-selected", isActive ? "true" : "false");
      tab.setAttribute("tabindex", isActive ? "0" : "-1");
    }

    if (tablist.dataset.poTabA11yBound === "1") continue;
    tablist.dataset.poTabA11yBound = "1";
    tablist.addEventListener("keydown", (event) => {
      const key = String(event.key ?? "");
      if (!["ArrowRight", "ArrowLeft", "Home", "End"].includes(key)) return;
      const currentTabs = Array.from(tablist.querySelectorAll(".po-tab"));
      if (currentTabs.length === 0) return;
      const current = event.target?.closest?.(".po-tab");
      const currentIndex = Math.max(0, currentTabs.indexOf(current));
      let targetIndex = currentIndex;
      if (key === "ArrowRight") targetIndex = (currentIndex + 1) % currentTabs.length;
      if (key === "ArrowLeft") targetIndex = (currentIndex - 1 + currentTabs.length) % currentTabs.length;
      if (key === "Home") targetIndex = 0;
      if (key === "End") targetIndex = currentTabs.length - 1;
      const target = currentTabs[targetIndex];
      if (!target) return;
      event.preventDefault();
      target.focus();
      target.click();
    });
  }
}

function syncNotesDisclosureState(root) {
  if (!root?.querySelectorAll) return;
  root.querySelectorAll(".po-watch-entry").forEach((entry, index) => {
    const notes = entry.querySelector(".po-notes");
    const toggleButton = entry.querySelector("[data-action='toggle-notes']");
    if (!notes || !toggleButton) return;
    if (!notes.id) notes.id = `po-notes-auto-${index}-${foundry.utils.randomID()}`;
    const expanded = notes.classList.contains("is-active");
    toggleButton.setAttribute("aria-controls", notes.id);
    toggleButton.setAttribute("aria-expanded", expanded ? "true" : "false");
    notes.setAttribute("aria-hidden", expanded ? "false" : "true");
  });
}

function sanitizeSocketIdentifier(value, options = {}) {
  const maxLength = Number.isFinite(Number(options.maxLength)) ? Math.max(1, Math.floor(Number(options.maxLength))) : 128;
  const normalized = String(value ?? "").trim();
  if (!normalized || normalized.length > maxLength) return "";
  if (!/^[A-Za-z0-9._:-]+$/.test(normalized)) return "";
  return normalized;
}

function clampSocketText(value, maxLength = SOCKET_NOTE_MAX_LENGTH) {
  const cap = Number.isFinite(Number(maxLength)) ? Math.max(0, Math.floor(Number(maxLength))) : SOCKET_NOTE_MAX_LENGTH;
  return String(value ?? "").slice(0, cap);
}

function clampRestWatchRichNoteText(value, maxLength = SOCKET_NOTE_MAX_LENGTH) {
  const cap = Number.isFinite(Number(maxLength)) ? Math.max(0, Math.floor(Number(maxLength))) : SOCKET_NOTE_MAX_LENGTH;
  const raw = String(value ?? "");
  if (!raw || cap <= 0) return "";
  if (typeof document === "undefined" || typeof document.createElement !== "function") {
    return clampSocketText(raw, cap);
  }
  const scratch = document.createElement("div");
  scratch.innerHTML = raw;
  const plainText = String(scratch.textContent ?? "");
  if (plainText.length <= cap) return raw;
  const truncated = plainText.slice(0, cap);
  return `<p>${poEscapeHtml(truncated).replace(/\n/g, "<br>")}</p>`;
}

function normalizeRestNoteSaveSource(value) {
  const normalized = String(value ?? "").trim().toLowerCase();
  return normalized === "manual" ? "manual" : "autosave";
}

function resolveRequester(userOrId, options = {}) {
  const allowGM = options.allowGM !== false;
  const requireActive = options.requireActive === true;
  const requester = typeof userOrId === "string" ? game.users.get(userOrId) : userOrId;
  if (!requester) return null;
  if (!allowGM && requester.isGM) return null;
  if (requireActive && !requester.active) return null;
  return requester;
}

function getSocketRequester(message, options = {}) {
  const userId = sanitizeSocketIdentifier(message?.userId, { maxLength: 64 });
  if (!userId) return null;
  return resolveRequester(userId, options);
}

function normalizeSocketActivityType(value) {
  const normalized = String(value ?? "").trim().toLowerCase();
  return SOCKET_ACTIVITY_TYPES.has(normalized) ? normalized : "";
}

function isWritableModuleSettingKey(settingKeyInput) {
  const settingKey = String(settingKeyInput ?? "").trim();
  if (!settingKey) return false;
  return Object.values(SETTINGS).includes(settingKey);
}


function canAccessAllPlayerOps(user = game.user) {
  if (!user) return false;
  if (Boolean(user?.isGM)) return true;
  try {
    return Boolean(game.settings?.get?.(MODULE_ID, SETTINGS.SHARED_GM_PERMISSIONS));
  } catch {
    return false;
  }
}

function hasActiveGmClient() {
  const users = game.users?.contents ?? game.users ?? [];
  return users.some((user) => Boolean(user?.active) && Boolean(user?.isGM));
}

function getPlayerUiLocalOverrideStorageKey() {
  return `po-player-ui-setting-overrides-${game.user?.id ?? "anon"}`;
}

function getPlayerPermissionDebugStorageKey() {
  return `po-permission-debug-${game.user?.id ?? "anon"}`;
}

function readSessionStorageJson(key, fallback) {
  try {
    const raw = globalThis.sessionStorage?.getItem?.(key);
    if (!raw) return fallback;
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === "object" ? parsed : fallback;
  } catch {
    return fallback;
  }
}

function writeSessionStorageJson(key, value) {
  try {
    globalThis.sessionStorage?.setItem?.(key, JSON.stringify(value));
    return true;
  } catch {
    return false;
  }
}

function readPlayerUiLocalSettingOverrides() {
  const key = getPlayerUiLocalOverrideStorageKey();
  const stored = readSessionStorageJson(key, null);
  if (stored && typeof stored === "object" && !Array.isArray(stored)) return stored;
  return Object.fromEntries(playerUiLocalSettingOverridesMemory.entries());
}

function writePlayerUiLocalSettingOverrides(overrides = {}) {
  const normalized = overrides && typeof overrides === "object" && !Array.isArray(overrides)
    ? overrides
    : {};
  playerUiLocalSettingOverridesMemory.clear();
  for (const [key, value] of Object.entries(normalized)) {
    playerUiLocalSettingOverridesMemory.set(String(key ?? "").trim(), foundry.utils.deepClone(value));
  }
  writeSessionStorageJson(getPlayerUiLocalOverrideStorageKey(), normalized);
}

function getPlayerUiLocalSettingOverride(settingKey) {
  const normalizedSettingKey = String(settingKey ?? "").trim();
  if (!normalizedSettingKey) return undefined;
  const overrides = readPlayerUiLocalSettingOverrides();
  if (!Object.prototype.hasOwnProperty.call(overrides, normalizedSettingKey)) return undefined;
  return foundry.utils.deepClone(overrides[normalizedSettingKey]);
}

function setPlayerUiLocalSettingOverride(settingKey, value) {
  const normalizedSettingKey = String(settingKey ?? "").trim();
  if (!normalizedSettingKey) return false;
  const overrides = readPlayerUiLocalSettingOverrides();
  overrides[normalizedSettingKey] = foundry.utils.deepClone(value);
  writePlayerUiLocalSettingOverrides(overrides);
  return true;
}

function canUsePlayerUiLocalOverride(settingKey, user = game.user) {
  const normalizedSettingKey = String(settingKey ?? "").trim();
  return Boolean(
    normalizedSettingKey
    && PLAYER_UI_LOCAL_OVERRIDE_SETTING_KEYS.has(normalizedSettingKey)
    && user
    && !user.isGM
    && canAccessAllPlayerOps(user)
    && !hasActiveGmClient()
  );
}

function getModuleSettingWithPlayerUiOverride(settingKey) {
  const normalizedSettingKey = String(settingKey ?? "").trim();
  if (!normalizedSettingKey) return undefined;
  if (canUsePlayerUiLocalOverride(normalizedSettingKey)) {
    const override = getPlayerUiLocalSettingOverride(normalizedSettingKey);
    if (override !== undefined) return override;
  }
  return game.settings.get(MODULE_ID, normalizedSettingKey);
}

function logPlayerPermissionDebug(code, message, details = {}) {
  const entry = {
    at: new Date().toISOString(),
    userId: String(game.user?.id ?? "").trim(),
    userName: String(game.user?.name ?? "Unknown").trim() || "Unknown",
    code: String(code ?? "").trim() || "unknown",
    message: String(message ?? "").trim() || "Permission barrier encountered.",
    details: details && typeof details === "object" && !Array.isArray(details)
      ? foundry.utils.deepClone(details)
      : {}
  };
  playerPermissionDebugMemory.unshift(entry);
  if (playerPermissionDebugMemory.length > PLAYER_PERMISSION_DEBUG_LIMIT) {
    playerPermissionDebugMemory.length = PLAYER_PERMISSION_DEBUG_LIMIT;
  }
  const stored = readSessionStorageJson(getPlayerPermissionDebugStorageKey(), []);
  const next = [entry, ...(Array.isArray(stored) ? stored : [])].slice(0, PLAYER_PERMISSION_DEBUG_LIMIT);
  writeSessionStorageJson(getPlayerPermissionDebugStorageKey(), next);
  console.warn(`[${MODULE_ID}][permission-debug] ${entry.message}`, entry);
  try {
    globalThis.dispatchEvent?.(new CustomEvent(`${MODULE_ID}:permission-debug`, { detail: entry }));
  } catch {
    // Ignore event dispatch failures in older browser contexts.
  }
  return entry;
}

function getPlayerPermissionDebugEntries() {
  const stored = readSessionStorageJson(getPlayerPermissionDebugStorageKey(), []);
  const entries = Array.isArray(stored) ? stored : playerPermissionDebugMemory;
  return foundry.utils.deepClone(entries);
}

function clearPlayerPermissionDebugEntries() {
  playerPermissionDebugMemory.length = 0;
  try {
    globalThis.sessionStorage?.removeItem?.(getPlayerPermissionDebugStorageKey());
  } catch {
    // Ignore storage cleanup failures.
  }
}

function getRenderableElementRoot(html) {
  if (!html) return null;
  if (html instanceof HTMLElement) return html;
  if (Array.isArray(html) && html[0] instanceof HTMLElement) return html[0];
  if (html?.[0] instanceof HTMLElement) return html[0];
  if (typeof html?.get === "function") {
    const node = html.get(0);
    if (node instanceof HTMLElement) return node;
  }
  return null;
}

function parseFolderOwnershipBatchLevelsFromSubmitData(submitData = {}) {
  const source = submitData && typeof submitData === "object" ? submitData : {};
  const levels = {};
  for (const [key, rawValue] of Object.entries(source)) {
    const textKey = String(key ?? "").trim();
    if (!textKey.startsWith("ownership.")) continue;
    const ownershipKey = textKey.slice("ownership.".length).trim();
    if (!ownershipKey) continue;
    const levelRaw = Number(rawValue);
    if (!Number.isFinite(levelRaw) || levelRaw < 0) continue;
    const level = Math.max(
      Number(CONST?.DOCUMENT_OWNERSHIP_LEVELS?.NONE ?? 0),
      Math.min(Number(CONST?.DOCUMENT_OWNERSHIP_LEVELS?.OWNER ?? 3), Math.trunc(levelRaw))
    );
    levels[ownershipKey] = level;
  }
  return levels;
}

function bindFolderOwnershipProxySubmit(app, html) {
  if (game.user?.isGM) return;
  if (!canAccessAllPlayerOps()) return;
  const document = app?.document ?? null;
  if (!document || String(document?.documentName ?? "").trim() !== "Folder") return;
  if (String(document?.type ?? "").trim() !== "JournalEntry") return;
  const folderId = String(document?.id ?? "").trim();
  if (!folderId) return;
  const rootFolder = findOperationsJournalRootFolder?.() ?? null;
  const rootFolderId = String(rootFolder?.id ?? "").trim();
  if (!rootFolderId) return;
  const isOperationsJournalFolder = folderId === rootFolderId
    || Boolean(journalFolderIsUnderRoot?.(folderId, rootFolderId));
  if (!isOperationsJournalFolder) return;
  const root = getRenderableElementRoot(html);
  const form = root?.querySelector?.("form");
  if (!(form instanceof HTMLFormElement)) return;
  if (form.dataset.poOwnershipProxyBound === "1") return;
  form.dataset.poOwnershipProxyBound = "1";

  form.addEventListener("submit", async (event) => {
    if (game.user?.isGM || !canAccessAllPlayerOps()) return;
    event.preventDefault();
    event.stopPropagation();

    let submitData = {};
    try {
      if (typeof app?._getSubmitData === "function") {
        submitData = app._getSubmitData() ?? {};
      } else {
        const raw = new FormData(form);
        submitData = Object.fromEntries(raw.entries());
      }
    } catch (error) {
      console.warn(`${MODULE_ID}: failed reading folder ownership submit data`, error);
      ui.notifications?.warn("Unable to read folder permission changes.");
      return;
    }

    const levels = parseFolderOwnershipBatchLevelsFromSubmitData(submitData);
    if (Object.keys(levels).length <= 0) {
      ui.notifications?.info("No ownership changes selected.");
      return;
    }

    try {
      game.socket.emit(SOCKET_CHANNEL, {
        type: "ops:folder-ownership-write",
        userId: game.user.id,
        folderId,
        levels
      });
      ui.notifications?.info("Applying folder permissions through active GM...");
      app.close();
    } catch (error) {
      console.warn(`${MODULE_ID}: failed sending folder ownership proxy request`, error);
      ui.notifications?.warn("Failed to send folder permission update request.");
    }
  });
}

function normalizeStewardPoolMode(value) {
  const normalized = String(value ?? "").trim().toLowerCase();
  if (normalized === STEWARD_POOL_MODES.FINITE) return STEWARD_POOL_MODES.FINITE;
  if (normalized === STEWARD_POOL_MODES.INFINITE) return STEWARD_POOL_MODES.INFINITE;
  return STEWARD_POOL_MODES.NONE;
}

function getStewardPoolLegacyField(poolKey) {
  return String(STEWARD_POOL_LEGACY_FIELD_BY_KEY[poolKey] ?? "").trim();
}

function normalizeStewardPoolEntry(entryInput, poolKey, resources) {
  const legacyField = getStewardPoolLegacyField(poolKey);
  const legacyRaw = Number(resources?.[legacyField] ?? 0);
  const legacyAmount = Number.isFinite(legacyRaw) ? Math.max(0, Math.floor(legacyRaw)) : 0;
  const entry = (entryInput && typeof entryInput === "object" && !Array.isArray(entryInput))
    ? entryInput
    : {};
  const hasExplicitMode = Object.prototype.hasOwnProperty.call(entry, "mode");
  let mode = normalizeStewardPoolMode(entry.mode);
  const amountRaw = Number(entry.amount);
  const amount = Number.isFinite(amountRaw) ? Math.max(0, Math.floor(amountRaw)) : legacyAmount;
  if (!hasExplicitMode) mode = amount > 0 ? STEWARD_POOL_MODES.FINITE : STEWARD_POOL_MODES.NONE;
  const source = String(entry.source ?? "").trim().slice(0, 180);
  return { mode, amount, source };
}

function ensureStewardPoolsState(resources) {
  if (!resources || typeof resources !== "object") return {};
  if (!resources.stewardPools || typeof resources.stewardPools !== "object" || Array.isArray(resources.stewardPools)) {
    resources.stewardPools = {};
  }
  for (const poolKey of STEWARD_POOL_KEYS) {
    const normalized = normalizeStewardPoolEntry(resources.stewardPools[poolKey], poolKey, resources);
    resources.stewardPools[poolKey] = normalized;
    const legacyField = getStewardPoolLegacyField(poolKey);
    if (legacyField) {
      resources[legacyField] = normalized.mode === STEWARD_POOL_MODES.FINITE ? normalized.amount : 0;
    }
  }
  return resources.stewardPools;
}

function getStewardPoolEntry(resources, poolKey) {
  const pools = ensureStewardPoolsState(resources);
  const pool = pools?.[poolKey];
  if (pool && typeof pool === "object") return pool;
  return { mode: STEWARD_POOL_MODES.NONE, amount: 0, source: "" };
}

function buildStewardPoolContext(resourcesState, poolKey) {
  const pool = getStewardPoolEntry(resourcesState, poolKey);
  const mode = normalizeStewardPoolMode(pool.mode);
  const amount = Math.max(0, Math.floor(Number(pool.amount ?? 0) || 0));
  const source = String(pool.source ?? "").trim();
  const modeOptions = [
    { value: STEWARD_POOL_MODES.NONE, label: "None", selected: mode === STEWARD_POOL_MODES.NONE },
    { value: STEWARD_POOL_MODES.INFINITE, label: "Surplus Source", selected: mode === STEWARD_POOL_MODES.INFINITE },
    { value: STEWARD_POOL_MODES.FINITE, label: "Finite Stock", selected: mode === STEWARD_POOL_MODES.FINITE }
  ];
  const modeLabel = mode === STEWARD_POOL_MODES.INFINITE
    ? "Surplus Source"
    : (mode === STEWARD_POOL_MODES.FINITE ? "Finite Stock" : "None");
  const amountDisplay = mode === STEWARD_POOL_MODES.FINITE
    ? String(amount)
    : (mode === STEWARD_POOL_MODES.INFINITE ? "Surplus" : "None");
  return {
    key: poolKey,
    label: STEWARD_POOL_LABELS[poolKey] ?? poolKey,
    mode,
    modeOptions,
    modeLabel,
    source,
    hasSource: source.length > 0,
    amount,
    amountDisplay,
    isNone: mode === STEWARD_POOL_MODES.NONE,
    isFinite: mode === STEWARD_POOL_MODES.FINITE,
    isInfinite: mode === STEWARD_POOL_MODES.INFINITE,
    summaryLabel: source.length > 0 ? `${amountDisplay} - ${source}` : amountDisplay
  };
}

function getStewardPoolFiniteAmount(pool) {
  if (!pool || typeof pool !== "object") return 0;
  if (normalizeStewardPoolMode(pool.mode) !== STEWARD_POOL_MODES.FINITE) return 0;
  return Math.max(0, Math.floor(Number(pool.amount ?? 0) || 0));
}

function isStewardPoolInfinite(pool) {
  if (!pool || typeof pool !== "object") return false;
  return normalizeStewardPoolMode(pool.mode) === STEWARD_POOL_MODES.INFINITE;
}

function getGatherSelectableActorsForUser(user = game.user) {
  if (!user) return [];
  const unique = new Map();
  const addActor = (actor) => {
    if (!actor || actor.type !== "character" || !actor.id) return;
    if (!canUserManageDowntimeActor(user, actor)) return;
    unique.set(String(actor.id), actor);
  };

  if (user.character?.type === "character") addActor(user.character);
  for (const actor of getOwnedPcActors()) addActor(actor);
  for (const actor of game.actors?.contents ?? []) addActor(actor);

  return Array.from(unique.values()).sort((a, b) => (a.name ?? "").localeCompare(b.name ?? ""));
}

function normalizeGatherRequestPayload(input = {}) {
  const source = (input && typeof input === "object" && !Array.isArray(input)) ? input : {};
  return {
    id: String(source.id ?? foundry.utils.randomID()).trim() || foundry.utils.randomID(),
    actorId: String(source.actorId ?? "").trim(),
    actorName: String(source.actorName ?? "").trim(),
    requesterUserId: String(source.requesterUserId ?? "").trim(),
    requesterName: String(source.requesterName ?? "").trim(),
    requestedAt: Number.isFinite(Number(source.requestedAt)) ? Number(source.requestedAt) : Date.now(),
    resourceType: normalizeGatherResourceType(source.resourceType),
    environment: normalizeGatherEnvironmentKey(source.environment),
    gatherMode: String(source.gatherMode ?? "standard").trim().toLowerCase() === "plant" ? "plant" : "standard",
    hoursSpent: Math.max(1, Math.floor(Number(source.hoursSpent ?? 4) || 4)),
    seasonMod: clampGatherModifier(source.seasonMod, 0),
    weatherMod: clampGatherModifier(source.weatherMod, 0),
    corruptionMod: clampGatherModifier(source.corruptionMod, 0),
    isCorruptedRegion: Boolean(source.isCorruptedRegion),
    hostileTerrain: Boolean(source.hostileTerrain),
    waterAutoFound: Boolean(source.waterAutoFound),
    duringTravel: Boolean(source.duringTravel),
    travelTradeoff: normalizeGatherTravelTradeoff(source.travelTradeoff),
    applyToLedger: source.applyToLedger !== false
  };
}

function ensureOperationalResourceConfig(resources) {
  if (!resources) return;
  const legacyFoodPool = Number(resources.partyRations);
  const configuredFoodPool = Number(resources.partyFoodRations);
  const configuredWaterPool = Number(resources.partyWaterRations);
  const configuredTorchPool = Number(resources.torches);
  resources.partyFoodRations = Number.isFinite(configuredFoodPool)
    ? Math.max(0, Math.floor(configuredFoodPool))
    : (Number.isFinite(legacyFoodPool) ? Math.max(0, Math.floor(legacyFoodPool)) : 0);
  resources.partyWaterRations = Number.isFinite(configuredWaterPool) ? Math.max(0, Math.floor(configuredWaterPool)) : 0;
  resources.torches = Number.isFinite(configuredTorchPool) ? Math.max(0, Math.floor(configuredTorchPool)) : 0;
  if (Object.prototype.hasOwnProperty.call(resources, "partyRations")) delete resources.partyRations;
  const upkeepTimestamp = Number(resources.upkeepLastAppliedTs);
  resources.upkeepLastAppliedTs = Number.isFinite(upkeepTimestamp) ? upkeepTimestamp : null;
  if (!resources.itemSelections) resources.itemSelections = {};
  for (const key of RESOURCE_TRACK_KEYS) {
    if (!resources.itemSelections[key]) resources.itemSelections[key] = { actorId: "", itemId: "" };
    if (typeof resources.itemSelections[key].actorId !== "string") resources.itemSelections[key].actorId = "";
    if (typeof resources.itemSelections[key].itemId !== "string") resources.itemSelections[key].itemId = "";
  }
  if (!resources.gather) resources.gather = {};
  if (!resources.gather.weatherMods) resources.gather.weatherMods = {};
  if (!Array.isArray(resources.gather.requests)) resources.gather.requests = [];
  resources.gather.requests = resources.gather.requests
    .map((entry) => {
      const source = (entry && typeof entry === "object") ? entry : {};
      const requestedAtRaw = Number(source.requestedAt ?? source.timestamp ?? Date.now());
      const requestedAt = Number.isFinite(requestedAtRaw) ? requestedAtRaw : Date.now();
      return {
        id: String(source.id ?? foundry.utils.randomID()).trim() || foundry.utils.randomID(),
        actorId: String(source.actorId ?? "").trim(),
        actorName: String(source.actorName ?? "Unknown Actor").trim() || "Unknown Actor",
        requesterUserId: String(source.requesterUserId ?? "").trim(),
        requesterName: String(source.requesterName ?? "Player").trim() || "Player",
        requestedAt,
        resourceType: normalizeGatherResourceType(source.resourceType),
        environment: normalizeGatherEnvironmentKey(source.environment),
        gatherMode: String(source.gatherMode ?? "standard").trim().toLowerCase() === "plant" ? "plant" : "standard",
        hoursSpent: Math.max(1, Math.floor(Number(source.hoursSpent ?? 4) || 4)),
        seasonMod: clampGatherModifier(source.seasonMod, 0),
        weatherMod: clampGatherModifier(source.weatherMod, 0),
        corruptionMod: clampGatherModifier(source.corruptionMod, 0),
        isCorruptedRegion: Boolean(source.isCorruptedRegion),
        hostileTerrain: Boolean(source.hostileTerrain),
        waterAutoFound: Boolean(source.waterAutoFound),
        duringTravel: Boolean(source.duringTravel),
        travelTradeoff: normalizeGatherTravelTradeoff(source.travelTradeoff),
        applyToLedger: source.applyToLedger !== false
      };
    })
    .sort((a, b) => Number(b.requestedAt ?? 0) - Number(a.requestedAt ?? 0));
  if (!Array.isArray(resources.gather.history)) resources.gather.history = [];
  resources.gather.history = resources.gather.history
    .map((entry) => {
      const source = (entry && typeof entry === "object") ? entry : {};
      const timestampRaw = Number(source.timestamp ?? source.createdAt ?? Date.now());
      const timestamp = Number.isFinite(timestampRaw) ? timestampRaw : Date.now();
      const resultRaw = String(source.result ?? "").trim().toLowerCase();
      const result = resultRaw === "success" || resultRaw === "fail" ? resultRaw : (Boolean(source.success) ? "success" : "fail");
      return {
        id: String(source.id ?? foundry.utils.randomID()).trim() || foundry.utils.randomID(),
        timestamp,
        actorId: String(source.actorId ?? "").trim(),
        actorName: String(source.actorName ?? "Unknown Actor").trim() || "Unknown Actor",
        dayKey: String(source.dayKey ?? "").trim(),
        result,
        success: result === "success",
        resourceType: normalizeGatherResourceType(source.resourceType),
        rations: Math.max(0, Math.floor(Number(source.rations ?? source.finalRations ?? 0) || 0)),
        checkTotal: Math.floor(Number(source.checkTotal ?? source.rollTotal ?? 0) || 0),
        dc: Math.max(1, Math.floor(Number(source.dc ?? 1) || 1)),
        environment: normalizeGatherEnvironmentKey(source.environment),
        flags: Array.isArray(source.flags) ? source.flags.map((flag) => String(flag ?? "").trim()).filter(Boolean) : [],
        complications: Array.isArray(source.complications) ? source.complications.map((flag) => String(flag ?? "").trim()).filter(Boolean) : [],
        notes: Array.isArray(source.notes) ? source.notes.map((note) => String(note ?? "").trim()).filter(Boolean) : [],
        gatherMode: String(source.gatherMode ?? "standard").trim().toLowerCase() === "plant" ? "plant" : "standard",
        appliedToLedger: Boolean(source.appliedToLedger),
        inventoryGainSource: String(source.inventoryGainSource ?? "").trim(),
        inventoryGainAmount: Math.max(0, Math.floor(Number(source.inventoryGainAmount ?? 0) || 0)),
        createdBy: String(source.createdBy ?? "GM").trim() || "GM",
        requesterUserId: String(source.requesterUserId ?? "").trim(),
        requesterName: String(source.requesterName ?? "").trim(),
        approvedBy: String(source.approvedBy ?? "").trim(),
        rationDieTotal: Number.isFinite(Number(source.rationDieTotal)) ? Math.max(0, Math.floor(Number(source.rationDieTotal) || 0)) : null,
        yieldRollSource: String(source.yieldRollSource ?? "").trim(),
        yieldRolledBy: String(source.yieldRolledBy ?? "").trim()
      };
    })
    .sort((a, b) => Number(b.timestamp ?? 0) - Number(a.timestamp ?? 0));
  if (!resources.gather.pendingPools || typeof resources.gather.pendingPools !== "object") {
    resources.gather.pendingPools = { food: 0, water: 0 };
  }
  resources.gather.pendingPools.food = Math.max(0, Math.floor(Number(resources.gather.pendingPools.food ?? 0) || 0));
  resources.gather.pendingPools.water = Math.max(0, Math.floor(Number(resources.gather.pendingPools.water ?? 0) || 0));
  if (!resources.gather.autoUpkeepPrompt || typeof resources.gather.autoUpkeepPrompt !== "object") {
    resources.gather.autoUpkeepPrompt = {};
  }
  const rawPromptState = String(resources.gather.autoUpkeepPrompt.state ?? AUTO_UPKEEP_PROMPT_STATES.IDLE).trim().toLowerCase();
  resources.gather.autoUpkeepPrompt.state = Object.values(AUTO_UPKEEP_PROMPT_STATES).includes(rawPromptState)
    ? rawPromptState
    : AUTO_UPKEEP_PROMPT_STATES.IDLE;
  resources.gather.autoUpkeepPrompt.messageId = String(resources.gather.autoUpkeepPrompt.messageId ?? "").trim();
  resources.gather.autoUpkeepPrompt.createdAt = Math.max(0, Number(resources.gather.autoUpkeepPrompt.createdAt ?? 0) || 0);
  resources.gather.autoUpkeepPrompt.dayKey = String(resources.gather.autoUpkeepPrompt.dayKey ?? "").trim();
  resources.gather.autoUpkeepPrompt.lastResolvedAt = Math.max(0, Number(resources.gather.autoUpkeepPrompt.lastResolvedAt ?? 0) || 0);
  if (typeof resources.gather.foodCoveredNextUpkeep !== "boolean") resources.gather.foodCoveredNextUpkeep = false;
  if (typeof resources.gather.waterCoveredNextUpkeep !== "boolean") resources.gather.waterCoveredNextUpkeep = false;
  const foodCoverageDueKey = Number(resources.gather.foodCoverageDueKey);
  resources.gather.foodCoverageDueKey = Number.isFinite(foodCoverageDueKey) ? foodCoverageDueKey : null;
  const waterCoverageDueKey = Number(resources.gather.waterCoverageDueKey);
  resources.gather.waterCoverageDueKey = Number.isFinite(waterCoverageDueKey) ? waterCoverageDueKey : null;
  const defaultWeatherMods = {
    clear: 0,
    "light-rain": 2,
    "heavy-rain": 5,
    wind: 2,
    fog: 3,
    extreme: 5
  };
  for (const [key, value] of Object.entries(defaultWeatherMods)) {
    const current = Number(resources.gather.weatherMods[key]);
    resources.gather.weatherMods[key] = Number.isFinite(current) ? current : value;
  }
  if (!resources.upkeep) resources.upkeep = {};
  ensureStewardPoolsState(resources);
}

function getGatherPendingPoolAmount(resourcesState, resourceType) {
  const key = normalizeGatherResourceType(resourceType);
  if (!["food", "water"].includes(key)) return 0;
  return Math.max(0, Math.floor(Number(resourcesState?.gather?.pendingPools?.[key] ?? 0) || 0));
}

function getAutoUpkeepPromptState(resourcesState) {
  const rawState = String(resourcesState?.gather?.autoUpkeepPrompt?.state ?? AUTO_UPKEEP_PROMPT_STATES.IDLE).trim().toLowerCase();
  return Object.values(AUTO_UPKEEP_PROMPT_STATES).includes(rawState)
    ? rawState
    : AUTO_UPKEEP_PROMPT_STATES.IDLE;
}

function getAutoUpkeepPromptData(resourcesState) {
  return {
    state: getAutoUpkeepPromptState(resourcesState),
    messageId: String(resourcesState?.gather?.autoUpkeepPrompt?.messageId ?? "").trim(),
    createdAt: Math.max(0, Number(resourcesState?.gather?.autoUpkeepPrompt?.createdAt ?? 0) || 0),
    dayKey: String(resourcesState?.gather?.autoUpkeepPrompt?.dayKey ?? "").trim(),
    lastResolvedAt: Math.max(0, Number(resourcesState?.gather?.autoUpkeepPrompt?.lastResolvedAt ?? 0) || 0)
  };
}

function hasGatherAttemptsForDay(resourcesState, dayKey) {
  const targetDayKey = String(dayKey ?? "").trim();
  if (!targetDayKey) return false;
  const history = Array.isArray(resourcesState?.gather?.history) ? resourcesState.gather.history : [];
  return history.some((entry) => String(entry?.dayKey ?? "").trim() === targetDayKey);
}

function hasPendingGatherRequests(resourcesState) {
  return Array.isArray(resourcesState?.gather?.requests) && resourcesState.gather.requests.length > 0;
}

async function setAutomaticUpkeepPromptState(nextState, updates = {}) {
  const normalizedState = Object.values(AUTO_UPKEEP_PROMPT_STATES).includes(String(nextState ?? "").trim().toLowerCase())
    ? String(nextState).trim().toLowerCase()
    : AUTO_UPKEEP_PROMPT_STATES.IDLE;
  await updateOperationsLedger((ledger) => {
    if (!ledger.resources) ledger.resources = {};
    ensureOperationalResourceConfig(ledger.resources);
    ledger.resources.gather.autoUpkeepPrompt.state = normalizedState;
    if (Object.prototype.hasOwnProperty.call(updates, "messageId")) {
      ledger.resources.gather.autoUpkeepPrompt.messageId = String(updates.messageId ?? "").trim();
    }
    if (Object.prototype.hasOwnProperty.call(updates, "createdAt")) {
      ledger.resources.gather.autoUpkeepPrompt.createdAt = Math.max(0, Number(updates.createdAt ?? 0) || 0);
    }
    if (Object.prototype.hasOwnProperty.call(updates, "dayKey")) {
      ledger.resources.gather.autoUpkeepPrompt.dayKey = String(updates.dayKey ?? "").trim();
    }
    if (Object.prototype.hasOwnProperty.call(updates, "lastResolvedAt")) {
      ledger.resources.gather.autoUpkeepPrompt.lastResolvedAt = Math.max(0, Number(updates.lastResolvedAt ?? 0) || 0);
    }
  }, { skipLocalRefresh: true });
}

async function clearAutomaticUpkeepPromptState(reason = "Automatic upkeep prompt resolved.") {
  const resources = getOperationsLedger().resources ?? {};
  ensureOperationalResourceConfig(resources);
  const prompt = getAutoUpkeepPromptData(resources);
  const existing = prompt.messageId ? game.messages?.get?.(prompt.messageId) ?? null : null;
  if (existing) {
    await existing.update({
      content: `<div class="po-chat-card po-chat-card-gather"><p><strong>Automatic Upkeep</strong></p><p>${poEscapeHtml(String(reason))}</p></div>`,
      flags: {
        [MODULE_ID]: {
          autoUpkeepPrompt: {
            state: AUTO_UPKEEP_PROMPT_STATES.IDLE,
            dayKey: prompt.dayKey
          }
        }
      }
    });
  }
  return setAutomaticUpkeepPromptState(AUTO_UPKEEP_PROMPT_STATES.IDLE, {
    messageId: "",
    createdAt: 0,
    dayKey: "",
    lastResolvedAt: Date.now()
  });
}

function ensurePartyOperationsClass(appOrElement) {
  const root = getAppRootElement(appOrElement);
  if (!(root instanceof HTMLElement)) return;
  const frame = root.matches(".window-app, .application")
    ? root
    : root.closest(".window-app, .application");
  if (!frame?.classList) return;
  const hasPartyOpsWindow = Boolean(
    frame.querySelector?.(".po-window[data-tool], .po-window[data-main-tab]")
  );
  if (!hasPartyOpsWindow) return;
  frame.classList.add("party-operations");
}

function applyNonGmOperationsReadonly(appOrElement) {
  if (game.user?.isGM) return;  // Only actual GMs bypass readonly restrictions; shared-perm players still need restrictions
  const root = getAppRootElement(appOrElement);
  if (!root) return;
  const operationsWindow = root.querySelector(".po-window[data-main-tab='operations'], .po-window[data-main-tab='gm']");
  if (!operationsWindow) return;

  operationsWindow.querySelectorAll("[data-action]").forEach((element) => {
    const action = String(element?.dataset?.action ?? "").trim();
    if (!NON_GM_READONLY_ACTIONS.has(action)) return;
    if ("disabled" in element) element.disabled = true;
    element.setAttribute("aria-disabled", "true");
    element.dataset.poReadonly = "true";
    const existingTitle = String(element.getAttribute("title") ?? "").trim();
    if (!existingTitle.includes("GM only")) {
      const suffix = existingTitle ? ` ${existingTitle}` : "";
      element.setAttribute("title", `GM only.${suffix}`.trim());
    }
  });

  const selector = [
    ".po-base-site-editor input",
    ".po-base-site-editor select",
    ".po-injury-editor input",
    ".po-injury-editor select",
    ".po-injury-editor textarea",
    ".po-reputation-builder input",
    ".po-reputation-builder select",
    ".po-reputation-builder textarea"
  ].join(", ");
  operationsWindow.querySelectorAll(selector).forEach((element) => {
    if ("disabled" in element) element.disabled = true;
    element.setAttribute("aria-disabled", "true");
    element.dataset.poReadonly = "true";
  });
}

function suppressNextSettingRefresh(fullSettingKey) {
  if (!fullSettingKey) return;
  const count = suppressedSettingRefreshKeys.get(fullSettingKey) ?? 0;
  suppressedSettingRefreshKeys.set(fullSettingKey, count + 1);
}

function consumeSuppressedSettingRefresh(fullSettingKey) {
  const count = suppressedSettingRefreshKeys.get(fullSettingKey) ?? 0;
  if (count <= 0) return false;
  if (count === 1) suppressedSettingRefreshKeys.delete(fullSettingKey);
  else suppressedSettingRefreshKeys.set(fullSettingKey, count - 1);
  return true;
}

async function setModuleSettingWithLocalRefreshSuppressed(settingKey, value) {
  const normalizedSettingKey = String(settingKey ?? "").trim();
  if (!normalizedSettingKey) return false;
  const settingRecord = game.settings?.settings?.get?.(`${MODULE_ID}.${normalizedSettingKey}`) ?? null;
  const settingScope = String(settingRecord?.scope ?? "").trim().toLowerCase();

  if (!game.user?.isGM) {
    if (settingScope === "client") {
      const fullClientSettingKey = `${MODULE_ID}.${normalizedSettingKey}`;
      suppressNextSettingRefresh(fullClientSettingKey);
      await game.settings.set(MODULE_ID, normalizedSettingKey, value);
      return true;
    }
    if (!canAccessAllPlayerOps(game.user)) return false;
    const hasActiveGm = hasActiveGmClient();
    if (!hasActiveGm) {
      if (canUsePlayerUiLocalOverride(normalizedSettingKey, game.user)) {
        setPlayerUiLocalSettingOverride(normalizedSettingKey, value);
        logPlayerPermissionDebug("local-override", "Saved Party Operations change to local player test state because no GM client is active.", {
          settingKey: normalizedSettingKey
        });
        notifyUiInfoThrottled(
          "Party Operations saved locally for player-side UI testing. Changes are not synced until a GM client reconnects.",
          { key: `player-local-override:${normalizedSettingKey}`, ttlMs: 5000 }
        );
        return true;
      }
      logPlayerPermissionDebug("no-active-gm", "Party Operations change blocked because no active GM client is available.", {
        settingKey: normalizedSettingKey
      });
      ui.notifications?.warn("Party Operations change blocked: no active GM client is available.");
      return false;
    }
    game.socket.emit(SOCKET_CHANNEL, {
      type: "ops:setting-write",
      userId: game.user.id,
      settingKey: normalizedSettingKey,
      value: foundry.utils.deepClone(value)
    });
    return true;
  }
  const fullSettingKey = `${MODULE_ID}.${normalizedSettingKey}`;
  suppressNextSettingRefresh(fullSettingKey);
  await game.settings.set(MODULE_ID, normalizedSettingKey, value);
  return true;
}

