function getAudioMixPresetText(item) {
  return `${item.name} ${item.category} ${item.subcategory} ${item.tags.join(" ")}`.toLowerCase();
}

function scoreAudioTrackForMixPreset(item, preset) {
  if (!item || !preset) return 0;
  const preferredKinds = Array.isArray(preset.preferredKinds) ? preset.preferredKinds : [];
  const preferredUsage = Array.isArray(preset.preferredUsage) ? preset.preferredUsage : [];
  const searchTokens = Array.isArray(preset.searchTokens) ? preset.searchTokens : [];
  const text = getAudioMixPresetText(item);
  let score = 0;

  if (preferredKinds.includes(item.kind)) score += 10;
  else if (item.kind === "music" && preferredKinds.includes("ambience")) score += 3;

  if (preferredUsage.includes(item.usage)) score += 12;
  else if (item.usage === "general") score += 3;

  for (const token of searchTokens) {
    const normalizedToken = String(token ?? "").trim().toLowerCase();
    if (!normalizedToken) continue;
    if (text.includes(normalizedToken)) score += 4;
  }

  if (item.usage === "scifi" && preset.id !== "stingers") score -= 8;
  if (item.kind === "voice" && preset.id !== "stingers") score -= 2;
  return score;
}

function buildAudioMixAssignedCandidates(catalog, preset = getSelectedAudioMixPreset()) {
  const trackIds = Array.isArray(preset?.trackIds) ? preset.trackIds : [];
  return trackIds
    .map((trackId, index) => {
      const item = catalog.items.find((entry) => entry.id === trackId);
      if (!item) return null;
      return {
        item,
        score: Math.max(1, 1000 - index)
      };
    })
    .filter(Boolean);
}

function buildAudioMixCandidates(catalog, preset = getSelectedAudioMixPreset(), { excludeTrackIds = [] } = {}) {
  const excluded = new Set(normalizeAudioMixPresetTrackIds(excludeTrackIds));
  const scored = catalog.items
    .map((item) => ({
      item,
      score: scoreAudioTrackForMixPreset(item, preset)
    }))
    .filter((entry) => entry.score > 0 && !excluded.has(entry.item.id))
    .sort((left, right) => {
      if (right.score !== left.score) return right.score - left.score;
      return left.item.name.localeCompare(right.item.name);
    });
  if (scored.length > 0) return scored;

  return catalog.items
    .filter((item) => ((preset.preferredKinds ?? []).includes(item.kind) || (preset.preferredUsage ?? []).includes(item.usage)) && !excluded.has(item.id))
    .map((item) => ({ item, score: 1 }))
    .sort((left, right) => left.item.name.localeCompare(right.item.name));
}

function getPlayableAudioMixCandidates(catalog, preset = getSelectedAudioMixPreset()) {
  if (Array.isArray(preset?.trackIds) && preset.trackIds.length > 0) return buildAudioMixAssignedCandidates(catalog, preset);
  return buildAudioMixCandidates(catalog, preset);
}

function getManagedAudioMixPlaylist() {
  const playlists = Array.from(game?.playlists?.contents ?? []);
  return playlists.find((playlist) => playlist.getFlag?.(MODULE_ID, "managedAudioMixboard"))
    ?? playlists.find((playlist) => String(playlist?.name ?? "").trim() === AUDIO_MIX_PLAYLIST_NAME)
    ?? null;
}

function isManagedAudioMixPlaylist(playlist) {
  if (!playlist) return false;
  if (playlist.getFlag?.(MODULE_ID, "managedAudioMixboard")) return true;
  return String(playlist?.name ?? "").trim() === AUDIO_MIX_PLAYLIST_NAME;
}

function getManagedAudioMixTrackIdFromPlaylistSound(sound) {
  return normalizeAudioLibraryRootPath(sound?.getFlag?.(MODULE_ID, "audioLibraryTrackId") ?? "");
}

function getManagedAudioMixPlayingSound(playlist = getManagedAudioMixPlaylist(), preferredSoundId = "") {
  const sounds = Array.from(playlist?.sounds?.contents ?? []);
  const normalizedPreferredId = String(preferredSoundId ?? "").trim();
  return sounds.find((sound) => Boolean(sound?.playing) && String(sound?.id ?? "").trim() === normalizedPreferredId)
    ?? sounds.find((sound) => Boolean(sound?.playing))
    ?? null;
}

function getManagedAudioMixSoundFromState(playlist = getManagedAudioMixPlaylist(), mixState = getAudioMixStateFlag(playlist)) {
  const sounds = Array.from(playlist?.sounds?.contents ?? []);
  const preferredSoundId = String(mixState?.playlistSoundId ?? "").trim();
  const activeTrackId = String(mixState?.activeTrackId ?? "").trim();
  const activeTrackPath = normalizeAudioLibraryRootPath(mixState?.activeTrackPath ?? "");
  return sounds.find((sound) => String(sound?.id ?? "").trim() === preferredSoundId)
    ?? sounds.find((sound) => getManagedAudioMixTrackIdFromPlaylistSound(sound) === activeTrackId)
    ?? sounds.find((sound) => normalizeAudioLibraryRootPath(sound?.path ?? "") === activeTrackPath)
    ?? getManagedAudioMixPlayingSound(playlist, preferredSoundId)
    ?? null;
}

async function syncManagedAudioMixStateFromPlaylist(playlist = getManagedAudioMixPlaylist(), options = {}) {
  if (!game.user?.isGM || !playlist) return null;
  const priorState = options?.priorState ?? getAudioMixStateFlag(playlist);
  const preferredSoundId = String(options?.playlistSoundId ?? priorState.playlistSoundId ?? "").trim();
  const activeSound = getManagedAudioMixPlayingSound(playlist, preferredSoundId);
  const shouldRefresh = options?.refresh === true;
  const fallbackPreset = getAudioMixPresetById(priorState.presetId || options?.presetId || getSelectedAudioMixPreset().id);

  if (!activeSound) {
    const nextState = await setAudioMixStateFlag(playlist, {
      ...priorState,
      presetId: String(priorState.presetId ?? fallbackPreset?.id ?? "").trim(),
      activeTrackId: "",
      activeTrackName: "",
      activeTrackPath: "",
      playlistSoundId: "",
      playbackId: options?.preservePlaybackId ? String(priorState.playbackId ?? "").trim() : "",
      isPlaying: false,
      startedAt: 0,
      updatedAt: Date.now()
    });
    if (shouldRefresh) {
      refreshOpenApps({ scope: REFRESH_SCOPE_KEYS.LOOT });
      emitSocketRefresh({ scope: REFRESH_SCOPE_KEYS.LOOT });
    }
    return nextState;
  }

  const activeSoundId = String(activeSound?.id ?? "").trim();
  const activeTrackId = getManagedAudioMixTrackIdFromPlaylistSound(activeSound)
    || normalizeAudioLibraryRootPath(activeSound?.path ?? "")
    || String(priorState.activeTrackId ?? "").trim();
  const queueTrackIds = normalizeAudioMixPresetTrackIds(priorState.queueTrackIds ?? []);
  const currentIndex = queueTrackIds.indexOf(activeTrackId);
  const isSameActiveSound = Boolean(priorState.isPlaying) && String(priorState.playlistSoundId ?? "").trim() === activeSoundId;
  const nextState = await setAudioMixStateFlag(playlist, {
    ...priorState,
    presetId: String(activeSound?.getFlag?.(MODULE_ID, "mixPresetId") ?? options?.presetId ?? priorState.presetId ?? fallbackPreset?.id ?? "").trim(),
    activeTrackId,
    activeTrackName: String(activeSound?.name ?? priorState.activeTrackName ?? "").trim(),
    activeTrackPath: normalizeAudioLibraryRootPath(activeSound?.path ?? priorState.activeTrackPath ?? ""),
    playlistSoundId: activeSoundId,
    playbackId: isSameActiveSound
      ? (String(priorState.playbackId ?? "").trim() || foundry.utils.randomID())
      : (String(options?.playbackId ?? "").trim() || foundry.utils.randomID()),
    currentIndex: currentIndex >= 0
      ? currentIndex
      : Math.max(0, Math.floor(Number(options?.currentIndex ?? priorState.currentIndex ?? 0) || 0)),
    volume: normalizeAudioMixVolume(activeSound?.volume ?? priorState.volume ?? fallbackPreset?.volume ?? 0.5),
    channel: normalizeAudioMixChannel(activeSound?.channel ?? priorState.channel ?? fallbackPreset?.channel),
    fade: Math.max(0, Math.floor(Number(activeSound?.fade ?? priorState.fade ?? fallbackPreset?.fade ?? 0) || 0)),
    isPlaying: true,
    startedAt: isSameActiveSound
      ? Math.max(0, Number(priorState.startedAt ?? 0) || 0)
      : Math.max(0, Number(options?.startedAt ?? Date.now()) || Date.now()),
    updatedAt: Date.now()
  });
  if (shouldRefresh) {
    refreshOpenApps({ scope: REFRESH_SCOPE_KEYS.LOOT });
    emitSocketRefresh({ scope: REFRESH_SCOPE_KEYS.LOOT });
  }
  return nextState;
}

function hideManagedAudioMixPlaylistUi(root = document) {
  // Keep the managed playlist visible in Foundry's audio deck so deck controls
  // remain the source of truth for playback.
  return root;
}

function shouldSequenceAudioMixPresetPlayback(preset, candidateCount = 0) {
  return Number(candidateCount ?? 0) > 1;
}

function getAudioMixPlaylistMode(preset, candidateCount = 0) {
  const disabled = CONST?.PLAYLIST_MODES?.DISABLED ?? 0;
  const sequential = CONST?.PLAYLIST_MODES?.SEQUENTIAL ?? disabled;
  const shuffle = CONST?.PLAYLIST_MODES?.SHUFFLE ?? sequential;
  if (!shouldSequenceAudioMixPresetPlayback(preset, candidateCount)) return disabled;
  return preset?.repeat ? shuffle : sequential;
}

async function ensureManagedAudioMixPlaylist(preset, candidateCount = 0) {
  const baseData = {
    name: AUDIO_MIX_PLAYLIST_NAME,
    description: `Managed by Party Operations for the ${preset.label} mix preset.`,
    mode: getAudioMixPlaylistMode(preset, candidateCount),
    sorting: CONST?.PLAYLIST_SORT_MODES?.MANUAL ?? 0,
    channel: normalizeAudioMixChannel(preset.channel),
    fade: Math.max(0, Math.floor(Number(preset.fade ?? 0) || 0))
  };
  let playlist = getManagedAudioMixPlaylist();
  if (!playlist) {
    playlist = await Playlist.create({
      ...baseData,
      flags: {
        [MODULE_ID]: {
          managedAudioMixboard: true
        }
      }
    });
    hideManagedAudioMixPlaylistUi(document);
    return playlist;
  }

  await playlist.update(baseData);
  if (!playlist.getFlag?.(MODULE_ID, "managedAudioMixboard")) {
    await playlist.setFlag(MODULE_ID, "managedAudioMixboard", true);
  }
  hideManagedAudioMixPlaylistUi(document);
  return playlist;
}

async function syncAudioMixPlaylistSounds(playlist, preset, candidates) {
  const rows = candidates.slice(0, 24);
  const existingIds = Array.from(playlist?.sounds?.contents ?? []).map((sound) => sound.id).filter(Boolean);
  if (existingIds.length > 0) {
    await playlist.deleteEmbeddedDocuments("PlaylistSound", existingIds);
  }
  if (rows.length <= 0) return [];

  const shouldSequence = shouldSequenceAudioMixPresetPlayback(preset, rows.length);
  const sounds = rows.map(({ item, score }, index) => ({
    name: item.name,
    path: item.path,
    channel: normalizeAudioMixChannel(preset.channel),
    repeat: shouldSequence ? false : Boolean(preset.repeat),
    fade: Math.max(0, Math.floor(Number(preset.fade ?? 0) || 0)),
    volume: Math.max(0, Math.min(1, Number(preset.volume ?? 0.5) || 0.5)),
    sort: index * 10,
    flags: {
      [MODULE_ID]: {
        audioLibraryTrackId: item.id,
        mixPresetId: preset.id,
        mixScore: score
      }
    }
  }));
  return playlist.createEmbeddedDocuments("PlaylistSound", sounds);
}

function pickAudioMixCandidate(candidates, excludedTrackId = "") {
  const normalizedExcludedId = String(excludedTrackId ?? "").trim();
  const pool = candidates.filter(({ item }) => item.id !== normalizedExcludedId);
  const effectivePool = pool.length > 0 ? pool : candidates;
  if (effectivePool.length <= 0) return null;
  const topSlice = effectivePool.slice(0, Math.min(6, effectivePool.length));
  return topSlice[Math.floor(Math.random() * topSlice.length)] ?? effectivePool[0];
}

function normalizeAudioMixQueueTrackIds(trackIds = [], candidates = []) {
  const available = new Set((Array.isArray(candidates) ? candidates : []).map(({ item }) => String(item?.id ?? "").trim()).filter(Boolean));
  return normalizeAudioMixPresetTrackIds(trackIds).filter((entry) => available.has(entry));
}

function buildOrderedAudioMixCandidates(candidates, options = {}) {
  const rows = Array.isArray(candidates) ? candidates.slice() : [];
  const candidateMap = new Map(rows.map((entry) => [String(entry?.item?.id ?? "").trim(), entry]));
  const queuedIds = normalizeAudioMixQueueTrackIds(options.queueTrackIds, rows);
  let ordered = queuedIds
    .map((trackId) => candidateMap.get(trackId) ?? null)
    .filter(Boolean);
  if (ordered.length <= 0) ordered = rows;
  const preferredTrackId = String(options.preferredTrackId ?? "").trim();
  // Preserve the live/manual queue order when one already exists. Preferred
  // track selection should choose the active row, not rewrite the queue.
  if (preferredTrackId && queuedIds.length <= 0) {
    const preferred = candidateMap.get(preferredTrackId) ?? null;
    if (preferred) {
      ordered = [preferred, ...ordered.filter((entry) => String(entry?.item?.id ?? "").trim() !== preferredTrackId)];
    }
  }
  return ordered;
}

async function stopManagedAudioMixPlaylist(playlist) {
  if (!playlist) return false;
  if (typeof playlist.stopAll === "function") {
    await playlist.stopAll();
    return true;
  }
  if (typeof playlist.stopAllSounds === "function") {
    await playlist.stopAllSounds();
    return true;
  }
  return false;
}

function getManagedAudioMixPlaybackStateInput(input = {}) {
  return {
    presetId: String(input?.presetId ?? "").trim(),
    activeTrackId: normalizeAudioLibraryRootPath(input?.activeTrackId ?? ""),
    activeTrackName: String(input?.activeTrackName ?? "").trim(),
    activeTrackPath: normalizeAudioLibraryRootPath(input?.activeTrackPath ?? ""),
    playlistSoundId: String(input?.playlistSoundId ?? "").trim(),
    playbackId: String(input?.playbackId ?? "").trim(),
    queueTrackIds: normalizeAudioMixPresetTrackIds(input?.queueTrackIds ?? []),
    currentIndex: Math.max(0, Math.floor(Number(input?.currentIndex ?? 0) || 0)),
    volume: normalizeAudioMixVolume(input?.volume ?? 0.5),
    channel: normalizeAudioMixChannel(input?.channel),
    fade: Math.max(0, Math.floor(Number(input?.fade ?? 0) || 0)),
    isPlaying: Boolean(input?.isPlaying),
    startedAt: Math.max(0, Number(input?.startedAt ?? 0) || 0),
    updatedAt: Math.max(0, Number(input?.updatedAt ?? 0) || 0)
  };
}

function getAudioMixStateFlag(playlist = getManagedAudioMixPlaylist()) {
  return getManagedAudioMixPlaybackStateInput(playlist?.getFlag?.(MODULE_ID, "audioMixState") ?? {});
}

async function setAudioMixStateFlag(playlist, input = {}) {
  if (!playlist?.setFlag) return null;
  const next = getManagedAudioMixPlaybackStateInput({
    ...input,
    updatedAt: Number(input?.updatedAt ?? Date.now()) || Date.now()
  });
  await playlist.setFlag(MODULE_ID, "audioMixState", next);
  return next;
}

function logManagedAudioMixDebug(message, details = null) {
  if (!isModuleDebugEnabled()) return;
  try {
    if (details === null || details === undefined) {
      console.debug(`[${MODULE_ID}][audio-mix] ${message}`);
      return;
    }
    console.debug(`[${MODULE_ID}][audio-mix] ${message}`, details);
  } catch {
    // Never fail user actions because of logging.
  }
}

async function handleManagedAudioMixTrackEnd(playbackId) {
  if (!game.user?.isGM) return false;
  const playlist = getManagedAudioMixPlaylist();
  const mixState = getAudioMixStateFlag(playlist);
  if (!mixState.isPlaying || String(mixState.playbackId ?? "").trim() !== String(playbackId ?? "").trim()) return false;
  const preset = getAudioMixPresetById(mixState.presetId || getSelectedAudioMixPreset().id);
  const queueTrackIds = normalizeAudioMixPresetTrackIds(mixState.queueTrackIds);
  if (queueTrackIds.length <= 1) {
    if (preset.repeat && queueTrackIds.length === 1) {
      return playManagedAudioMixQueueAtIndex(0, { excludeTrackId: "" });
    }
    await stopAudioMixPlayback({ preserveQueue: true, statusMessage: `${preset.label} finished playing.` });
    return true;
  }
  return playNextAudioMixTrack();
}

async function autoStartManagedAudioMixFromSavedState() {
  if (!game.user?.isGM) return false;
  const playlist = getManagedAudioMixPlaylist();
  const mixState = getAudioMixStateFlag(playlist);
  const preset = getAudioMixPresetById(mixState.presetId || getSharedSelectedAudioMixPresetId() || getSelectedAudioMixPreset().id);
  const queuedTrackIds = normalizeAudioMixPresetTrackIds(mixState.queueTrackIds?.length > 0
    ? mixState.queueTrackIds
    : preset?.trackIds ?? []);
  if (queuedTrackIds.length <= 0) return false;
  try {
    await playAudioMixPresetById(preset.id, {
      queueTrackIds: queuedTrackIds,
      preferredTrackId: queuedTrackIds[0],
      currentIndex: 0,
      excludeTrackId: ""
    });
    return true;
  } catch (error) {
    if (isModuleDebugEnabled()) {
      console.warn(`${MODULE_ID}: failed to auto-start saved audio mix`, error);
    }
    return false;
  }
}

async function syncManagedAudioMixPlaybackForCurrentUser(options = {}) {
  const playlist = getManagedAudioMixPlaylist();
  const mixState = getAudioMixStateFlag(playlist);
  const allowAutostart = Boolean(options?.allowAutostart);
  const activeSound = playlist ? getManagedAudioMixPlayingSound(playlist, mixState.playlistSoundId) : null;
  logManagedAudioMixDebug("syncing managed audio mix playback", {
    allowAutostart,
    refresh: options?.refresh === true,
    hasPlaylist: Boolean(playlist),
    playlistId: String(playlist?.id ?? "").trim(),
    mixPlaybackId: String(mixState?.playbackId ?? "").trim(),
    mixPlaylistSoundId: String(mixState?.playlistSoundId ?? "").trim(),
    activeSoundId: String(activeSound?.id ?? "").trim()
  });

  if (!playlist) {
    if (allowAutostart && game.user?.isGM) {
      return autoStartManagedAudioMixFromSavedState();
    }
    return false;
  }

  if (!activeSound) {
    if (game.user?.isGM) {
      await syncManagedAudioMixStateFromPlaylist(playlist, {
        refresh: options?.refresh === true
      });
    }
    if (allowAutostart && game.user?.isGM && !mixState.isPlaying) {
      return autoStartManagedAudioMixFromSavedState();
    }
    return false;
  }

  const activeSoundId = String(activeSound?.id ?? "").trim();
  let effectiveMixState = mixState;
  const needsStateRefresh = Boolean(game.user?.isGM) && (
    !mixState.isPlaying
    || !String(mixState.playbackId ?? "").trim()
    || String(mixState.playlistSoundId ?? "").trim() !== activeSoundId
  );
  if (needsStateRefresh) {
    effectiveMixState = await syncManagedAudioMixStateFromPlaylist(playlist, {
      priorState: mixState,
      playlistSoundId: activeSoundId,
      refresh: options?.refresh === true
    }) ?? mixState;
  }

  return Boolean(String(activeSound?.path ?? effectiveMixState.activeTrackPath ?? "").trim());
}

function queueManagedAudioMixPlaybackResync(delayMs = 60, options = {}) {
  if (managedAudioMixResyncTimerId) {
    window.clearTimeout(managedAudioMixResyncTimerId);
    managedAudioMixResyncTimerId = null;
  }
  managedAudioMixResyncTimerId = window.setTimeout(async () => {
    managedAudioMixResyncTimerId = null;
    if (game.user?.isGM && options?.syncState !== false) {
      await syncManagedAudioMixStateFromPlaylist(options?.playlist ?? getManagedAudioMixPlaylist(), {
        refresh: options?.refresh === true
      });
    }
    await syncManagedAudioMixPlaybackForCurrentUser({
      refresh: options?.refresh === true
    });
  }, Math.max(0, Math.floor(Number(delayMs ?? 60) || 60)));
}

async function playAudioMixPresetById(presetId, options = {}) {
  if (!canAccessAllPlayerOps()) {
    ui.notifications?.warn("Only the GM can control Party Operations mix playback.");
    return null;
  }
  const preset = getAudioMixPresetById(presetId);
  const catalog = getAudioLibraryCatalog();
  const queuedTrackIds = normalizeAudioMixPresetTrackIds(options.queueTrackIds ?? preset?.trackIds ?? []);
  const candidates = buildAudioMixAssignedCandidates(catalog, {
    ...preset,
    trackIds: queuedTrackIds
  });
  if (candidates.length <= 0) {
    throw new Error(`Add tracks from the Track Browser to the ${preset.label} queue before playing it.`);
  }

  const playlist = await ensureManagedAudioMixPlaylist(preset, candidates.length);
  if (!playlist) throw new Error("The managed mix playlist could not be created.");
  const priorState = getAudioMixStateFlag(playlist);
  logManagedAudioMixDebug("preparing managed mix preset playback", {
    presetId: String(preset?.id ?? "").trim(),
    priorPlaybackId: String(priorState?.playbackId ?? "").trim(),
    candidateCount: candidates.length,
    queuedTrackCount: queuedTrackIds.length,
    preferredTrackId: String(options?.preferredTrackId ?? "").trim()
  });
  await stopManagedAudioMixPlaylist(playlist);
  const orderedCandidates = buildOrderedAudioMixCandidates(candidates, options);
  const preferredTrackId = String(options.preferredTrackId ?? "").trim();
  const chosenCandidate = preferredTrackId
    ? orderedCandidates.find(({ item }) => item.id === preferredTrackId) ?? pickAudioMixCandidate(orderedCandidates, options.excludeTrackId ?? priorState.activeTrackId)
    : pickAudioMixCandidate(orderedCandidates, options.excludeTrackId ?? priorState.activeTrackId);
  const createdSounds = await syncAudioMixPlaylistSounds(playlist, preset, orderedCandidates);
  const chosenSound = Array.from(createdSounds ?? []).find((sound) => String(sound?.getFlag?.(MODULE_ID, "audioLibraryTrackId") ?? "").trim() === chosenCandidate?.item?.id)
    ?? createdSounds?.[0]
    ?? null;
  if (!chosenSound) {
    throw new Error(`Failed to prepare playback for the ${preset.label} mix.`);
  }

  const queueTrackIds = orderedCandidates.map(({ item }) => item.id);
  const currentIndex = Math.max(0, queueTrackIds.indexOf(String(chosenCandidate?.item?.id ?? "").trim()));
  const playbackId = foundry.utils.randomID();
  const nextState = await setAudioMixStateFlag(playlist, {
    presetId: preset.id,
    activeTrackId: String(chosenCandidate?.item?.id ?? ""),
    activeTrackName: String(chosenCandidate?.item?.name ?? chosenSound.name ?? ""),
    activeTrackPath: String(chosenCandidate?.item?.path ?? chosenSound.path ?? ""),
    playlistSoundId: String(chosenSound?.id ?? ""),
    playbackId,
    queueTrackIds,
    currentIndex,
    volume: normalizeAudioMixVolume(preset.volume),
    channel: normalizeAudioMixChannel(preset.channel),
    fade: Math.max(0, Math.floor(Number(preset.fade ?? 0) || 0)),
    isPlaying: true,
    startedAt: Date.now(),
    updatedAt: Date.now()
  });
  if (typeof playlist.playSound === "function") {
    await playlist.playSound(chosenSound);
  } else if (chosenSound?.id) {
    await playlist.updateEmbeddedDocuments("PlaylistSound", [{
      _id: String(chosenSound.id),
      playing: true
    }]);
  }
  await syncManagedAudioMixStateFromPlaylist(playlist, {
    priorState: nextState,
    playlistSoundId: String(chosenSound?.id ?? ""),
    presetId: preset.id,
    playbackId,
    currentIndex,
    startedAt: nextState?.startedAt ?? Date.now()
  });
  setSelectedAudioMixPresetId(preset.id);
  audioLibraryUiState.selectedTrackId = String(chosenCandidate?.item?.id ?? audioLibraryUiState.selectedTrackId);
  setAudioMixStatus(`Playing ${preset.label}: ${String(chosenCandidate?.item?.name ?? chosenSound.name ?? "Track")}`);
  refreshOpenApps({ scope: REFRESH_SCOPE_KEYS.LOOT });
  emitSocketRefresh({ scope: REFRESH_SCOPE_KEYS.LOOT });
  return {
    playlist,
    preset,
    sound: chosenSound,
    track: chosenCandidate?.item ?? null
  };
}

async function stopAudioMixPlayback(options = {}) {
  if (!canAccessAllPlayerOps()) {
    ui.notifications?.warn("Only the GM can stop Party Operations mix playback.");
    return false;
  }
  const playlist = getManagedAudioMixPlaylist();
  const priorState = getAudioMixStateFlag(playlist);
  logManagedAudioMixDebug("stopping managed mix playback", {
    playlistId: String(playlist?.id ?? "").trim(),
    preserveActiveTrack: options?.preserveActiveTrack === true,
    preservePlaybackId: options?.preservePlaybackId === true,
    preserveQueue: options?.preserveQueue === true,
    priorPlaybackId: String(priorState?.playbackId ?? "").trim(),
    priorPlaylistSoundId: String(priorState?.playlistSoundId ?? "").trim()
  });
  if (playlist) await stopManagedAudioMixPlaylist(playlist);
  if (playlist) {
    const preserveActiveTrack = options?.preserveActiveTrack === true;
    const preservePlaybackId = options?.preservePlaybackId === true;
    await setAudioMixStateFlag(playlist, {
      ...priorState,
      presetId: priorState.presetId || getSelectedAudioMixPreset().id,
      activeTrackId: preserveActiveTrack ? String(priorState.activeTrackId ?? "").trim() : "",
      activeTrackName: preserveActiveTrack ? String(priorState.activeTrackName ?? "").trim() : "",
      activeTrackPath: preserveActiveTrack ? normalizeAudioLibraryRootPath(priorState.activeTrackPath ?? "") : "",
      playlistSoundId: "",
      playbackId: preservePlaybackId ? String(priorState.playbackId ?? "").trim() : "",
      queueTrackIds: options?.preserveQueue ? priorState.queueTrackIds : normalizeAudioMixPresetTrackIds(priorState.queueTrackIds),
      currentIndex: Math.max(0, Math.floor(Number(priorState.currentIndex ?? 0) || 0)),
      isPlaying: false,
      startedAt: 0,
      updatedAt: Date.now()
    });
  }
  setAudioMixStatus(String(options?.statusMessage ?? "Mix playback stopped."));
  refreshOpenApps({ scope: REFRESH_SCOPE_KEYS.LOOT });
  emitSocketRefresh({ scope: REFRESH_SCOPE_KEYS.LOOT });
  return true;
}

async function toggleAudioMixPlayback() {
  if (!canAccessAllPlayerOps()) {
    ui.notifications?.warn("Only the GM can control Party Operations mix playback.");
    return false;
  }
  const playlist = getManagedAudioMixPlaylist();
  const mixState = getAudioMixStateFlag(playlist);
  if (mixState.isPlaying) {
    const preset = getAudioMixPresetById(mixState.presetId || getSelectedAudioMixPreset().id);
    return stopAudioMixPlayback({
      preserveQueue: true,
      preserveActiveTrack: true,
      preservePlaybackId: true,
      statusMessage: `${preset.label} paused.`
    });
  }

  const queueTrackIds = normalizeAudioMixPresetTrackIds(mixState.queueTrackIds);
  if (queueTrackIds.length > 0) {
    const resumeIndex = Math.max(0, Math.min(queueTrackIds.length - 1, Math.floor(Number(mixState.currentIndex ?? 0) || 0)));
    return Boolean(await playManagedAudioMixQueueAtIndex(resumeIndex));
  }

  return Boolean(await playAudioMixPresetById(mixState.presetId || getSelectedAudioMixPreset().id));
}

async function syncLiveAudioMixPresetVolume(preset = getSelectedAudioMixPreset()) {
  const playlist = getManagedAudioMixPlaylist();
  const mixState = getAudioMixStateFlag(playlist);
  if (!playlist || !mixState.isPlaying) return false;
  if (String(mixState.presetId ?? "").trim() !== String(preset?.id ?? "").trim()) return false;
  const nextState = await setAudioMixStateFlag(playlist, {
    ...mixState,
    volume: normalizeAudioMixVolume(preset?.volume ?? mixState.volume),
    channel: normalizeAudioMixChannel(preset?.channel ?? mixState.channel),
    fade: Math.max(0, Math.floor(Number(preset?.fade ?? mixState.fade ?? 0) || 0)),
    updatedAt: Date.now()
  });
  await playlist.update({
    channel: nextState.channel,
    fade: nextState.fade
  });
  const soundUpdates = Array.from(playlist?.sounds?.contents ?? [])
    .map((sound) => ({
      _id: String(sound?.id ?? "").trim(),
      volume: nextState.volume,
      channel: nextState.channel,
      fade: nextState.fade
    }))
    .filter((update) => update._id);
  if (soundUpdates.length > 0) {
    await playlist.updateEmbeddedDocuments("PlaylistSound", soundUpdates);
  }
  refreshOpenApps({ scope: REFRESH_SCOPE_KEYS.LOOT });
  emitSocketRefresh({ scope: REFRESH_SCOPE_KEYS.LOOT });
  return true;
}

async function playAudioMixCandidateByTrackId(trackId) {
  const preset = getSelectedAudioMixPreset();
  const normalizedTrackId = normalizeAudioLibraryRootPath(trackId);
  if (!normalizedTrackId) return false;
  const queueTrackIds = normalizeAudioMixPresetTrackIds(preset?.trackIds ?? []);
  const previewQueueTrackIds = queueTrackIds.includes(normalizedTrackId)
    ? queueTrackIds
    : [normalizedTrackId];
  return playAudioMixPresetById(preset.id, {
    excludeTrackId: "",
    preferredTrackId: normalizedTrackId,
    queueTrackIds: previewQueueTrackIds
  });
}

async function playManagedAudioMixQueueAtIndex(targetIndex, options = {}) {
  if (!canAccessAllPlayerOps()) {
    ui.notifications?.warn("Only the GM can control Party Operations mix playback.");
    return null;
  }
  const catalog = getAudioLibraryCatalog();
  const playlist = getManagedAudioMixPlaylist();
  const mixState = getAudioMixStateFlag(playlist);
  const preset = getAudioMixPresetById(mixState.presetId || getSelectedAudioMixPreset().id);
  const candidates = getPlayableAudioMixCandidates(catalog, preset);
  const queueTrackIds = normalizeAudioMixQueueTrackIds(mixState.queueTrackIds, candidates);
  if (queueTrackIds.length <= 0) {
    return playAudioMixPresetById(preset.id, {});
  }
  const normalizedIndex = Math.max(0, Math.min(queueTrackIds.length - 1, Math.floor(Number(targetIndex ?? 0) || 0)));
  const preferredTrackId = queueTrackIds[normalizedIndex];
  return playAudioMixPresetById(preset.id, {
    queueTrackIds,
    preferredTrackId,
    currentIndex: normalizedIndex,
    excludeTrackId: options.excludeTrackId ?? ""
  });
}

async function playNextAudioMixTrack() {
  const playlist = getManagedAudioMixPlaylist();
  const mixState = getAudioMixStateFlag(playlist);
  const preset = getAudioMixPresetById(mixState.presetId || getSelectedAudioMixPreset().id);
  const queueTrackIds = normalizeAudioMixPresetTrackIds(mixState.queueTrackIds);
  if (queueTrackIds.length <= 0) {
    return playAudioMixPresetById(preset.id);
  }
  const nextIndex = mixState.currentIndex + 1;
  if (nextIndex >= queueTrackIds.length) {
    if (!preset.repeat) {
      await stopAudioMixPlayback();
      setAudioMixStatus(`${preset.label} reached the end of the queue.`);
      return null;
    }
    return playManagedAudioMixQueueAtIndex(0);
  }
  return playManagedAudioMixQueueAtIndex(nextIndex);
}

async function restartCurrentAudioMixTrack() {
  const playlist = getManagedAudioMixPlaylist();
  const mixState = getAudioMixStateFlag(playlist);
  if (!mixState.activeTrackId) {
    return playAudioMixPresetById(getSelectedAudioMixPreset().id);
  }
  return playManagedAudioMixQueueAtIndex(mixState.currentIndex);
}

async function queueSelectedTrackNext(actionElement) {
  const preset = getSelectedAudioMixPreset();
  const trackId = String(actionElement?.dataset?.trackId ?? "").trim() || String(audioLibraryUiState.selectedTrackId ?? "").trim();
  if (!trackId) return false;
  if (Array.isArray(preset?.trackIds)) return queueTrackNextInSelectedAudioMixPreset(trackId);
  const playlist = getManagedAudioMixPlaylist();
  const mixState = getAudioMixStateFlag(playlist);
  const queueTrackIds = normalizeAudioMixPresetTrackIds(mixState.queueTrackIds);
  const currentIndex = Math.max(0, Math.floor(Number(mixState.currentIndex ?? 0) || 0));
  const filtered = queueTrackIds.filter((entry) => entry !== trackId);
  const targetIndex = Math.min(filtered.length, currentIndex + 1);
  filtered.splice(targetIndex, 0, trackId);
  if (playlist) {
    await setAudioMixStateFlag(playlist, {
      ...mixState,
      queueTrackIds: filtered,
      updatedAt: Date.now()
    });
    refreshOpenApps({ scope: REFRESH_SCOPE_KEYS.LOOT });
    emitSocketRefresh({ scope: REFRESH_SCOPE_KEYS.LOOT });
    return true;
  }
  return false;
}

function getFilteredAudioLibraryItems(catalog) {
  const filters = normalizeAudioLibraryFilters(audioLibraryUiState.filters);
  return catalog.items.filter((item) => matchesAudioLibraryItemFilters(item, filters));
}

function normalizeAudioLibrarySearchMatchText(value) {
  return String(value ?? "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .trim();
}

function isAudioLibrarySubsequenceMatch(needle = "", haystack = "") {
  if (!needle || !haystack || needle.length < 3) return false;
  let index = 0;
  for (const char of haystack) {
    if (char === needle[index]) index += 1;
    if (index >= needle.length) return true;
  }
  return false;
}

function isAudioLibraryFuzzyTokenMatch(token, candidateValues = []) {
  const normalizedToken = normalizeAudioLibrarySearchMatchText(token).replace(/\s+/g, "");
  if (!normalizedToken) return true;
  return candidateValues.some((value) => {
    const normalizedValue = normalizeAudioLibrarySearchMatchText(value);
    if (!normalizedValue) return false;
    const compactValue = normalizedValue.replace(/\s+/g, "");
    return normalizedValue.includes(normalizedToken)
      || compactValue.includes(normalizedToken)
      || isAudioLibrarySubsequenceMatch(normalizedToken, compactValue);
  });
}

function getAudioLibraryItemSearchValues(item = {}) {
  return [
    String(item?.name ?? ""),
    ...(Array.isArray(item?.tags) ? item.tags : []),
    String(item?.category ?? ""),
    String(item?.subcategory ?? "")
  ].filter(Boolean);
}

function buildAudioLibraryItemFilterTokenSet(item = {}) {
  const tokens = new Set();
  const categoryToken = buildAudioLibraryFilterToken("category", item?.category);
  if (categoryToken) tokens.add(categoryToken);
  const subcategoryToken = buildAudioLibraryFilterToken("subcategory", item?.subcategory);
  if (subcategoryToken) tokens.add(subcategoryToken);
  for (const tag of normalizeAudioLibraryTagList(item?.tags ?? [])) {
    const token = buildAudioLibraryFilterToken("tag", tag);
    if (token) tokens.add(token);
  }
  return tokens;
}

function matchesAudioLibraryItemFilters(item = {}, filters = normalizeAudioLibraryFilters(audioLibraryUiState.filters)) {
  const normalizedFilters = normalizeAudioLibraryFilters(filters);
  if (normalizedFilters.kind !== "all" && item.kind !== normalizedFilters.kind) return false;
  if (normalizedFilters.usage !== "all" && item.usage !== normalizedFilters.usage) return false;
  if (normalizedFilters.selectedTags.length > 0) {
    const itemFilterTokens = buildAudioLibraryItemFilterTokenSet(item);
    if (!normalizedFilters.selectedTags.some((tag) => itemFilterTokens.has(tag))) return false;
  }
  const searchTokens = normalizedFilters.search.split(/\s+/g).filter(Boolean);
  if (searchTokens.length <= 0) return true;
  const searchValues = getAudioLibraryItemSearchValues(item);
  return searchTokens.every((token) => isAudioLibraryFuzzyTokenMatch(token, searchValues));
}

function filterAudioMixTrackCandidates(candidates = [], filters = normalizeAudioLibraryFilters(audioLibraryUiState.filters)) {
  const normalizedFilters = normalizeAudioLibraryFilters(filters);
  return (Array.isArray(candidates) ? candidates : []).filter(({ item }) => matchesAudioLibraryItemFilters(item, normalizedFilters));
}

function buildAudioLibraryFilterOptions(catalog = getAudioLibraryCatalog()) {
  const filters = normalizeAudioLibraryFilters(audioLibraryUiState.filters);
  const selectedTagSet = new Set(filters.selectedTags);
  const kindOptions = Object.entries(AUDIO_LIBRARY_KIND_LABELS).map(([value, label]) => ({
    value,
    label,
    selected: filters.kind === value
  }));
  const usageOptions = Object.entries(AUDIO_LIBRARY_USAGE_LABELS).map(([value, label]) => ({
    value,
    label,
    selected: filters.usage === value
  }));
  const categoryGroupsByValue = new Map();
  for (const item of Array.isArray(catalog?.items) ? catalog.items : []) {
    const categoryLabel = String(item?.category ?? "").trim() || "Uncategorized";
    const categoryValue = normalizeAudioLibraryTag(categoryLabel);
    if (!categoryValue) continue;
    let categoryGroup = categoryGroupsByValue.get(categoryValue);
    if (!categoryGroup) {
      categoryGroup = {
        value: categoryValue,
        label: categoryLabel,
        count: 0,
        subcategories: new Map()
      };
      categoryGroupsByValue.set(categoryValue, categoryGroup);
    }
    categoryGroup.count += 1;

    const subcategoryLabel = String(item?.subcategory ?? "").trim();
    const subcategoryValue = normalizeAudioLibraryTag(subcategoryLabel);
    if (!subcategoryValue) continue;
    const existingSubcategory = categoryGroup.subcategories.get(subcategoryValue) ?? {
      value: subcategoryValue,
      label: subcategoryLabel,
      count: 0
    };
    existingSubcategory.count += 1;
    categoryGroup.subcategories.set(subcategoryValue, existingSubcategory);
  }
  const compareAudioLibraryFilterRows = (left, right) => {
    const selectedCompare = Number(Boolean(right?.selected)) - Number(Boolean(left?.selected));
    if (selectedCompare !== 0) return selectedCompare;
    const countCompare = Number(right?.count ?? 0) - Number(left?.count ?? 0);
    if (countCompare !== 0) return countCompare;
    return String(left?.label ?? "").localeCompare(String(right?.label ?? ""));
  };
  const categoryGroups = Array.from(categoryGroupsByValue.values())
    .map((group) => {
      const categoryToken = buildAudioLibraryFilterToken("category", group.value);
      const selected = selectedTagSet.has(categoryToken);
      const subcategoryOptions = Array.from(group.subcategories.values())
        .map((entry) => {
          const token = buildAudioLibraryFilterToken("subcategory", entry.value);
          return {
            value: token,
            label: entry.label,
            count: entry.count,
            selected: selectedTagSet.has(token)
          };
        })
        .sort(compareAudioLibraryFilterRows);
      const selectedChildCount = subcategoryOptions.filter((entry) => entry.selected).length;
      return {
        value: categoryToken,
        label: group.label,
        count: group.count,
        selected,
        selectedCount: selectedChildCount + (selected ? 1 : 0),
        hasSelected: selected || selectedChildCount > 0,
        hasSubcategories: subcategoryOptions.length > 0,
        isOpen: selected || selectedChildCount > 0,
        subcategoryOptions
      };
    })
    .sort(compareAudioLibraryFilterRows);
  const simpleFolderOptions = categoryGroups.filter((group) => !group.hasSubcategories);
  const nestedFolderGroups = categoryGroups.filter((group) => group.hasSubcategories);
  return {
    kindOptions,
    usageOptions,
    categoryGroups: nestedFolderGroups,
    simpleFolderOptions,
    hasCategoryGroups: nestedFolderGroups.length > 0,
    hasSimpleFolderOptions: simpleFolderOptions.length > 0,
    hasTagOptions: nestedFolderGroups.length > 0 || simpleFolderOptions.length > 0,
    selectedTagCount: filters.selectedTags.length,
    hasActiveFilters: hasActiveAudioLibraryFilters(filters)
  };
}

function buildAudioLibrarySummary(catalog, options = {}) {
  const categoryCount = new Set(catalog.items.map((item) => item.category).filter(Boolean)).size;
  const kindCount = new Set(catalog.items.map((item) => item.kind).filter(Boolean)).size;
  const usageCount = new Set(catalog.items.map((item) => item.usage).filter(Boolean)).size;
  const hiddenCount = Math.max(0, Math.floor(Number(options?.hiddenCount ?? 0) || 0));
  const resolvedDurationCount = catalog.items.filter((item) => isAudioLibraryDurationResolved(item)).length;
  const usageSummaryOrder = ["music", "ambience", "sfx", "voice", "combat", "tension", "rest", "travel"];
  const cards = usageSummaryOrder.map((key) => {
    const count = catalog.items.filter((item) => item.kind === key || item.usage === key).length;
    if (count <= 0) return null;
    return {
      key,
      label: AUDIO_LIBRARY_KIND_LABELS[key] ?? AUDIO_LIBRARY_USAGE_LABELS[key] ?? key,
      count
    };
  }).filter(Boolean);
  return {
    trackCount: catalog.items.length,
    categoryCount,
    kindCount,
    usageCount,
    hiddenCount,
    resolvedDurationCount,
    scannedAtLabel: catalog.scannedAt ? new Date(catalog.scannedAt).toLocaleString() : "-",
    scannedBy: catalog.scannedBy || "-",
    cards
  };
}

function buildAudioLibraryResults(catalog) {
  const filtered = getFilteredAudioLibraryItems(catalog);
  const selectedId = String(audioLibraryUiState.selectedTrackId ?? "").trim();
  const selectedTrackIdSet = new Set(getSelectedAudioLibraryTrackSelectionIds());
  const visibleTracks = filtered.slice(0, 160).map((item) => ({
    ...buildAudioLibraryTrackDisplay(item),
    selected: item.id === selectedId,
    checked: selectedTrackIdSet.has(item.id)
  }));
  const visibleSelectedCount = visibleTracks.filter((item) => item.checked).length;
  const selectedCount = selectedTrackIdSet.size;
  return {
    tracks: visibleTracks,
    hasTracks: visibleTracks.length > 0,
    totalMatches: filtered.length,
    visibleCount: visibleTracks.length,
    selection: {
      selectedCount,
      visibleSelectedCount,
      hasSelection: selectedCount > 0,
      hasVisibleSelection: visibleSelectedCount > 0,
      allVisibleSelected: visibleTracks.length > 0 && visibleSelectedCount === visibleTracks.length,
      label: selectedCount === 1
        ? "1 track checked for bulk hide."
        : `${selectedCount} tracks checked for bulk hide.`
    }
  };
}

function getAudioMixPlaybackState(catalog) {
  const playlist = getManagedAudioMixPlaylist();
  const mixFlag = getAudioMixStateFlag(playlist);
  const activeTrackId = String(mixFlag?.activeTrackId ?? "").trim();
  const activeTrackPath = normalizeAudioLibraryRootPath(mixFlag?.activeTrackPath ?? "");
  const activeTrack = catalog.items.find((item) => item.id === activeTrackId)
    ?? catalog.items.find((item) => normalizeAudioLibraryRootPath(item?.path ?? "") === activeTrackPath)
    ?? null;
  const activePreset = getAudioMixPresetById(mixFlag?.presetId ?? getSelectedAudioMixPreset().id);
  const queueTrackIds = normalizeAudioMixPresetTrackIds(mixFlag.queueTrackIds ?? []);
  const queueTracks = queueTrackIds
    .map((trackId, index) => {
      const item = catalog.items.find((entry) => entry.id === trackId);
      if (!item) return null;
      return {
        ...item,
        order: index + 1,
        isActive: item.id === activeTrackId,
        isCurrentIndex: index === mixFlag.currentIndex
      };
    })
    .filter(Boolean);
  const currentIndex = queueTracks.findIndex((entry) => entry.id === activeTrackId);
  const normalizedCurrentIndex = currentIndex >= 0 ? currentIndex : Math.min(Math.max(0, mixFlag.currentIndex), Math.max(0, queueTracks.length - 1));
  const activeTrackTags = Array.isArray(activeTrack?.tags) ? activeTrack.tags.filter(Boolean) : [];
  const hasToggleTarget = Boolean(activeTrackId || activeTrackPath || queueTracks.length > 0);
  const isPlaying = Boolean(mixFlag?.isPlaying);
  return {
    hasPlaylist: Boolean(playlist),
    playlistName: String(playlist?.name ?? AUDIO_MIX_PLAYLIST_NAME),
    transportLabel: AUDIO_MIX_TRANSPORT_LABEL,
    isPlaying,
    isPaused: !isPlaying && hasToggleTarget,
    presetId: activePreset.id,
    presetLabel: activePreset.label,
    activeTrack,
    activeTrackId,
    activeTrackName: String(activeTrack?.name ?? mixFlag?.activeTrackName ?? "").trim(),
    activeTrackPath,
    playlistSoundId: String(mixFlag?.playlistSoundId ?? "").trim(),
    playbackId: String(mixFlag?.playbackId ?? "").trim(),
    volume: normalizeAudioMixVolume(mixFlag?.volume ?? activePreset.volume),
    volumePercent: getAudioMixVolumePercent(mixFlag?.volume ?? activePreset.volume),
    channel: normalizeAudioMixChannel(mixFlag?.channel ?? activePreset.channel),
    channelLabel: getAudioMixChannelLabel(mixFlag?.channel ?? activePreset.channel),
    fade: Math.max(0, Math.floor(Number(mixFlag?.fade ?? activePreset.fade ?? 0) || 0)),
    startedAt: Math.max(0, Number(mixFlag?.startedAt ?? 0) || 0),
    startedAtLabel: mixFlag?.startedAt ? new Date(Number(mixFlag.startedAt)).toLocaleTimeString() : "-",
    updatedAtLabel: mixFlag?.updatedAt ? new Date(Number(mixFlag.updatedAt)).toLocaleString() : "-",
    queueTrackIds,
    queueTracks,
    activeTrackHasSubcategory: Boolean(activeTrack?.subcategory),
    activeTrackTags,
    hasActiveTrackTags: activeTrackTags.length > 0,
    hasQueue: queueTracks.length > 0,
    queueLength: queueTracks.length,
    currentIndex: normalizedCurrentIndex,
    canTogglePlayback: hasToggleTarget,
    transportActionLabel: isPlaying ? "Pause shared mix" : "Resume shared mix",
    transportActionIcon: isPlaying ? "fa-pause" : "fa-play",
    canSkipNext: queueTracks.length > 1 || Boolean(activePreset.repeat),
    canRestart: Boolean(activeTrackId)
  };
}

function normalizeAudioLibraryDurationSeconds(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric) || numeric <= 0) return 0;
  return Number(numeric.toFixed(2));
}

function normalizeAudioLibraryDurationResolvedAt(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric) || numeric <= 0) return 0;
  return Math.max(0, Math.floor(numeric));
}

function isAudioLibraryDurationResolved(item) {
  return normalizeAudioLibraryDurationResolvedAt(item?.durationResolvedAt ?? 0) > 0;
}

function formatAudioLibraryDurationLabel(value) {
  const totalSeconds = Math.max(0, Math.floor(normalizeAudioLibraryDurationSeconds(value)));
  if (totalSeconds <= 0) return "--:--";
  const hours = Math.floor(totalSeconds / 3600);
  const minutes = Math.floor((totalSeconds % 3600) / 60);
  const seconds = totalSeconds % 60;
  if (hours > 0) return `${hours}:${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
  return `${minutes}:${String(seconds).padStart(2, "0")}`;
}

function getManagedAudioMixPlaybackMonitorSnapshot() {
  const playlist = getManagedAudioMixPlaylist();
  const mixFlag = getAudioMixStateFlag(playlist);
  const catalog = getAudioLibraryCatalog();
  const activeSound = playlist ? getManagedAudioMixPlayingSound(playlist, mixFlag.playlistSoundId) : null;
  const activeTrackId = String(mixFlag?.activeTrackId ?? "").trim();
  const activeTrackPath = normalizeAudioLibraryRootPath(mixFlag?.activeTrackPath ?? activeSound?.path ?? "");
  const activeTrack = catalog.items.find((item) => item.id === activeTrackId)
    ?? catalog.items.find((item) => normalizeAudioLibraryRootPath(item?.path ?? "") === activeTrackPath)
    ?? null;
  const playbackId = String(mixFlag?.playbackId ?? "").trim();
  const startedAt = Math.max(0, Number(mixFlag?.startedAt ?? 0) || 0);
  const durationSeconds = Math.max(0, Number(activeTrack?.durationSeconds ?? 0) || 0);
  let currentSeconds = 0;
  if (startedAt > 0) {
    const elapsedSeconds = Math.max(0, (Date.now() - startedAt) / 1000);
    const shouldLoop = Boolean(activeSound?.repeat);
    currentSeconds = durationSeconds > 0
      ? (shouldLoop ? (elapsedSeconds % durationSeconds) : Math.min(durationSeconds, elapsedSeconds))
      : elapsedSeconds;
  }
  const normalizedCurrentSeconds = durationSeconds > 0
    ? Math.max(0, Math.min(durationSeconds, currentSeconds))
    : Math.max(0, currentSeconds);
  return {
    playbackId,
    startedAt,
    durationSeconds: Number(durationSeconds.toFixed(2)),
    currentSeconds: Number(normalizedCurrentSeconds.toFixed(2)),
    progressPermille: durationSeconds > 0
      ? Math.max(0, Math.min(1000, Math.round((normalizedCurrentSeconds / durationSeconds) * 1000)))
      : 0,
    volumePercent: getAudioMixVolumePercent(mixFlag?.volume ?? 0.5)
  };
}

function buildAudioMixKindFocusOptions(selectedValue = "music") {
  return Object.entries(AUDIO_LIBRARY_KIND_LABELS).map(([value, label]) => ({
    value,
    label,
    selected: normalizeAudioLibraryKind(selectedValue) === value
  }));
}

function buildAudioMixUsageFocusOptions(selectedValue = "general") {
  return Object.entries(AUDIO_LIBRARY_USAGE_LABELS).map(([value, label]) => ({
    value,
    label,
    selected: normalizeAudioLibraryUsage(selectedValue) === value
  }));
}

function buildAudioMixPlaybackModeOptions(selectedValue = "repeat") {
  return Object.entries(AUDIO_MIX_PLAYBACK_MODE_LABELS).map(([value, label]) => ({
    value,
    label,
    selected: normalizeAudioMixPlaybackMode(selectedValue) === value
  }));
}

function buildAudioMixContext(catalog) {
  const selectedPreset = getSelectedAudioMixPreset();
  const savedTrackIds = normalizeAudioMixPresetTrackIds(selectedPreset?.trackIds ?? []);
  const assignedCandidates = buildAudioMixAssignedCandidates(catalog, selectedPreset);
  const {
    view: trackBrowserView,
    suggestedCandidates,
    allCandidates,
    visibleCandidates
  } = getVisibleAudioMixTrackBrowserCandidates(catalog, selectedPreset);
  const hasSavedTrackList = savedTrackIds.length > 0;
  const playback = getAudioMixPlaybackState(catalog);
  const selectedLibraryTrack = catalog.items.find((item) => item.id === String(audioLibraryUiState.selectedTrackId ?? "").trim()) ?? null;
  const selectedMixTrackIdSet = new Set(getSelectedAudioMixTrackSelectionIds());
  const playbackMatchesSelection = String(playback.presetId ?? "").trim() === String(selectedPreset.id ?? "").trim();
  const pagination = buildAudioMixTrackBrowserPagination(visibleCandidates.length, trackBrowserView);
  const queueRows = assignedCandidates.map(({ item }, index) => ({
    ...item,
    order: index + 1,
    isActive: item.id === playback?.activeTrack?.id,
    isCurrentIndex: index === playback.currentIndex
  }));
  const visibleTrackRows = visibleCandidates.slice(pagination.startIndex, pagination.endIndex).map(({ item, score }) => ({
    ...buildAudioLibraryTrackDisplay(item),
    score,
    checked: selectedMixTrackIdSet.has(item.id),
    selected: item.id === playback?.activeTrack?.id,
    isAssigned: savedTrackIds.includes(item.id)
  }));
  const visibleSelectedCount = visibleTrackRows.filter((track) => track.checked).length;
  const selectedCount = selectedMixTrackIdSet.size;
  const queueSourceLabel = hasSavedTrackList
    ? "Manual queue saved to this preset"
    : "Add tracks from the Track Browser to build this queue";
  const missingTrackCount = Math.max(0, savedTrackIds.length - assignedCandidates.length);
  const queueEmptyLabel = hasSavedTrackList
    ? (missingTrackCount > 0
      ? `${missingTrackCount} saved track${missingTrackCount === 1 ? "" : "s"} could not be matched in the current library. Rescan or re-add them.`
      : "This preset has a saved queue, but none of those tracks are available in the current library scan.")
    : "Add tracks below to build the current queue for this preset.";
  return {
    status: audioLibraryUiState.mixStatus,
    hasStatus: Boolean(audioLibraryUiState.mixStatus),
    selectedPresetId: selectedPreset.id,
    presets: getAllAudioMixPresets().map((preset) => ({
      id: preset.id,
      label: preset.label,
      description: preset.description,
      isCustom: Boolean(preset.isCustom),
      selected: preset.id === selectedPreset.id,
      candidateCount: (Array.isArray(preset.trackIds) && preset.trackIds.length > 0)
        ? buildAudioMixAssignedCandidates(catalog, preset).length
        : buildAudioMixCandidates(catalog, preset).length,
      playbackModeLabel: getAudioMixPlaybackModeLabel(preset.playbackMode),
      hasSavedTrackList: Array.isArray(preset.trackIds) && preset.trackIds.length > 0
    })),
    selectedPreset: {
      ...selectedPreset,
      candidateCount: suggestedCandidates.length,
      assignedCount: assignedCandidates.length,
      suggestedCount: suggestedCandidates.length,
      savedTrackCount: savedTrackIds.length,
      missingTrackCount,
      hasSavedTrackList,
      channelLabel: getAudioMixChannelLabel(selectedPreset.channel),
      volumePercent: getAudioMixVolumePercent(selectedPreset.volume),
      playbackModeLabel: getAudioMixPlaybackModeLabel(selectedPreset.playbackMode),
      kindFocusLabel: getAudioLibraryKindLabel(selectedPreset.kindFocus),
      usageFocusLabel: getAudioLibraryUsageLabel(selectedPreset.usageFocus),
      searchTokensLabel: formatAudioMixPresetSearchTokens(selectedPreset.searchTokens),
      canDelete: Boolean(selectedPreset.isCustom),
      canRename: Boolean(selectedPreset.isCustom)
    },
    candidates: suggestedCandidates.slice(0, 14).map(({ item, score }) => ({
      ...buildAudioLibraryTrackDisplay(item),
      score,
      selected: item.id === playback?.activeTrack?.id
    })),
    assignedTracks: assignedCandidates.slice(0, 20).map(({ item, score }) => ({
      ...buildAudioLibraryTrackDisplay(item),
      score,
      selected: item.id === playback?.activeTrack?.id,
      isActive: item.id === playback?.activeTrack?.id
    })),
    hasAssignedTracks: assignedCandidates.length > 0,
    suggestedTracks: suggestedCandidates.slice(0, 20).map(({ item, score }) => ({
      ...buildAudioLibraryTrackDisplay(item),
      score,
      selected: item.id === playback?.activeTrack?.id
    })),
    hasSuggestedTracks: suggestedCandidates.length > 0,
    hasCandidates: assignedCandidates.length > 0,
    trackBrowser: {
      viewSuggested: trackBrowserView === AUDIO_MIX_TRACK_BROWSER_VIEW_IDS.SUGGESTED,
      viewAll: trackBrowserView === AUDIO_MIX_TRACK_BROWSER_VIEW_IDS.ALL,
      suggestedCount: suggestedCandidates.length,
      allCount: allCandidates.length,
      tracks: visibleTrackRows,
      hasTracks: visibleTrackRows.length > 0,
      totalCount: visibleCandidates.length,
      visibleCount: visibleTrackRows.length,
      hasActiveFilters: hasActiveAudioLibraryFilters(audioLibraryUiState.filters),
      pagination: {
        ...pagination
      },
      summaryLabel: trackBrowserView === AUDIO_MIX_TRACK_BROWSER_VIEW_IDS.ALL
        ? (pagination.totalCount > 0
          ? `Browsing ${pagination.label}.`
          : "No library tracks are available in the current scan.")
        : (pagination.totalCount > 0
          ? `Showing ${pagination.label} from ${suggestedCandidates.length} tag-matched suggestions.`
          : "No suggestions matched this preset yet."),
      emptyLabel: trackBrowserView === AUDIO_MIX_TRACK_BROWSER_VIEW_IDS.ALL
        ? "No tracks are available in the current library scan."
        : "No suggestions matched this preset yet. Broaden the focus or adjust the search tokens.",
      selection: {
        selectedCount,
        visibleSelectedCount,
        hasSelection: selectedCount > 0,
        hasVisibleSelection: visibleSelectedCount > 0,
        allVisibleSelected: visibleTrackRows.length > 0 && visibleSelectedCount === visibleTrackRows.length,
        label: selectedCount < 1
          ? "No tracks selected for bulk add."
          : selectedCount === 1
          ? "1 track selected for bulk add."
          : `${selectedCount} tracks selected for bulk add.`
      }
    },
    editor: {
      canEdit: true,
      canRename: Boolean(selectedPreset.isCustom),
      hasSelectedLibraryTrack: Boolean(selectedLibraryTrack),
      selectedLibraryTrackName: String(selectedLibraryTrack?.name ?? ""),
      kindOptions: buildAudioMixKindFocusOptions(selectedPreset.kindFocus),
      usageOptions: buildAudioMixUsageFocusOptions(selectedPreset.usageFocus),
      playbackOptions: buildAudioMixPlaybackModeOptions(selectedPreset.playbackMode),
      volumePercent: getAudioMixVolumePercent(selectedPreset.volume),
      hasAssignedTracks: assignedCandidates.length > 0
    },
    queue: {
      hasTracks: queueRows.length > 0,
      sourceLabel: queueSourceLabel,
      emptyLabel: queueEmptyLabel,
      tracks: queueRows.map((track) => buildAudioLibraryTrackDisplay(track)),
      hasSelectedLibraryTrack: Boolean(selectedLibraryTrack),
      selectedLibraryTrackName: String(selectedLibraryTrack?.name ?? ""),
      canControl: playbackMatchesSelection || selectedPreset.isCustom,
      canEdit: Boolean(hasSavedTrackList && selectedPreset.isCustom),
      hasSavedTrackList,
      missingTrackCount,
      hasLiveQueue: playbackMatchesSelection && playback.hasQueue
    },
    playback: {
      ...playback,
      hasActiveTrack: Boolean(playback.activeTrack || playback.activeTrackName || playback.activeTrackPath),
      activeTrackName: playback.activeTrackName || "No track playing",
      activeTrackPath: String(playback.activeTrack?.path ?? playback.activeTrackPath ?? ""),
      volumePercent: getAudioMixVolumePercent(playback.volume ?? selectedPreset.volume),
      activeTrackKindLabel: playback.activeTrack ? getAudioLibraryKindLabel(playback.activeTrack.kind) : "",
      activeTrackUsageLabel: playback.activeTrack ? getAudioLibraryUsageLabel(playback.activeTrack.usage) : "",
      activeTrackQueuePosition: playback.currentIndex >= 0 ? playback.currentIndex + 1 : 0,
      activeTrackQueueLabel: playback.currentIndex >= 0 && playback.queueLength > 0
        ? `Track ${playback.currentIndex + 1} of ${playback.queueLength}`
        : ""
    }
  };
}

function getSelectedAudioLibraryTrack(catalog, results) {
  const selectedId = String(audioLibraryUiState.selectedTrackId ?? "").trim();
  const fromCatalog = catalog.items.find((item) => item.id === selectedId);
  const fallback = fromCatalog ?? filteredFallback(results.tracks);
  if (!fallback) return null;
  return buildAudioLibraryTrackDisplay(fallback);
}

function filteredFallback(tracks = []) {
  return Array.isArray(tracks) && tracks.length > 0 ? tracks[0] : null;
}

function normalizeLootKeywordTag(value) {
  return String(value ?? "")
    .trim()
    .toLowerCase();
}

function normalizeLootKeywordTagList(values = []) {
  const source = Array.isArray(values) ? values : [values];
  return source
    .flatMap((entry) => String(entry ?? "").split(/[\n,;]+/))
    .map((entry) => normalizeLootKeywordTag(entry))
    .filter((entry, index, rows) => entry.length > 0 && rows.indexOf(entry) === index);
}

function normalizeLootKeywordIncludeMode(value, fallback = LOOT_KEYWORD_INCLUDE_MODES.ALL) {
  const normalized = String(value ?? "").trim().toLowerCase();
  if (normalized === LOOT_KEYWORD_INCLUDE_MODES.ANY) return LOOT_KEYWORD_INCLUDE_MODES.ANY;
  if (normalized === LOOT_KEYWORD_INCLUDE_MODES.ALL) return LOOT_KEYWORD_INCLUDE_MODES.ALL;
  return fallback;
}

function parseLootKeywordTagListFromInput(value) {
  return normalizeLootKeywordTagList(String(value ?? "").split(/[\s,;\n]+/));
}

function formatLootKeywordTagListForInput(values = []) {
  return normalizeLootKeywordTagList(values).join(", ");
}

function normalizeLootSourceClass(value = "", fallback = LOOT_SOURCE_CLASSES.GENERATED) {
  const normalized = String(value ?? "").trim().toLowerCase();
  if (normalized === LOOT_SOURCE_CLASSES.CURATED) return LOOT_SOURCE_CLASSES.CURATED;
  if (normalized === LOOT_SOURCE_CLASSES.MANUAL) return LOOT_SOURCE_CLASSES.MANUAL;
  if (normalized === LOOT_SOURCE_CLASSES.TABLE) return LOOT_SOURCE_CLASSES.TABLE;
  if (normalized === LOOT_SOURCE_CLASSES.GENERATED) return LOOT_SOURCE_CLASSES.GENERATED;
  return fallback;
}

function normalizeLootSourcePolicy(value = "", fallback = LOOT_SOURCE_POLICIES.NORMAL) {
  const normalized = String(value ?? "").trim().toLowerCase().replace(/_/g, "-");
  if (normalized === LOOT_SOURCE_POLICIES.BONUS) return LOOT_SOURCE_POLICIES.BONUS;
  if (normalized === LOOT_SOURCE_POLICIES.ANCHOR) return LOOT_SOURCE_POLICIES.ANCHOR;
  if (normalized === LOOT_SOURCE_POLICIES.OUTSIDE_BUDGET || normalized === "outsidebudget") return LOOT_SOURCE_POLICIES.OUTSIDE_BUDGET;
  if (normalized === LOOT_SOURCE_POLICIES.NORMAL) return LOOT_SOURCE_POLICIES.NORMAL;
  return fallback;
}

function isLootOutsideBudgetPolicy(entryOrPolicy = null) {
  const policy = entryOrPolicy && typeof entryOrPolicy === "object"
    ? normalizeLootSourcePolicy(entryOrPolicy?.sourcePolicy ?? "")
    : normalizeLootSourcePolicy(entryOrPolicy ?? "");
  return policy === LOOT_SOURCE_POLICIES.BONUS || policy === LOOT_SOURCE_POLICIES.OUTSIDE_BUDGET;
}

function normalizeLootRarityValue(value) {
  const raw = String(value ?? "").trim().toLowerCase();
  const allowed = new Set(LOOT_RARITY_OPTIONS.map((entry) => String(entry.value ?? "").trim().toLowerCase()));
  return allowed.has(raw) ? raw : "";
}

function buildLootItemTypeCatalog() {
  const labels = CONFIG?.Item?.typeLabels && typeof CONFIG.Item.typeLabels === "object"
    ? CONFIG.Item.typeLabels
    : {};
  const merged = new Map();
  for (const [key, label] of Object.entries(LOOT_ITEM_TYPE_LABELS)) {
    merged.set(String(key).trim(), String(label).trim() || String(key).trim());
  }
  for (const [key, label] of Object.entries(labels)) {
    const id = String(key ?? "").trim();
    if (!id) continue;
    if (!merged.has(id)) merged.set(id, String(label ?? id).trim() || id);
  }
  return Array.from(merged.entries())
    .map(([value, label]) => ({ value, label }))
    .filter((entry) => entry.value)
    .sort((a, b) => a.label.localeCompare(b.label));
}

function normalizeLootSourcePackEntry(entry = {}) {
  const id = String(entry?.id ?? entry?.pack ?? "").trim();
  if (!id) return null;
  const weightRaw = Number(entry?.weight ?? 1);
  const weight = Number.isFinite(weightRaw) ? Math.max(1, Math.floor(weightRaw)) : 1;
  const sourceKindRaw = String(entry?.sourceKind ?? (id === LOOT_WORLD_ITEMS_SOURCE_ID ? "world-items" : "compendium-pack")).trim().toLowerCase();
  const sourceKind = sourceKindRaw === "world-items" ? "world-items" : "compendium-pack";
  return {
    id,
    label: String(entry?.label ?? "").trim(),
    sourceKind,
    enabled: entry?.enabled !== false,
    weight
  };
}

function normalizeLootSourceTableEntry(entry = {}) {
  const id = String(entry?.id ?? entry?.tableRef ?? entry?.tableUuid ?? "").trim();
  if (!id) return null;
  const typeRaw = String(entry?.tableType ?? entry?.type ?? "currency").trim().toLowerCase();
  const validTypes = new Set(LOOT_TABLE_TYPE_OPTIONS.map((option) => option.value));
  const tableType = validTypes.has(typeRaw) ? typeRaw : "currency";
  const sourceKindRaw = String(entry?.sourceKind ?? (id.startsWith("world-table:") ? "world-table" : "table-pack")).trim().toLowerCase();
  const sourceKind = sourceKindRaw === "world-table" ? "world-table" : "table-pack";
  return {
    id,
    label: String(entry?.label ?? "").trim(),
    sourceKind,
    enabled: entry?.enabled !== false,
    tableType
  };
}

function normalizeLootSourceConfig(config = {}) {
  const fallback = buildDefaultLootSourceConfig();
  const rawPacks = Array.isArray(config?.packs) ? config.packs : fallback.packs;
  const rawTables = Array.isArray(config?.tables) ? config.tables : fallback.tables;
  const validLootGenerationSourceIds = new Set(
    getLootGenerationItemPackSources()
      .map((entry) => String(entry?.id ?? "").trim())
      .filter(Boolean)
  );
  const packs = rawPacks
    .map((entry) => normalizeLootSourcePackEntry(entry))
    .filter((entry, index, rows) => {
      if (!entry) return false;
      if (!validLootGenerationSourceIds.has(String(entry.id ?? "").trim())) return false;
      return rows.findIndex((candidate) => candidate?.id === entry.id) === index;
    });
  if (!packs.some((entry) => String(entry?.id ?? "").trim() === LOOT_WORLD_ITEMS_SOURCE_ID)) {
    packs.unshift(buildLootWorldItemSourceEntry());
  } else {
    for (const entry of packs) {
      if (String(entry?.id ?? "").trim() !== LOOT_WORLD_ITEMS_SOURCE_ID) continue;
      entry.sourceKind = "world-items";
      if (!String(entry?.label ?? "").trim()) entry.label = LOOT_WORLD_ITEMS_SOURCE_LABEL;
      entry.weight = Math.max(1, Math.floor(Number(entry?.weight ?? 1) || 1));
    }
  }
  const tables = rawTables
    .map((entry) => normalizeLootSourceTableEntry(entry))
    .filter((entry, index, rows) => entry && rows.findIndex((candidate) => candidate.id === entry.id) === index);

  const itemTypeCatalog = new Set(buildLootItemTypeCatalog().map((entry) => entry.value));
  const validPackIds = new Set(getLootGenerationItemPackSources().map((entry) => String(entry?.id ?? "").trim()).filter(Boolean));
  const rawAllowedTypes = Array.isArray(config?.filters?.allowedTypes)
    ? config.filters.allowedTypes
    : fallback.filters.allowedTypes;
  const allowedTypes = rawAllowedTypes
    .map((entry) => String(entry ?? "").trim())
    .filter((entry, index, rows) => entry && itemTypeCatalog.has(entry) && rows.indexOf(entry) === index);

  const updatedAtRaw = Number(config?.updatedAt ?? 0);
  return {
    packs,
    tables,
    filters: {
      allowedTypes: allowedTypes.length > 0 ? allowedTypes : [...LOOT_DEFAULT_ITEM_TYPES],
      rarityFloor: normalizeLootRarityValue(config?.filters?.rarityFloor),
      rarityCeiling: normalizeLootRarityValue(config?.filters?.rarityCeiling),
      manifestPackId: (() => {
        const id = String(config?.filters?.manifestPackId ?? "").trim();
        if (!id) return "";
        if (validPackIds.has(id)) return id;
        const selectedFolderId = parseLootWorldItemsFolderFilterId(id);
        return selectedFolderId ? buildLootWorldItemsFolderFilterId(selectedFolderId) : "";
      })(),
      keywordIncludeMode: normalizeLootKeywordIncludeMode(config?.filters?.keywordIncludeMode, LOOT_KEYWORD_INCLUDE_MODES.ALL),
      keywordIncludeTags: normalizeLootKeywordTagList(config?.filters?.keywordIncludeTags ?? []),
      keywordExcludeTags: normalizeLootKeywordTagList(config?.filters?.keywordExcludeTags ?? [])
    },
    updatedAt: Number.isFinite(updatedAtRaw) ? updatedAtRaw : 0,
    updatedBy: String(config?.updatedBy ?? "")
  };
}

function getLootSourceConfig() {
  const stored = game.settings.get(MODULE_ID, SETTINGS.LOOT_SOURCE_CONFIG);
  return normalizeLootSourceConfig(stored ?? buildDefaultLootSourceConfig());
}

async function updateLootSourceConfig(mutator, options = {}) {
  if (typeof mutator !== "function") return;
  if (!canAccessAllPlayerOps()) {
    ui.notifications?.warn("Only the GM can configure loot sources.");
    return;
  }
  const config = getLootSourceConfig();
  mutator(config);
  const next = normalizeLootSourceConfig(config);
  next.updatedAt = Date.now();
  next.updatedBy = String(game.user?.name ?? "GM");
  await setModuleSettingWithLocalRefreshSuppressed(SETTINGS.LOOT_SOURCE_CONFIG, next);
  if (!options.skipLocalRefresh) refreshOpenApps({ scope: REFRESH_SCOPE_KEYS.LOOT });
  emitSocketRefresh({ scope: REFRESH_SCOPE_KEYS.LOOT });
}

function getAllCompendiumPacks() {
  if (!game?.packs) return [];
  if (typeof game.packs.values === "function") return Array.from(game.packs.values());
  const rows = [];
  for (const entry of game.packs) {
    if (Array.isArray(entry) && entry.length > 1) rows.push(entry[1]);
    else rows.push(entry);
  }
  return rows;
}

function normalizeLootManifestItemType(value) {
  return String(value ?? "")
    .trim()
    .toLowerCase();
}

function getLootManifestFolderNameKey(value) {
  return String(value ?? "")
    .trim()
    .toLowerCase();
}

function getLootManifestFolderLabelForType(itemType = "") {
  const normalizedType = normalizeLootManifestItemType(itemType);
  if (!normalizedType) return LOOT_MANIFEST_FOLDER_LABELS.other;
  const explicit = String(LOOT_MANIFEST_FOLDER_LABELS[normalizedType] ?? "").trim();
  if (explicit) return explicit;
  const fallback = String(LOOT_ITEM_TYPE_LABELS[normalizedType] ?? "").trim();
  if (fallback) return fallback;
  return normalizedType
    .split(/[-_\s]+/)
    .filter(Boolean)
    .map((segment) => segment.charAt(0).toUpperCase() + segment.slice(1))
    .join(" ");
}

function getLootManifestFolderSortPriority(itemType = "") {
  const normalizedType = normalizeLootManifestItemType(itemType) || "other";
  const index = LOOT_MANIFEST_FOLDER_TYPE_PRIORITY.indexOf(normalizedType);
  if (index >= 0) return index;
  return LOOT_MANIFEST_FOLDER_TYPE_PRIORITY.length + 100;
}

function getLootManifestCompendiumPack() {
  const allowedPackages = new Set([String(PRIMARY_MODULE_ID).trim().toLowerCase(), String(PREMIUM_MODULE_ID).trim().toLowerCase()]);
  const targetName = String(LOOT_MANIFEST_PACK_NAME).trim().toLowerCase();
  const targetLabel = String(LOOT_MANIFEST_PACK_LABEL).trim().toLowerCase();

  const candidates = getAllCompendiumPacks().filter((pack) => {
    const documentName = String(pack?.documentName ?? pack?.metadata?.type ?? "").trim().toLowerCase();
    if (documentName !== "item") return false;
    const metadataName = String(pack?.metadata?.name ?? "").trim().toLowerCase();
    return metadataName === targetName;
  });

  if (candidates.length > 0) {
    const packageMatched = candidates.find((pack) => {
      const packageName = String(pack?.metadata?.packageName ?? pack?.metadata?.package ?? "").trim().toLowerCase();
      if (!packageName) return false;
      return allowedPackages.has(packageName);
    });
    if (packageMatched) return packageMatched;
    return candidates[0];
  }

  const collectionMatched = getAllCompendiumPacks().find((pack) => {
    const documentName = String(pack?.documentName ?? pack?.metadata?.type ?? "").trim().toLowerCase();
    if (documentName !== "item") return false;
    const collection = String(pack?.collection ?? "").trim().toLowerCase();
    return collection.endsWith(`.${targetName}`);
  });
  if (collectionMatched) return collectionMatched;

  return getAllCompendiumPacks().find((pack) => {
    const documentName = String(pack?.documentName ?? pack?.metadata?.type ?? "").trim().toLowerCase();
    if (documentName !== "item") return false;
    const label = String(pack?.metadata?.label ?? pack?.title ?? "").trim().toLowerCase();
    return label === targetLabel;
  }) ?? null;
}

function getCompendiumFolderRows(pack) {
  const folders = pack?.folders;
  if (!folders) return [];
  if (Array.isArray(folders?.contents)) return folders.contents;
  if (typeof folders.values === "function") return Array.from(folders.values());
  if (Array.isArray(folders)) return folders;
  return [];
}

async function getLootManifestPackItemRows(pack) {
  try {
    if (typeof pack?.getIndex === "function") {
      const index = await pack.getIndex({ fields: ["type", "folder", "name", "flags.party-operations.folder", "flags"] });
      const rows = [];
      if (Array.isArray(index)) rows.push(...index);
      else if (Array.isArray(index?.contents)) rows.push(...index.contents);
      else if (typeof index?.values === "function") rows.push(...Array.from(index.values()));
      if (rows.length > 0) {
        return rows.map((entry) => ({
          id: String(entry?._id ?? entry?.id ?? "").trim(),
          type: normalizeLootManifestItemType(entry?.type),
          name: String(entry?.name ?? "").trim(),
          folderId: String(entry?.folder?.id ?? entry?.folder ?? "").trim(),
          folderMeta: getLootItemFolderProfileFromData(entry)
        })).filter((entry) => entry.id);
      }
    }
  } catch (error) {
    console.warn(`${MODULE_ID}: failed to read loot manifest compendium index`, error);
  }

  try {
    const docs = typeof pack?.getDocuments === "function" ? await pack.getDocuments() : [];
    return (Array.isArray(docs) ? docs : []).map((entry) => ({
      id: String(entry?.id ?? entry?._id ?? "").trim(),
      type: normalizeLootManifestItemType(entry?.type),
      name: String(entry?.name ?? "").trim(),
      folderId: String(entry?.folder?.id ?? entry?.folder ?? "").trim(),
      folderMeta: getLootItemFolderProfileFromData(entry)
    })).filter((entry) => entry.id);
  } catch (error) {
    console.warn(`${MODULE_ID}: failed to read loot manifest compendium documents`, error);
  }

  return [];
}

function isLockedCompendiumMutationError(error) {
  const message = String(error?.message ?? error ?? "").toLowerCase();
  if (!message) return false;
  if (!message.includes("compendium")) return false;
  if (!message.includes("locked")) return false;
  return message.includes("may not modify")
    || message.includes("cannot modify")
    || message.includes("you may not modify");
}

function getCompendiumPackageType(pack) {
  return String(pack?.metadata?.packageType ?? "").trim().toLowerCase();
}

function isReadOnlyCompendiumPackForFolderSync(pack) {
  const packageType = getCompendiumPackageType(pack);
  if (packageType && packageType !== "world") return true;
  const collection = String(pack?.collection ?? "").trim().toLowerCase();
  if (collection.startsWith(`${String(MODULE_ID).trim().toLowerCase()}.`)) return true;
  if (Boolean(pack?.locked) && typeof pack?.configure !== "function") return true;
  return false;
}

function isMonksTokenBarCompendiumUpdateCompatibilityMode(pack) {
  const monksTokenBarActive = game.modules?.get("monks-tokenbar")?.active === true;
  if (!monksTokenBarActive) return false;
  const packageType = getCompendiumPackageType(pack);
  return packageType === "module" || packageType === "system";
}

function disableLootManifestFolderSync(reason = "pack-locked", error = null) {
  if (!lootManifestFolderSyncDisabledReason) {
    lootManifestFolderSyncDisabledReason = String(reason ?? "").trim() || "pack-locked";
  }
  if (!lootManifestFolderSyncDisabledNotified) {
    lootManifestFolderSyncDisabledNotified = true;
    ui.notifications?.warn("Party Operations: loot manifest folder sync disabled because the compendium is locked or read-only.");
  }
  if (error) {
    console.warn(`${MODULE_ID}: loot manifest folder sync disabled (${lootManifestFolderSyncDisabledReason})`, error);
  } else {
    console.warn(`${MODULE_ID}: loot manifest folder sync disabled (${lootManifestFolderSyncDisabledReason})`);
  }
}

async function updateLootManifestPackItemFolders(pack, updates = []) {
  if (isMonksTokenBarCompendiumUpdateCompatibilityMode(pack)) {
    if (!lootManifestMonksCompatNotified) {
      lootManifestMonksCompatNotified = true;
      ui.notifications?.warn("Party Operations: skipped manifest item-folder updates while Monks TokenBar is active (compatibility workaround).");
      console.warn(`${MODULE_ID}: skipping loot manifest item-folder updates while monks-tokenbar is active`, {
        packId: String(pack?.collection ?? "")
      });
    }
    return 0;
  }

  const normalizedUpdates = (Array.isArray(updates) ? updates : [])
    .map((entry) => {
      const id = String(entry?._id ?? entry?.id ?? "").trim();
      const folderId = String(entry?.folder ?? "").trim();
      if (!id) return null;
      return { _id: id, folder: folderId || null };
    })
    .filter(Boolean);
  if (normalizedUpdates.length <= 0) return 0;

  if (typeof Item?.updateDocuments === "function") {
    try {
      await Item.updateDocuments(normalizedUpdates, { pack: pack.collection });
    } catch (error) {
      if (isLockedCompendiumMutationError(error)) {
        disableLootManifestFolderSync("pack-locked", error);
        return 0;
      }
      throw error;
    }
    return normalizedUpdates.length;
  }

  let applied = 0;
  for (const entry of normalizedUpdates) {
    try {
      const document = typeof pack?.getDocument === "function" ? await pack.getDocument(entry._id) : null;
      if (!document || typeof document.update !== "function") continue;
      await document.update({ folder: entry.folder });
      applied += 1;
    } catch (error) {
      if (isLockedCompendiumMutationError(error)) {
        disableLootManifestFolderSync("pack-locked", error);
        return applied;
      }
      console.warn(`${MODULE_ID}: failed to update loot manifest item folder`, entry?._id, error);
    }
  }
  return applied;
}

async function ensureLootManifestCompendiumTypeFolders(options = {}) {
  if (!game.user?.isGM) return { ok: false, reason: "not-gm" };
  if (lootManifestFolderSyncDisabledReason) {
    return { ok: false, reason: lootManifestFolderSyncDisabledReason };
  }
  const pack = getLootManifestCompendiumPack();
  if (!pack) return { ok: false, reason: "pack-missing" };

  const report = {
    ok: true,
    packId: String(pack?.collection ?? ""),
    createdFolders: 0,
    updatedItems: 0
  };

  if (isReadOnlyCompendiumPackForFolderSync(pack)) {
    report.ok = false;
    report.reason = "pack-read-only";
    disableLootManifestFolderSync("pack-read-only");
    return report;
  }

  const originalLocked = Boolean(pack?.locked);
  const mustUnlock = originalLocked && typeof pack?.configure === "function";
  try {
    if (mustUnlock) await pack.configure({ locked: false });
    if (mustUnlock && Boolean(pack?.locked)) {
      report.ok = false;
      report.reason = "pack-locked";
      disableLootManifestFolderSync("pack-locked");
      return report;
    }
  } catch (error) {
    report.ok = false;
    report.reason = "unlock-failed";
    if (isLockedCompendiumMutationError(error)) {
      disableLootManifestFolderSync("unlock-failed", error);
    }
    console.warn(`${MODULE_ID}: unable to unlock loot manifest compendium for folder sync`, error);
    return report;
  }

  try {
    const items = await getLootManifestPackItemRows(pack);
    if (items.length <= 0) return report;

    const folderRequestsByType = new Map();
    for (const item of items) {
      const normalizedType = normalizeLootManifestItemType(item?.type) || "other";
      if (!folderRequestsByType.has(normalizedType)) {
        folderRequestsByType.set(normalizedType, {
          type: normalizedType,
          label: getLootManifestFolderLabelForType(normalizedType),
          priority: getLootManifestFolderSortPriority(normalizedType)
        });
      }
    }

    if (typeof pack?.getFolders === "function") {
      await pack.getFolders();
    }
    let folders = getCompendiumFolderRows(pack);
    const folderByName = new Map(
      folders.map((folder) => [getLootManifestFolderNameKey(folder?.name), folder]).filter(([key]) => key)
    );

    const foldersToCreate = Array.from(folderRequestsByType.values())
      .filter((entry) => !folderByName.has(getLootManifestFolderNameKey(entry.label)))
      .sort((left, right) => {
        const byPriority = Number(left?.priority ?? 0) - Number(right?.priority ?? 0);
        if (byPriority !== 0) return byPriority;
        return String(left?.label ?? "").localeCompare(String(right?.label ?? ""));
      })
      .map((entry, index) => ({
        name: String(entry.label ?? "Other"),
        type: "Item",
        folder: null,
        sorting: "a",
        color: null,
        sort: (index + 1) * 1000
      }));

    if (foldersToCreate.length > 0) {
      if (typeof Folder?.createDocuments === "function") {
        try {
          await Folder.createDocuments(foldersToCreate, { pack: pack.collection });
        } catch (error) {
          if (isLockedCompendiumMutationError(error)) {
            report.ok = false;
            report.reason = "pack-locked";
            disableLootManifestFolderSync("pack-locked", error);
            return report;
          }
          throw error;
        }
        report.createdFolders = foldersToCreate.length;
      } else if (typeof pack?.createFolder === "function") {
        for (const folderData of foldersToCreate) {
          try {
            await pack.createFolder(folderData);
          } catch (error) {
            if (isLockedCompendiumMutationError(error)) {
              report.ok = false;
              report.reason = "pack-locked";
              disableLootManifestFolderSync("pack-locked", error);
              return report;
            }
            throw error;
          }
          report.createdFolders += 1;
        }
      }
      if (typeof pack?.getFolders === "function") {
        await pack.getFolders();
      }
      folders = getCompendiumFolderRows(pack);
      folderByName.clear();
      for (const folder of folders) {
        const key = getLootManifestFolderNameKey(folder?.name);
        if (!key) continue;
        folderByName.set(key, folder);
      }
    }

    const itemUpdates = [];
    for (const item of items) {
      const normalizedType = normalizeLootManifestItemType(item?.type) || "other";
      const folderLabel = getLootManifestFolderLabelForType(normalizedType);
      const folder = folderByName.get(getLootManifestFolderNameKey(folderLabel));
      const folderId = String(folder?.id ?? "").trim();
      if (!folderId) continue;
      if (String(item.folderId ?? "").trim() === folderId) continue;
      itemUpdates.push({
        _id: item.id,
        folder: folderId
      });
    }

    report.updatedItems = await updateLootManifestPackItemFolders(pack, itemUpdates);

    if (isModuleDebugEnabled()) {
      console.log(`${MODULE_ID}: loot manifest compendium folder sync`, {
        reason: String(options?.reason ?? ""),
        ...report
      });
    }

    return report;
  } catch (error) {
    report.ok = false;
    report.reason = "sync-failed";
    console.warn(`${MODULE_ID}: failed to sync loot manifest compendium folders`, error);
    return report;
  } finally {
    if (mustUnlock) {
      try {
        await pack.configure({ locked: true });
      } catch (error) {
        console.warn(`${MODULE_ID}: failed to restore loot manifest compendium lock`, error);
      }
    }
  }
}

function scheduleLootManifestCompendiumTypeFolderSync(reason = "") {
  if (!game.user?.isGM) return Promise.resolve({ ok: false, reason: "not-gm" });
  if (lootManifestFolderSyncDisabledReason) {
    return Promise.resolve({ ok: false, reason: lootManifestFolderSyncDisabledReason });
  }
  if (lootManifestFolderSyncPromise) return lootManifestFolderSyncPromise;

  lootManifestFolderSyncPromise = ensureLootManifestCompendiumTypeFolders({ reason })
    .catch((error) => {
      console.warn(`${MODULE_ID}: unexpected loot manifest folder sync failure`, error);
      return { ok: false, reason: "unexpected-error" };
    })
    .finally(() => {
      lootManifestFolderSyncPromise = null;
    });
  return lootManifestFolderSyncPromise;
}

function getDocumentFolderParentId(entry) {
  return String(entry?.folder?.id ?? entry?.folder ?? entry?.parent?.id ?? entry?.parent ?? "").trim();
}

function getLootManifestImportFlag(entry = {}) {
  const primary = entry?.flags?.[MODULE_ID]?.lootManifestImport;
  if (primary && typeof primary === "object") return primary;
  const legacy = entry?.flags?.["party-operations"]?.lootManifestImport;
  if (legacy && typeof legacy === "object") return legacy;
  return {};
}

function parseCompendiumItemSourceReference(value = "") {
  const raw = String(value ?? "").trim();
  if (!raw) return null;
  const match = raw.match(/^Compendium\.(.+)\.Item\.([^.]+)$/i);
  if (!match) return null;
  return {
    packId: String(match[1] ?? "").trim(),
    itemId: String(match[2] ?? "").trim()
  };
}

function buildLootManifestImportSourceKey(packId = "", itemId = "") {
  const normalizedPackId = String(packId ?? "").trim();
  const normalizedItemId = String(itemId ?? "").trim();
  if (!normalizedPackId || !normalizedItemId) return "";
  return `${normalizedPackId}:${normalizedItemId}`;
}

function getLootManifestImportedSourceKey(entry = {}) {
  const importFlag = getLootManifestImportFlag(entry);
  const flaggedKey = buildLootManifestImportSourceKey(importFlag?.sourcePackId, importFlag?.sourceItemId);
  if (flaggedKey) return flaggedKey;

  const sourceCandidates = [
    entry?.flags?.core?.sourceId,
    entry?._stats?.compendiumSource,
    entry?.flags?.[MODULE_ID]?.core?.sourceId,
    entry?.flags?.["party-operations"]?.core?.sourceId
  ];
  for (const candidate of sourceCandidates) {
    const parsed = parseCompendiumItemSourceReference(candidate);
    const key = buildLootManifestImportSourceKey(parsed?.packId, parsed?.itemId);
    if (key) return key;
  }
  return "";
}

function buildLootManifestCompendiumFolderDescriptors(pack, itemRows = []) {
  const descriptorMap = new Map();
  let usedMetadata = false;

  for (const item of Array.isArray(itemRows) ? itemRows : []) {
    const folderMeta = item?.folderMeta;
    const path = Array.isArray(folderMeta?.path) ? folderMeta.path : [];
    if (path.length <= 0) continue;
    usedMetadata = true;

    let parentKey = "";
    const pathKeys = [];
    for (const segment of path) {
      const segmentKey = String(segment?.key ?? "").trim().toLowerCase();
      const segmentLabel = String(segment?.label ?? "").trim();
      if (!segmentKey || !segmentLabel) continue;
      pathKeys.push(segmentKey);
      const descriptorKey = `meta:${pathKeys.join("/")}`;
      if (!descriptorMap.has(descriptorKey)) {
        descriptorMap.set(descriptorKey, {
          key: descriptorKey,
          sourceFolderId: "",
          name: segmentLabel,
          parentKey,
          sort: Number(segment?.sort ?? ((pathKeys.length) * 1000)) || ((pathKeys.length) * 1000)
        });
      }
      parentKey = descriptorKey;
    }
  }

  if (!usedMetadata) {
    const actualFolders = getCompendiumFolderRows(pack)
      .map((folder) => {
        const id = String(folder?.id ?? folder?._id ?? "").trim();
        if (!id) return null;
        return {
          key: `folder:${id}`,
          sourceFolderId: id,
          name: String(folder?.name ?? "").trim() || "Other",
          parentKey: (() => {
            const parentId = getDocumentFolderParentId(folder);
            return parentId ? `folder:${parentId}` : "";
          })(),
          sort: Number(folder?.sort ?? 0) || 0
        };
      })
      .filter(Boolean);

    for (const descriptor of actualFolders) {
      descriptorMap.set(descriptor.key, descriptor);
    }

    const rootDescriptorByName = new Map(
      Array.from(descriptorMap.values())
        .filter((descriptor) => !descriptor.parentKey)
        .map((descriptor) => [getLootManifestFolderNameKey(descriptor.name), descriptor.key])
    );

    for (const item of Array.isArray(itemRows) ? itemRows : []) {
      const sourceFolderId = String(item?.folderId ?? "").trim();
      if (sourceFolderId && descriptorMap.has(`folder:${sourceFolderId}`)) continue;
      const normalizedType = normalizeLootManifestItemType(item?.type) || "other";
      const label = getLootManifestFolderLabelForType(normalizedType);
      const existingRootKey = rootDescriptorByName.get(getLootManifestFolderNameKey(label));
      if (existingRootKey) continue;
      const key = `type:${normalizedType}`;
      if (descriptorMap.has(key)) continue;
      descriptorMap.set(key, {
        key,
        sourceFolderId: "",
        name: label,
        parentKey: "",
        sort: getLootManifestFolderSortPriority(normalizedType) * 1000
      });
      rootDescriptorByName.set(getLootManifestFolderNameKey(label), key);
    }
  }

  const getDepth = (descriptor) => {
    let depth = 0;
    let currentKey = String(descriptor?.parentKey ?? "").trim();
    const visited = new Set([String(descriptor?.key ?? "").trim()]);
    while (currentKey && depth < 20) {
      if (visited.has(currentKey)) break;
      visited.add(currentKey);
      const current = descriptorMap.get(currentKey);
      if (!current) break;
      depth += 1;
      currentKey = String(current?.parentKey ?? "").trim();
    }
    return depth;
  };

  return Array.from(descriptorMap.values()).sort((left, right) => {
    const depthDelta = getDepth(left) - getDepth(right);
    if (depthDelta !== 0) return depthDelta;
    const sortDelta = Number(left?.sort ?? 0) - Number(right?.sort ?? 0);
    if (sortDelta !== 0) return sortDelta;
    return String(left?.name ?? "").localeCompare(String(right?.name ?? ""));
  });
}

async function ensureLootManifestWorldImportRootFolder(pack) {
  const packId = String(pack?.collection ?? "").trim();
  const preferredName = String(pack?.metadata?.label ?? pack?.title ?? LOOT_MANIFEST_PACK_LABEL).trim() || LOOT_MANIFEST_PACK_LABEL;
  const itemFolders = (game.folders?.contents ?? []).filter((folder) => {
    const type = String(folder?.type ?? folder?.documentName ?? "").trim().toLowerCase();
    return type === "item";
  });

  let rootFolder = itemFolders.find((folder) => {
    const importFlag = getLootManifestImportFlag(folder);
    return importFlag?.isRoot === true && String(importFlag?.sourcePackId ?? "").trim() === packId;
  }) ?? null;

  if (!rootFolder) {
    rootFolder = itemFolders.find((folder) => {
      if (getDocumentFolderParentId(folder)) return false;
      return String(folder?.name ?? "").trim() === preferredName;
    }) ?? null;
  }

  const flagData = {
    managed: true,
    isRoot: true,
    sourcePackId: packId,
    importedAt: Date.now()
  };

  if (!rootFolder) {
    return Folder.create({
      name: preferredName,
      type: "Item",
      folder: null,
      sorting: "a",
      color: null,
      sort: -1000,
      flags: {
        [MODULE_ID]: {
          lootManifestImport: flagData
        }
      }
    });
  }

  const needsUpdate = String(rootFolder?.name ?? "").trim() !== preferredName
    || getDocumentFolderParentId(rootFolder)
    || getLootManifestImportFlag(rootFolder)?.isRoot !== true
    || String(getLootManifestImportFlag(rootFolder)?.sourcePackId ?? "").trim() !== packId;
  if (needsUpdate) {
    await rootFolder.update({
      name: preferredName,
      folder: null,
      flags: {
        [MODULE_ID]: {
          lootManifestImport: flagData
        }
      }
    });
  }
  return rootFolder;
}

async function ensureLootManifestWorldImportFolders(pack, rootFolder, itemRows = []) {
  const descriptors = buildLootManifestCompendiumFolderDescriptors(pack, itemRows);
  const packId = String(pack?.collection ?? "").trim();
  const worldItemFolders = (game.folders?.contents ?? []).filter((folder) => {
    const type = String(folder?.type ?? folder?.documentName ?? "").trim().toLowerCase();
    return type === "item";
  });
  const descriptorFolderMap = new Map();
  const existingBySourceFolderId = new Map();
  const existingBySourceFolderKey = new Map();
  const existingByParentAndName = new Map();

  for (const folder of worldItemFolders) {
    const importFlag = getLootManifestImportFlag(folder);
    if (importFlag?.isRoot === true && String(importFlag?.sourcePackId ?? "").trim() === packId) continue;
    const sourceFolderId = String(importFlag?.sourceFolderId ?? "").trim();
    if (sourceFolderId && String(importFlag?.sourcePackId ?? "").trim() === packId) {
      existingBySourceFolderId.set(sourceFolderId, folder);
    }
    const sourceFolderKey = String(importFlag?.sourceFolderKey ?? "").trim();
    if (sourceFolderKey && String(importFlag?.sourcePackId ?? "").trim() === packId) {
      existingBySourceFolderKey.set(sourceFolderKey, folder);
    }
    const parentId = getDocumentFolderParentId(folder) || rootFolder.id;
    const nameKey = getLootManifestFolderNameKey(folder?.name);
    if (nameKey) existingByParentAndName.set(`${parentId}::${nameKey}`, folder);
  }

  let createdFolders = 0;
  let updatedFolders = 0;

  for (const descriptor of descriptors) {
    const parentFolderId = descriptor.parentKey
      ? (descriptorFolderMap.get(descriptor.parentKey)?.id ?? rootFolder.id)
      : rootFolder.id;
    const sourceFolderId = String(descriptor?.sourceFolderId ?? "").trim();
    const sourceFolderKey = String(descriptor?.key ?? "").trim();
    const nameKey = getLootManifestFolderNameKey(descriptor?.name);
    let folder = sourceFolderKey ? existingBySourceFolderKey.get(sourceFolderKey) ?? null : null;
    if (!folder) folder = sourceFolderId ? existingBySourceFolderId.get(sourceFolderId) ?? null : null;
    if (!folder) folder = existingByParentAndName.get(`${parentFolderId}::${nameKey}`) ?? null;

    const flagData = {
      managed: true,
      isRoot: false,
      sourcePackId: packId,
      sourceFolderId,
      sourceFolderKey,
      importedAt: Date.now()
    };

    if (!folder) {
      folder = await Folder.create({
        name: String(descriptor?.name ?? "Other"),
        type: "Item",
        folder: parentFolderId,
        sorting: "a",
        color: null,
        sort: Number(descriptor?.sort ?? 0) || 0,
        flags: {
          [MODULE_ID]: {
            lootManifestImport: flagData
          }
        }
      });
      createdFolders += 1;
    } else {
      const currentImportFlag = getLootManifestImportFlag(folder);
      const needsUpdate = String(folder?.name ?? "").trim() !== String(descriptor?.name ?? "").trim()
        || String(getDocumentFolderParentId(folder) || rootFolder.id).trim() !== String(parentFolderId).trim()
        || String(currentImportFlag?.sourcePackId ?? "").trim() !== packId
        || String(currentImportFlag?.sourceFolderId ?? "").trim() !== sourceFolderId
        || String(currentImportFlag?.sourceFolderKey ?? "").trim() !== sourceFolderKey
        || currentImportFlag?.isRoot === true;
      if (needsUpdate) {
        await folder.update({
          name: String(descriptor?.name ?? "Other"),
          folder: parentFolderId,
          sort: Number(descriptor?.sort ?? 0) || 0,
          flags: {
            [MODULE_ID]: {
              lootManifestImport: flagData
            }
          }
        });
        updatedFolders += 1;
      }
    }

    descriptorFolderMap.set(String(descriptor?.key ?? "").trim(), folder);
    const folderParentId = getDocumentFolderParentId(folder) || rootFolder.id;
    existingByParentAndName.set(`${folderParentId}::${nameKey}`, folder);
    if (sourceFolderId) existingBySourceFolderId.set(sourceFolderId, folder);
    if (sourceFolderKey) existingBySourceFolderKey.set(sourceFolderKey, folder);
  }

  return {
    descriptorFolderMap,
    createdFolders,
    updatedFolders
  };
}

function chunkDocumentRows(rows = [], size = 50) {
  const source = Array.isArray(rows) ? rows : [];
  const chunkSize = Math.max(1, Math.floor(Number(size) || 50));
  const chunks = [];
  for (let index = 0; index < source.length; index += chunkSize) {
    chunks.push(source.slice(index, index + chunkSize));
  }
  return chunks;
}

function buildFolderTreeScopeIds(folders = []) {
  const seedFolders = Array.isArray(folders) ? folders : [];
  const allItemFolders = (game.folders?.contents ?? []).filter((folder) => {
    const type = String(folder?.type ?? folder?.documentName ?? "").trim().toLowerCase();
    return type === "item";
  });
  const childrenByParentId = new Map();
  for (const folder of allItemFolders) {
    const parentId = getDocumentFolderParentId(folder);
    if (!parentId) continue;
    if (!childrenByParentId.has(parentId)) childrenByParentId.set(parentId, []);
    childrenByParentId.get(parentId).push(folder);
  }

  const scopedIds = new Set();
  const pending = [...seedFolders];
  while (pending.length > 0) {
    const folder = pending.pop();
    const folderId = String(folder?.id ?? "").trim();
    if (!folderId || scopedIds.has(folderId)) continue;
    scopedIds.add(folderId);
    for (const child of (childrenByParentId.get(folderId) ?? [])) pending.push(child);
  }
  return scopedIds;
}

function getLootManifestImportedWorldItems(pack, options = {}) {
  const packId = String(pack?.collection ?? "").trim();
  if (!packId) return [];
  const managedFolderIds = options?.managedFolderIds instanceof Set
    ? options.managedFolderIds
    : new Set();
  return (game.items?.contents ?? []).filter((item) => {
    const folderId = String(item?.folder?.id ?? item?.folder ?? item?.folderId ?? "").trim();
    if (folderId && managedFolderIds.has(folderId)) return true;
    const importFlag = getLootManifestImportFlag(item);
    if (String(importFlag?.sourcePackId ?? "").trim() === packId) return true;
    const sourceKey = getLootManifestImportedSourceKey(item);
    return sourceKey.startsWith(`${packId}:`);
  });
}

function getLootManifestManagedWorldFolders(pack) {
  const packId = String(pack?.collection ?? "").trim();
  if (!packId) return [];
  return (game.folders?.contents ?? []).filter((folder) => {
    const type = String(folder?.type ?? folder?.documentName ?? "").trim().toLowerCase();
    if (type !== "item") return false;
    const importFlag = getLootManifestImportFlag(folder);
    return String(importFlag?.sourcePackId ?? "").trim() === packId;
  });
}

function sortFoldersDeepestFirst(folders = []) {
  const rows = Array.isArray(folders) ? folders : [];
  const byId = new Map(rows.map((folder) => [String(folder?.id ?? "").trim(), folder]));
  const getDepth = (folder) => {
    let depth = 0;
    let parentId = getDocumentFolderParentId(folder);
    const visited = new Set([String(folder?.id ?? "").trim()]);
    while (parentId && depth < 30) {
      if (visited.has(parentId)) break;
      visited.add(parentId);
      const parent = byId.get(parentId);
      if (!parent) break;
      depth += 1;
      parentId = getDocumentFolderParentId(parent);
    }
    return depth;
  };
  return [...rows].sort((left, right) => getDepth(right) - getDepth(left));
}

async function clearLootManifestImportedWorldItems() {
  if (!canAccessAllPlayerOps()) {
    ui.notifications?.warn("Only the GM can clear imported built loot items.");
    return { ok: false, reason: "not-gm" };
  }

  const pack = getLootManifestCompendiumPack();
  if (!pack) {
    ui.notifications?.warn("Party Operations built-items compendium was not found.");
    return { ok: false, reason: "pack-missing" };
  }

  const managedFolders = getLootManifestManagedWorldFolders(pack);
  const managedFolderIds = buildFolderTreeScopeIds(managedFolders);
  const importedItems = getLootManifestImportedWorldItems(pack, { managedFolderIds });
  if (importedItems.length <= 0 && managedFolders.length <= 0) {
    ui.notifications?.info("No imported built items were found in the world.");
    return { ok: true, packId: String(pack?.collection ?? "").trim(), deletedItems: 0, deletedFolders: 0 };
  }

  const confirmed = await Dialog.confirm({
    title: "Clear Imported Built Items",
    content: `
      <p>This will remove imported Party Operations built items from the world.</p>
      <p><strong>Items:</strong> ${importedItems.length}</p>
      <p><strong>Managed folders:</strong> ${managedFolders.length}</p>
      <p>This does not modify the source compendium.</p>
    `,
    yes: () => true,
    no: () => false,
    defaultYes: false
  });
  if (!confirmed) return { ok: false, reason: "cancelled" };

  for (const batch of chunkDocumentRows(importedItems.map((item) => String(item?.id ?? "").trim()).filter(Boolean), 50)) {
    if (batch.length <= 0) continue;
    await Item.deleteDocuments(batch);
  }

  const remainingScopedItems = getLootManifestImportedWorldItems(pack, { managedFolderIds });
  let deletedFolders = 0;
  for (const folder of sortFoldersDeepestFirst(managedFolders)) {
    const folderId = String(folder?.id ?? "").trim();
    if (!folderId) continue;
    const folderStillHasItems = (game.items?.contents ?? []).some((item) => {
      const itemFolderId = String(item?.folder?.id ?? item?.folder ?? item?.folderId ?? "").trim();
      return itemFolderId === folderId;
    });
    if (folderStillHasItems) continue;
    try {
      await folder.delete();
      deletedFolders += 1;
    } catch (error) {
      console.warn(`${MODULE_ID}: failed to delete managed loot import folder`, folder, error);
    }
  }

  await updateLootSourceConfig((config) => {
    if (!config.filters || typeof config.filters !== "object") config.filters = {};
    const currentManifestId = String(config.filters.manifestPackId ?? "").trim();
    const selectedFolderId = parseLootWorldItemsFolderFilterId(currentManifestId);
    const deletedFolderIds = new Set(managedFolders.map((folder) => String(folder?.id ?? "").trim()).filter(Boolean));
    if (selectedFolderId && deletedFolderIds.has(selectedFolderId)) {
      config.filters.manifestPackId = "";
    }
  }, { skipLocalRefresh: true });
  refreshOpenApps({ scope: REFRESH_SCOPE_KEYS.LOOT });

  const report = {
    ok: true,
    packId: String(pack?.collection ?? "").trim(),
    deletedItems: importedItems.length,
    deletedFolders
  };
  if (remainingScopedItems.length > 0) {
    ui.notifications?.warn(
      `Cleared ${report.deletedItems} imported built item(s). `
      + `${remainingScopedItems.length} item(s) still remain in the managed folder tree, so folders were left in place.`
    );
  } else {
    ui.notifications?.info(`Cleared ${report.deletedItems} imported built item(s) and ${report.deletedFolders} folder(s).`);
  }
  return report;
}

async function importLootManifestCompendiumToWorld() {
  if (!canAccessAllPlayerOps()) {
    ui.notifications?.warn("Only the GM can import built loot items.");
    return { ok: false, reason: "not-gm" };
  }

  const pack = getLootManifestCompendiumPack();
  if (!pack) {
    ui.notifications?.warn("Party Operations built-items compendium was not found.");
    return { ok: false, reason: "pack-missing" };
  }

  const syncReport = await scheduleLootManifestCompendiumTypeFolderSync("world-import").catch(() => null);
  if (syncReport?.ok === false && isModuleDebugEnabled()) {
    console.warn(`${MODULE_ID}: proceeding with loot manifest world import after folder sync warning`, syncReport);
  }

  if (typeof pack?.getFolders === "function") {
    try {
      await pack.getFolders();
    } catch (error) {
      console.warn(`${MODULE_ID}: failed to preload loot manifest compendium folders`, error);
    }
  }

  const documents = typeof pack?.getDocuments === "function" ? await pack.getDocuments() : [];
  if (!Array.isArray(documents) || documents.length <= 0) {
    ui.notifications?.warn("The built-items compendium is empty.");
    return { ok: false, reason: "pack-empty" };
  }
  const indexedRows = await getLootManifestPackItemRows(pack);
  const indexedRowMap = new Map((Array.isArray(indexedRows) ? indexedRows : []).map((row) => [String(row?.id ?? "").trim(), row]));
  const itemRows = documents.map((entry) => {
    const id = String(entry?.id ?? entry?._id ?? "").trim();
    const indexed = indexedRowMap.get(id) ?? {};
    return {
      id,
      type: normalizeLootManifestItemType(entry?.type ?? indexed?.type),
      name: String(entry?.name ?? indexed?.name ?? "").trim(),
      folderId: String(entry?.folder?.id ?? entry?.folder ?? indexed?.folderId ?? "").trim(),
      folderMeta: getLootItemFolderProfileFromData(entry) ?? indexed?.folderMeta ?? null
    };
  }).filter((entry) => entry.id);

  const rootFolder = await ensureLootManifestWorldImportRootFolder(pack);
  const { descriptorFolderMap, createdFolders, updatedFolders } = await ensureLootManifestWorldImportFolders(pack, rootFolder, itemRows);
  const itemRowById = new Map((Array.isArray(itemRows) ? itemRows : []).map((row) => [String(row?.id ?? "").trim(), row]));
  const rootDescriptorByName = new Map(
    Array.from(descriptorFolderMap.entries())
      .filter(([, folder]) => String(getDocumentFolderParentId(folder) || rootFolder.id).trim() === String(rootFolder.id).trim())
      .map(([key, folder]) => [getLootManifestFolderNameKey(folder?.name), key])
  );
  const importedItemMap = new Map(
    (game.items?.contents ?? [])
      .map((item) => [getLootManifestImportedSourceKey(item), item])
      .filter(([key]) => key)
  );

  const createData = [];
  const updateData = [];
  const timestamp = Date.now();

  for (const documentRef of documents) {
    const sourceItemId = String(documentRef?.id ?? documentRef?._id ?? "").trim();
    if (!sourceItemId) continue;
    const sourceKey = buildLootManifestImportSourceKey(pack.collection, sourceItemId);
    if (!sourceKey) continue;
    const row = itemRowById.get(sourceItemId) ?? {};
    const folderMeta = getLootItemFolderProfileFromData(documentRef) ?? row?.folderMeta ?? null;
    const sourceFolderId = String(documentRef?.folder?.id ?? documentRef?.folder ?? row?.folderId ?? "").trim();
    let descriptorKey = String(folderMeta?.pathKey ?? "").trim();
    if (descriptorKey) descriptorKey = `meta:${descriptorKey}`;
    if (!descriptorKey) descriptorKey = sourceFolderId ? `folder:${sourceFolderId}` : "";
    if (!descriptorFolderMap.has(descriptorKey)) {
      const typeLabel = getLootManifestFolderLabelForType(documentRef?.type ?? row?.type ?? "other");
      descriptorKey = rootDescriptorByName.get(getLootManifestFolderNameKey(typeLabel)) ?? "";
    }
    const targetFolderId = descriptorFolderMap.get(descriptorKey)?.id ?? rootFolder.id;
    const sourceUuid = String(documentRef?.uuid ?? `Compendium.${pack.collection}.Item.${sourceItemId}`).trim();
    const data = typeof documentRef?.toObject === "function" ? documentRef.toObject() : foundry.utils.deepClone(documentRef);
    if (data && typeof data === "object" && "_id" in data) delete data._id;
    data.folder = targetFolderId;
    data.flags = data.flags && typeof data.flags === "object" ? data.flags : {};
    data.flags.core = data.flags.core && typeof data.flags.core === "object" ? data.flags.core : {};
    data.flags.core.sourceId = sourceUuid;
    data.flags[MODULE_ID] = data.flags[MODULE_ID] && typeof data.flags[MODULE_ID] === "object" ? data.flags[MODULE_ID] : {};
    data.flags[MODULE_ID].lootManifestImport = {
      managed: true,
      sourcePackId: pack.collection,
      sourceItemId,
      sourceUuid,
      sourceFolderId,
      sourceFolderPathKey: String(folderMeta?.pathKey ?? "").trim(),
      sourceFolderKey: descriptorKey,
      importedAt: timestamp
    };

    const existing = importedItemMap.get(sourceKey) ?? null;
    if (existing) {
      updateData.push({
        _id: existing.id,
        ...data
      });
      continue;
    }
    createData.push(data);
  }

  for (const batch of chunkDocumentRows(updateData, 50)) {
    if (batch.length <= 0) continue;
    await Item.updateDocuments(batch);
  }
  for (const batch of chunkDocumentRows(createData, 50)) {
    if (batch.length <= 0) continue;
    await Item.createDocuments(batch);
  }

  await updateLootSourceConfig((config) => {
    if (!Array.isArray(config.packs)) config.packs = [];
    let worldSource = config.packs.find((entry) => String(entry?.id ?? "").trim() === LOOT_WORLD_ITEMS_SOURCE_ID);
    if (!worldSource) {
      config.packs.unshift(buildLootWorldItemSourceEntry({ enabled: true }));
      worldSource = config.packs[0];
    }
    worldSource.enabled = true;
    if (!config.filters || typeof config.filters !== "object") config.filters = {};
    config.filters.manifestPackId = buildLootWorldItemsFolderFilterId(rootFolder.id);
  }, { skipLocalRefresh: true });
  refreshOpenApps({ scope: REFRESH_SCOPE_KEYS.LOOT });

  const report = {
    ok: true,
    packId: String(pack?.collection ?? "").trim(),
    rootFolderId: String(rootFolder?.id ?? "").trim(),
    createdFolders,
    updatedFolders,
    createdItems: createData.length,
    updatedItems: updateData.length
  };
  const importedItemCount = report.createdItems + report.updatedItems;
  const touchedFolderCount = report.createdFolders + report.updatedFolders;
  const sourceCompendiumFlat = syncReport?.reason === "pack-read-only" || syncReport?.reason === "pack-locked";
  ui.notifications?.info(
    `Imported ${importedItemCount} built item(s) into organized world folders `
    + `(${touchedFolderCount} folder ${touchedFolderCount === 1 ? "change" : "changes"}).`
    + (sourceCompendiumFlat ? " The source compendium stays flat because that pack is read-only." : "")
  );
  return report;
}

function getAvailableLootItemPackSources() {
  const rows = [{
    id: LOOT_WORLD_ITEMS_SOURCE_ID,
    label: "World Item Directory",
    sourceKind: "world-items"
  }];
  for (const pack of getAllCompendiumPacks()) {
    const documentName = String(pack?.documentName ?? pack?.metadata?.type ?? "").trim().toLowerCase();
    if (documentName !== "item") continue;
    const id = String(pack?.collection ?? "").trim();
    if (!id) continue;
    const packageLabel = String(pack?.metadata?.packageName ?? pack?.metadata?.package ?? "").trim();
    const baseLabel = String(pack?.metadata?.label ?? pack?.title ?? id).trim() || id;
    rows.push({
      id,
      label: packageLabel ? `${baseLabel} (${packageLabel})` : baseLabel,
      sourceKind: "compendium-pack"
    });
  }
  return rows
    .filter((entry, index, list) => entry.id && list.findIndex((candidate) => candidate.id === entry.id) === index)
    .sort((a, b) => a.label.localeCompare(b.label));
}

function getAvailableLootTableSources() {
  const rows = [];

  for (const table of game.tables?.contents ?? []) {
    const uuid = String(table?.uuid ?? "").trim();
    if (!uuid) continue;
    const name = String(table?.name ?? "World Roll Table").trim() || "World Roll Table";
    rows.push({
      id: `world-table:${uuid}`,
      label: `${name} (World Table)`,
      sourceKind: "world-table"
    });
  }

  for (const pack of getAllCompendiumPacks()) {
    const documentName = String(pack?.documentName ?? pack?.metadata?.type ?? "").trim().toLowerCase();
    if (documentName !== "rolltable") continue;
    const id = String(pack?.collection ?? "").trim();
    if (!id) continue;
    const packageLabel = String(pack?.metadata?.packageName ?? pack?.metadata?.package ?? "").trim();
    const baseLabel = String(pack?.metadata?.label ?? pack?.title ?? id).trim() || id;
    rows.push({
      id: `table-pack:${id}`,
      label: packageLabel ? `${baseLabel} (${packageLabel})` : baseLabel,
      sourceKind: "table-pack"
    });
  }

  return rows
    .filter((entry, index, list) => entry.id && list.findIndex((candidate) => candidate.id === entry.id) === index)
    .sort((a, b) => a.label.localeCompare(b.label));
}

function normalizeLootSourceSearchText(value) {
  return String(value ?? "")
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function tokenizeLootSourceSearchText(value) {
  const normalized = normalizeLootSourceSearchText(value);
  return normalized ? normalized.split(" ") : [];
}

function hasEditDistanceWithin(sourceToken, queryToken, maxDistance = 1) {
  if (sourceToken === queryToken) return true;
  const sourceLength = sourceToken.length;
  const queryLength = queryToken.length;
  if (!sourceLength || !queryLength) return false;
  if (Math.abs(sourceLength - queryLength) > maxDistance) return false;

  let previousRow = Array.from({ length: queryLength + 1 }, (_entry, index) => index);
  for (let rowIndex = 1; rowIndex <= sourceLength; rowIndex += 1) {
    const currentRow = [rowIndex];
    let rowMin = currentRow[0];
    for (let colIndex = 1; colIndex <= queryLength; colIndex += 1) {
      const substitutionCost = sourceToken[rowIndex - 1] === queryToken[colIndex - 1] ? 0 : 1;
      const value = Math.min(
        previousRow[colIndex] + 1,
        currentRow[colIndex - 1] + 1,
        previousRow[colIndex - 1] + substitutionCost
      );
      currentRow[colIndex] = value;
      if (value < rowMin) rowMin = value;
    }
    if (rowMin > maxDistance) return false;
    previousRow = currentRow;
  }
  return previousRow[queryLength] <= maxDistance;
}

function doesLootSourceTokenMatch(queryToken, candidateToken) {
  if (!queryToken || !candidateToken) return false;
  if (candidateToken.includes(queryToken) || queryToken.includes(candidateToken)) return true;

  const queryStem = queryToken.length > 4 && queryToken.endsWith("s") ? queryToken.slice(0, -1) : queryToken;
  const candidateStem = candidateToken.length > 4 && candidateToken.endsWith("s") ? candidateToken.slice(0, -1) : candidateToken;
  if (candidateStem.includes(queryStem) || queryStem.includes(candidateStem)) return true;

  const queryPrefix = queryStem.slice(0, Math.min(4, queryStem.length));
  const candidatePrefix = candidateStem.slice(0, Math.min(4, candidateStem.length));
  if (queryPrefix.length >= 3 && candidateStem.startsWith(queryPrefix)) return true;
  if (candidatePrefix.length >= 3 && queryStem.startsWith(candidatePrefix)) return true;

  const maxDistance = queryStem.length >= 6 ? 2 : 1;
  return hasEditDistanceWithin(candidateStem, queryStem, maxDistance);
}

function matchesLootSourceSearchQuery(query, source = {}) {
  const normalizedQuery = normalizeLootSourceSearchText(query);
  if (!normalizedQuery) return true;
  const queryTokens = tokenizeLootSourceSearchText(normalizedQuery);
  if (queryTokens.length === 0) return true;

  const searchableText = normalizeLootSourceSearchText([
    source.label,
    source.id,
    source.sourceKind,
    source.available ? "available" : "unavailable",
    source.enabled ? "enabled" : "disabled"
  ].join(" "));

  if (!searchableText) return false;
  if (searchableText.includes(normalizedQuery)) return true;

  const searchableTokens = tokenizeLootSourceSearchText(searchableText);
  return queryTokens.every((queryToken) => {
    if (searchableText.includes(queryToken)) return true;
    return searchableTokens.some((candidateToken) => doesLootSourceTokenMatch(queryToken, candidateToken));
  });
}

function getLootSourceDocumentsForEditor(config = getLootSourceConfig()) {
  const enabledSourceIds = new Set(
    (Array.isArray(config?.packs) ? config.packs : [])
      .filter((entry) => entry?.enabled !== false)
      .map((entry) => String(entry?.id ?? "").trim())
      .filter(Boolean)
  );
  if (!enabledSourceIds.has(LOOT_WORLD_ITEMS_SOURCE_ID)) return [];
  return (game.items?.contents ?? []).filter((item) => {
    const itemType = String(item?.type ?? "").trim().toLowerCase();
    if (!itemType) return false;
    const data = getMerchantItemData(item);
    const poFlags = getPartyOperationsItemFlags(data);
    return poFlags?.lootEligible !== false;
  });
}

function buildLootTagCatalogForEditor(config = getLootSourceConfig()) {
  const tags = new Set();
  const documents = getLootSourceDocumentsForEditor(config);
  for (const documentRef of documents) {
    const data = getMerchantItemData(documentRef);
    const keywords = getLootKeywordsFromData(data);
    for (const keyword of keywords) {
      const normalized = String(keyword ?? "").trim().toLowerCase();
      if (!normalized) continue;
      tags.add(normalized);
    }
  }
  return Array.from(tags)
    .sort((a, b) => String(a).localeCompare(String(b)))
    .slice(0, 400);
}

function buildLootSourceRegistryContext() {
  const config = getLootSourceConfig();
  const availablePacks = getLootGenerationItemPackSources();
  const availableTables = getAvailableLootTableSources();
  const packLookup = new Map((config.packs ?? []).map((entry) => [entry.id, entry]));
  const tableLookup = new Map((config.tables ?? []).map((entry) => [entry.id, entry]));

  const itemPackOptions = availablePacks.map((source) => {
    const stored = packLookup.get(source.id);
    const weightRaw = Number(stored?.weight ?? 1);
    return {
      id: source.id,
      label: source.label,
      sourceKind: source.sourceKind,
      available: true,
      enabled: Boolean(stored?.enabled),
      weight: Number.isFinite(weightRaw) ? Math.max(1, Math.floor(weightRaw)) : 1
    };
  });

  for (const stored of config.packs ?? []) {
    if (itemPackOptions.some((entry) => entry.id === stored.id)) continue;
    const weightRaw = Number(stored?.weight ?? 1);
    itemPackOptions.push({
      id: stored.id,
      label: stored.label || `${stored.id} (Unavailable)`,
      sourceKind: stored.sourceKind,
      available: false,
      enabled: Boolean(stored.enabled),
      weight: Number.isFinite(weightRaw) ? Math.max(1, Math.floor(weightRaw)) : 1
    });
  }

  const tableOptions = availableTables.map((source) => {
    const stored = tableLookup.get(source.id);
    const currentType = String(stored?.tableType ?? "currency");
    return {
      id: source.id,
      label: source.label,
      sourceKind: source.sourceKind,
      available: true,
      enabled: Boolean(stored?.enabled),
      tableType: currentType,
      typeOptions: LOOT_TABLE_TYPE_OPTIONS.map((option) => ({
        value: option.value,
        label: option.label,
        selected: option.value === currentType
      }))
    };
  });

  for (const stored of config.tables ?? []) {
    if (tableOptions.some((entry) => entry.id === stored.id)) continue;
    const currentType = String(stored?.tableType ?? "currency");
    tableOptions.push({
      id: stored.id,
      label: stored.label || `${stored.id} (Unavailable)`,
      sourceKind: stored.sourceKind,
      available: false,
      enabled: Boolean(stored.enabled),
      tableType: currentType,
      typeOptions: LOOT_TABLE_TYPE_OPTIONS.map((option) => ({
        value: option.value,
        label: option.label,
        selected: option.value === currentType
      }))
    });
  }

  itemPackOptions.sort((a, b) => {
    const enabledDelta = Number(Boolean(b.enabled)) - Number(Boolean(a.enabled));
    if (enabledDelta !== 0) return enabledDelta;
    return a.label.localeCompare(b.label);
  });
  tableOptions.sort((a, b) => {
    const enabledDelta = Number(Boolean(b.enabled)) - Number(Boolean(a.enabled));
    if (enabledDelta !== 0) return enabledDelta;
    return a.label.localeCompare(b.label);
  });

  const itemPackUi = getLootPackSourcesUiState();
  const itemPackFilter = normalizeLootPackSourcesFilter(itemPackUi.filter);
  const itemPackVisibleOptions = itemPackOptions.filter((entry) => matchesLootSourceSearchQuery(itemPackFilter, entry));
  const itemPackCollapsed = Boolean(itemPackUi.collapsed);

  const selectedTypes = new Set(config.filters?.allowedTypes ?? []);
  const itemTypeOptions = buildLootItemTypeCatalog().map((entry) => ({
    value: entry.value,
    label: entry.label,
    selected: selectedTypes.has(entry.value)
  }));

  const rarityFloor = normalizeLootRarityValue(config.filters?.rarityFloor);
  const rarityCeiling = normalizeLootRarityValue(config.filters?.rarityCeiling);
  const manifestPackId = String(config.filters?.manifestPackId ?? "").trim();
  const manifestPackOptions = buildLootManifestPackOptions(manifestPackId, itemPackOptions);
  const tagCatalog = buildLootTagCatalogForEditor(config);
  const includeTagOptions = buildMerchantTagOptionsForEditor(tagCatalog, config.filters?.keywordIncludeTags ?? []);
  const excludeTagOptions = buildMerchantTagOptionsForEditor(tagCatalog, config.filters?.keywordExcludeTags ?? []);
  const includeTagGroups = buildMerchantTagGroupsForEditor(includeTagOptions);
  const excludeTagGroups = buildMerchantTagGroupsForEditor(excludeTagOptions);
  const taxonomySummary = buildPartyOperationsTaxonomySummaryFromDocuments(getLootSourceDocumentsForEditor(config));
  const keywordIncludeMode = normalizeLootKeywordIncludeMode(config.filters?.keywordIncludeMode, LOOT_KEYWORD_INCLUDE_MODES.ALL);
  const keywordIncludeTagsInput = formatLootKeywordTagListForInput(config.filters?.keywordIncludeTags ?? []);
  const keywordExcludeTagsInput = formatLootKeywordTagListForInput(config.filters?.keywordExcludeTags ?? []);
  const updatedAt = Number(config.updatedAt ?? 0);
  const updatedAtLabel = updatedAt > 0 ? new Date(updatedAt).toLocaleString() : "Not set";
  return {
    itemPackOptions,
    itemPackVisibleOptions,
    itemPackCollapsed,
    itemPackToggleLabel: itemPackCollapsed ? "Expand" : "Collapse",
    itemPackToggleIcon: itemPackCollapsed ? "fa-chevron-down" : "fa-chevron-up",
    itemPackFilter,
    itemPackFilterActive: itemPackFilter.length > 0,
    itemPackVisibleCount: itemPackVisibleOptions.length,
    tableOptions,
    itemTypeOptions,
    rarityFloorOptions: LOOT_RARITY_OPTIONS.map((entry) => ({
      value: entry.value,
      label: entry.label,
      selected: entry.value === rarityFloor
    })),
    rarityCeilingOptions: LOOT_RARITY_OPTIONS.map((entry) => ({
      value: entry.value,
      label: entry.label,
      selected: entry.value === rarityCeiling
    })),
    tagCatalogCount: tagCatalog.length,
    hasTagCatalog: tagCatalog.length > 0,
    includeTagOptions,
    excludeTagOptions,
    includeTagGroups,
    excludeTagGroups,
    hasIncludeTagGroups: includeTagGroups.length > 0,
    hasExcludeTagGroups: excludeTagGroups.length > 0,
    includeTagSelectedCount: includeTagOptions.filter((entry) => entry?.selected).length,
    excludeTagSelectedCount: excludeTagOptions.filter((entry) => entry?.selected).length,
    keywordIncludeMode,
    keywordIncludeModeAll: keywordIncludeMode === LOOT_KEYWORD_INCLUDE_MODES.ALL,
    keywordIncludeModeAny: keywordIncludeMode === LOOT_KEYWORD_INCLUDE_MODES.ANY,
    taxonomySummary,
    manifestPackOptions,
    manifestPackId,
    keywordIncludeTagsInput,
    keywordExcludeTagsInput,
    keywordIncludeTagCount: normalizeLootKeywordTagList(config.filters?.keywordIncludeTags ?? []).length,
    keywordExcludeTagCount: normalizeLootKeywordTagList(config.filters?.keywordExcludeTags ?? []).length,
    summary: {
      enabledItemPacks: itemPackOptions.filter((entry) => entry.enabled).length,
      totalItemPacks: itemPackOptions.length,
      enabledTables: tableOptions.filter((entry) => entry.enabled).length,
      totalTables: tableOptions.length,
      enabledItemTypes: itemTypeOptions.filter((entry) => entry.selected).length,
      totalItemTypes: itemTypeOptions.length,
      sourceItemCount: taxonomySummary.itemCount,
      tagSchemaLabel: taxonomySummary.schemaLabel,
      merchantCategoryCount: taxonomySummary.categoryRows.length,
      updatedAtLabel,
      updatedBy: String(config.updatedBy ?? "").trim() || "GM"
    }
  };
}

function getCollectionValues(collectionLike) {
  if (!collectionLike) return [];
  if (Array.isArray(collectionLike)) return collectionLike;
  if (typeof collectionLike.values === "function") return Array.from(collectionLike.values());
  if (Array.isArray(collectionLike.contents)) return collectionLike.contents;
  return [];
}

function logAutoInventoryDebug(message, details = null) {
  if (!isModuleDebugEnabled()) return;
  if (details === null) {
    console.debug(`[${MODULE_ID}][auto-inv] ${message}`);
    return;
  }
  console.debug(`[${MODULE_ID}][auto-inv] ${message}`, details);
}

function normalizeAutoInventoryName(value) {
  return String(value ?? "")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9\s]+/g, " ")
    .replace(/\s+/g, " ");
}

function parseAutoInventoryCrValue(rawValue) {
  if (rawValue === null || rawValue === undefined) return 0;
  if (typeof rawValue === "number") return Number.isFinite(rawValue) ? Math.max(0, rawValue) : 0;

  const raw = String(rawValue).trim().toLowerCase();
  if (!raw) return 0;
  if (raw.includes("/")) {
    const [leftRaw, rightRaw] = raw.split("/", 2);
    const left = Number(leftRaw);
    const right = Number(rightRaw);
    if (Number.isFinite(left) && Number.isFinite(right) && right !== 0) {
      return Math.max(0, left / right);
    }
  }

  const parsed = Number(raw);
  if (Number.isFinite(parsed)) return Math.max(0, parsed);
  return 0;
}

function getActorCrForAutoInventory(actor) {
  if (!actor) return 0;
  const details = actor.system?.details ?? {};
  const candidates = [
    details?.cr,
    details?.cr?.value,
    details?.challengeRating,
    details?.challenge?.rating
  ];
  for (const candidate of candidates) {
    const parsed = parseAutoInventoryCrValue(candidate);
    if (parsed > 0) return parsed;
  }
  return 0;
}

function normalizeAutoInventoryCreatureType(rawType) {
  const normalized = normalizeAutoInventoryName(rawType);
  if (!normalized) return "unknown";
  const rules = [
    ["humanoid", "humanoid"],
    ["beast", "beast"],
    ["undead", "undead"],
    ["construct", "construct"],
    ["elemental", "elemental"],
    ["ooze", "ooze"],
    ["dragon", "dragon"],
    ["fiend", "fiend"],
    ["celestial", "celestial"],
    ["aberration", "aberration"],
    ["fey", "fey"],
    ["giant", "giant"],
    ["monstrosity", "monstrosity"],
    ["plant", "plant"],
    ["swarm", "swarm"]
  ];
  for (const [needle, value] of rules) {
    if (normalized.includes(needle)) return value;
  }
  return "unknown";
}

function getActorCreatureTypeForAutoInventory(actor) {
  if (!actor) return "unknown";
  const detailsType = actor.system?.details?.type;
  if (detailsType && typeof detailsType === "object") {
    const fromObject = normalizeAutoInventoryCreatureType(
      detailsType?.value
      ?? detailsType?.subtype
      ?? detailsType?.custom
      ?? detailsType?.type
      ?? detailsType?.label
      ?? ""
    );
    if (fromObject !== "unknown") return fromObject;
  }
  const fromDirect = normalizeAutoInventoryCreatureType(detailsType);
  if (fromDirect !== "unknown") return fromDirect;
  return normalizeAutoInventoryCreatureType(actor.system?.details?.race ?? "");
}

function getActorAbilityScore(actor, abilityKey) {
  const key = String(abilityKey ?? "").trim().toLowerCase();
  if (!key) return 0;
  const node = actor?.system?.abilities?.[key];
  const value = Number(node?.value ?? node?.mod ?? 0);
  return Number.isFinite(value) ? value : 0;
}

function actorHasFeatureName(actor, pattern) {
  const regex = pattern instanceof RegExp ? pattern : null;
  if (!regex || !actor?.items) return false;
  for (const item of actor.items) {
    const name = String(item?.name ?? "").trim();
    if (!name) continue;
    if (regex.test(name)) return true;
  }
  return false;
}

function inferRole(actor) {
  if (!actor) return "none";
  const hasSpellItems = actor.items?.some((item) => String(item?.type ?? "").trim().toLowerCase() === "spell") ?? false;
  const spellSlots = actor.system?.spells ?? {};
  const hasSpellSlots = Object.values(spellSlots).some((slot) => {
    const max = Number(slot?.max ?? 0);
    return Number.isFinite(max) && max > 0;
  });
  const hasSpellcastingFeature = actorHasFeatureName(actor, /(spellcasting|innate spellcasting)/i);
  if (hasSpellItems || hasSpellSlots || hasSpellcastingFeature) return "caster";

  if (actorHasFeatureName(actor, /(sneak|stealth|cunning|scout|skirmish)/i)) return "scout";
  if (actorHasFeatureName(actor, /(rage|frenzy|brutal|reckless|berserk)/i)) return "brute";

  const str = getActorAbilityScore(actor, "str");
  const dex = getActorAbilityScore(actor, "dex");
  const con = getActorAbilityScore(actor, "con");
  const int = getActorAbilityScore(actor, "int");
  const wis = getActorAbilityScore(actor, "wis");
  const cha = getActorAbilityScore(actor, "cha");
  const martialTop = Math.max(str, dex);
  const casterTop = Math.max(int, wis, cha);

  if (str >= 16 && con >= 14) return "brute";
  if (dex >= 15 && dex > str + 1) return "scout";
  if (martialTop >= casterTop) return "martial";
  return "none";
}

function isLikelyIntelligentCreature(actor) {
  const intScore = getActorAbilityScore(actor, "int");
  if (intScore >= 8) return true;
  const languages = actor?.system?.traits?.languages;
  const languageValue = String(languages?.value ?? "").trim();
  if (languageValue.length > 0) return true;
  return actorHasFeatureName(actor, /(speak|spellcasting|command|tactics)/i);
}

function getAutoInventoryCrBand(crValue = 0) {
  const cr = Math.max(0, Number(crValue) || 0);
  if (cr <= 1) return "cr-0-1";
  if (cr <= 4) return "cr-2-4";
  if (cr <= 8) return "cr-5-8";
  if (cr <= 12) return "cr-9-12";
  return "cr-13+";
}

function getAutoInventoryChallengeFromCr(crValue = 0) {
  const cr = Math.max(0, Number(crValue) || 0);
  if (cr <= 4) return "low";
  if (cr <= 10) return "mid";
  if (cr <= 16) return "high";
  return "epic";
}

function shiftAutoInventoryCrBand(crBand = "cr-0-1", shift = 0) {
  const current = String(crBand ?? "cr-0-1").trim();
  const currentIndex = UNLINKED_TOKEN_AUTO_INV_BAND_ORDER.indexOf(current);
  const baseIndex = currentIndex >= 0 ? currentIndex : 0;
  const delta = Math.max(-2, Math.min(2, Math.floor(Number(shift) || 0)));
  const targetIndex = Math.max(0, Math.min(UNLINKED_TOKEN_AUTO_INV_BAND_ORDER.length - 1, baseIndex + delta));
  return UNLINKED_TOKEN_AUTO_INV_BAND_ORDER[targetIndex] ?? "cr-0-1";
}

function rollChance(probability = 0) {
  const chance = Math.max(0, Math.min(1, Number(probability) || 0));
  return Math.random() < chance;
}

function autoInventoryPercentSettingToScale(value, fallback = 100) {
  const resolved = Number.isFinite(Number(value)) ? Number(value) : Number(fallback);
  return Math.max(0, Math.min(3, resolved / 100));
}

function scaleAutoInventoryChance(baseChance, scalarPercent = 100) {
  const base = Math.max(0, Math.min(1, Number(baseChance) || 0));
  const scale = autoInventoryPercentSettingToScale(scalarPercent, 100);
  return Math.max(0, Math.min(1, base * scale));
}

function rollIntRange(min, max) {
  const low = Math.ceil(Math.min(min, max));
  const high = Math.floor(Math.max(min, max));
  if (low === high) return low;
  return Math.floor(Math.random() * (high - low + 1)) + low;
}

function pickWeightedEntryName(entries = []) {
  if (!Array.isArray(entries) || entries.length === 0) return "";
  const pool = entries
    .map((entry) => ({
      name: String(entry?.name ?? "").trim(),
      weight: Math.max(0, Number(entry?.weight ?? 0) || 0)
    }))
    .filter((entry) => entry.name.length > 0 && entry.weight > 0);
  if (pool.length === 0) return "";
  const totalWeight = pool.reduce((sum, entry) => sum + entry.weight, 0);
  if (totalWeight <= 0) return pool[0].name;
  let cursor = Math.random() * totalWeight;
  for (const row of pool) {
    cursor -= row.weight;
    if (cursor <= 0) return row.name;
  }
  return pool[pool.length - 1]?.name ?? "";
}

function getDefaultAutoInventoryPackId() {
  const packs = getAllCompendiumPacks();
  const dnd5eItems = packs.find((pack) => {
    const id = String(pack?.collection ?? "").trim();
    const documentName = String(pack?.documentName ?? pack?.metadata?.type ?? "").trim().toLowerCase();
    return documentName === "item" && id === "dnd5e.items";
  });
  if (dnd5eItems) return "dnd5e.items";

  const fallback = packs.find((pack) => String(pack?.documentName ?? pack?.metadata?.type ?? "").trim().toLowerCase() === "item");
  return String(fallback?.collection ?? "").trim();
}

function resolveAutoInventoryPackId(packIdValue) {
  const requested = String(packIdValue ?? "").trim();
  if (requested && game.packs?.get(requested)) return requested;
  const fallback = getDefaultAutoInventoryPackId();
  return fallback || requested;
}

function getAutoInventorySettingsSnapshot() {
  return {
    enabled: Boolean(game.settings.get(MODULE_ID, SETTINGS.AUTO_INV_ENABLED) ?? true),
    currencyEnabled: Boolean(game.settings.get(MODULE_ID, SETTINGS.AUTO_INV_CURRENCY_ENABLED) ?? true),
    weaponPackId: resolveAutoInventoryPackId(game.settings.get(MODULE_ID, SETTINGS.AUTO_INV_WEAPON_PACK)),
    armorPackId: resolveAutoInventoryPackId(game.settings.get(MODULE_ID, SETTINGS.AUTO_INV_ARMOR_PACK)),
    gearPackId: resolveAutoInventoryPackId(game.settings.get(MODULE_ID, SETTINGS.AUTO_INV_GEAR_PACK)),
    consumablesPackId: resolveAutoInventoryPackId(game.settings.get(MODULE_ID, SETTINGS.AUTO_INV_CONSUMABLES_PACK)),
    itemChanceScalar: Number(game.settings.get(MODULE_ID, SETTINGS.AUTO_INV_ITEM_CHANCE_SCALAR) ?? AUTO_INV_DEFAULT_ITEM_CHANCE_SCALAR),
    consumableChanceScalar: Number(game.settings.get(MODULE_ID, SETTINGS.AUTO_INV_CONSUMABLE_CHANCE_SCALAR) ?? AUTO_INV_DEFAULT_CONSUMABLE_CHANCE_SCALAR),
    currencyScalar: Number(game.settings.get(MODULE_ID, SETTINGS.AUTO_INV_CURRENCY_SCALAR) ?? AUTO_INV_DEFAULT_CURRENCY_SCALAR),
    qualityShift: Math.max(-2, Math.min(2, Math.floor(Number(game.settings.get(MODULE_ID, SETTINGS.AUTO_INV_QUALITY_SHIFT) ?? AUTO_INV_DEFAULT_QUALITY_SHIFT) || 0)))
  };
}

function isAutoInventoryArmorIndexRow(row) {
  const type = String(row?.type ?? "").trim().toLowerCase();
  if (type !== "equipment") return false;
  const subtype = String(row?.subtype ?? "").trim().toLowerCase();
  if (["light", "medium", "heavy", "shield"].includes(subtype)) return true;
  const name = normalizeAutoInventoryName(row?.name ?? "");
  return name.includes("armor") || name.includes("mail") || name.includes("plate") || name.includes("shield");
}

function matchesAutoInventoryCategory(row, category = "gear") {
  const normalizedCategory = String(category ?? "gear").trim().toLowerCase();
  const type = String(row?.type ?? "").trim().toLowerCase();
  if (normalizedCategory === "weapon") return type === "weapon";
  if (normalizedCategory === "armor") return isAutoInventoryArmorIndexRow(row);
  if (normalizedCategory === "consumable") return type === "consumable";
  if (normalizedCategory === "gear") {
    if (type === "weapon" || type === "spell") return false;
    if (isAutoInventoryArmorIndexRow(row)) return false;
    return UNLINKED_TOKEN_AUTO_LOOT_ITEM_TYPES.has(type);
  }
  return true;
}

async function getAutoInventoryPackIndexRows(packId) {
  const id = String(packId ?? "").trim();
  if (!id) return [];
  if (autoInventoryPackIndexCache.has(id)) return autoInventoryPackIndexCache.get(id) ?? [];

  const pack = game.packs?.get(id);
  if (!pack) return [];
  try {
    const index = await pack.getIndex({ fields: ["name", "type", "system.type.value"] });
    const rows = getCollectionValues(index)
      .map((entry) => Array.isArray(entry) ? entry[1] : entry)
      .map((entry) => {
        const rowId = String(entry?._id ?? entry?.id ?? "").trim();
        const rowName = String(entry?.name ?? "").trim();
        if (!rowId || !rowName) return null;
        return {
          id: rowId,
          name: rowName,
          type: String(entry?.type ?? "").trim().toLowerCase(),
          subtype: String(foundry.utils.getProperty(entry, "system.type.value") ?? "").trim().toLowerCase(),
          search: normalizeAutoInventoryName(rowName)
        };
      })
      .filter(Boolean);
    autoInventoryPackIndexCache.set(id, rows);
    return rows;
  } catch (error) {
    console.warn(`${MODULE_ID}: failed to read auto-inventory pack index`, { packId: id, error });
    return [];
  }
}

function findAutoInventoryIndexRowByName(indexRows = [], targetName = "", category = "gear") {
  const needle = normalizeAutoInventoryName(targetName);
  if (!needle) return null;
  const categoryRows = (Array.isArray(indexRows) ? indexRows : []).filter((row) => matchesAutoInventoryCategory(row, category));
  const needsEnhancedItem = /\+\s*[123]/i.test(String(targetName ?? ""));
  const nonEnhancedRows = categoryRows.filter((row) => !/\+\s*[123]/i.test(String(row?.name ?? "")));
  const rows = !needsEnhancedItem && nonEnhancedRows.length > 0 ? nonEnhancedRows : categoryRows;
  const exact = rows.find((row) => row.search === needle);
  if (exact) return exact;

  const needleTokens = needle.split(" ").filter(Boolean);
  const startsWith = rows.find((row) => row.search.startsWith(needle));
  if (startsWith) return startsWith;
  const containsTokens = rows.find((row) => needleTokens.every((token) => row.search.includes(token)));
  if (containsTokens) return containsTokens;
  return rows.find((row) => row.search.includes(needle)) ?? null;
}

async function resolveAutoInventoryItemData(packId, itemName, category = "gear") {
  const id = String(packId ?? "").trim();
  if (!id) return null;
  const pack = game.packs?.get(id);
  if (!pack) return null;
  const rows = await getAutoInventoryPackIndexRows(id);
  const match = findAutoInventoryIndexRowByName(rows, itemName, category);
  if (!match) return null;
  try {
    const document = await pack.getDocument(match.id);
    if (!document || document.documentName !== "Item") return null;
    const data = document.toObject();
    if (data && typeof data === "object" && Object.prototype.hasOwnProperty.call(data, "_id")) delete data._id;
    return data;
  } catch (error) {
    console.warn(`${MODULE_ID}: failed loading auto-inventory item`, { packId: id, itemName, error });
    return null;
  }
}

function setAutoInventoryItemQuantity(itemData, quantity = 1) {
  const qty = Math.max(1, Math.floor(Number(quantity) || 1));
  if (!itemData || typeof itemData !== "object") return itemData;
  if (!itemData.system || typeof itemData.system !== "object") itemData.system = {};
  const quantityNode = itemData.system.quantity;
  if (quantityNode && typeof quantityNode === "object") {
    quantityNode.value = qty;
  } else {
    itemData.system.quantity = qty;
  }
  return itemData;
}

async function resolveTokenActorForAutoInventory(tokenDoc) {
  if (!tokenDoc) return null;
  const sleep = foundry.utils?.sleep
    ? (ms) => foundry.utils.sleep(ms)
    : (ms) => new Promise((resolve) => setTimeout(resolve, ms));
  for (let attempt = 0; attempt < 10; attempt += 1) {
    const actor = tokenDoc?.actor ?? tokenDoc?.object?.actor ?? tokenDoc?.getActor?.();
    if (actor?.documentName === "Actor") return actor;
    if (attempt < 9) await sleep(75);
  }
  return null;
}

function isPrimaryActiveGmClient() {
  const activeGms = (game.users ?? [])
    .filter((user) => Boolean(user?.active) && Boolean(user?.isGM))
    .sort((left, right) => String(left?.id ?? "").localeCompare(String(right?.id ?? "")));
  if (activeGms.length === 0) return Boolean(canAccessAllPlayerOps());
  return String(activeGms[0]?.id ?? "") === String(game.user?.id ?? "");
}

function isPrimaryActiveGmForAutoInventory() {
  return isPrimaryActiveGmClient();
}

function actorHasUsableInventory(actor) {
  if (!actor?.items) return false;
  return actor.items.some((item) => UNLINKED_TOKEN_AUTO_LOOT_ITEM_TYPES.has(String(item?.type ?? "").trim().toLowerCase()));
}

function shouldAutoInventoryApplyForCreature(actor, creatureType, role) {
  const type = String(creatureType ?? "unknown");
  if (["construct", "elemental", "ooze"].includes(type)) return false;
  if (type === "beast") return false;
  if (type === "undead") {
    if (!isLikelyIntelligentCreature(actor) && role === "none") return false;
  }
  return true;
}

function buildAutoInventoryTypeWeights(creatureType, role) {
  const type = String(creatureType ?? "unknown").trim().toLowerCase();
  const roleValue = String(role ?? "none").trim().toLowerCase();
  const base = {
    ...(UNLINKED_TOKEN_AUTO_LOOT_TYPE_WEIGHTS.default ?? {})
  };
  const creatureWeights = UNLINKED_TOKEN_AUTO_LOOT_TYPE_WEIGHTS[type] ?? {};
  const merged = { ...base, ...creatureWeights };
  if (roleValue === "caster") {
    merged.weapon = Math.max(0, Number(merged.weapon ?? 1) * 0.72);
    merged.consumable = Math.max(0, Number(merged.consumable ?? 1) * 1.35);
    merged.tool = Math.max(0, Number(merged.tool ?? 1) * 1.2);
  } else if (roleValue === "scout") {
    merged.weapon = Math.max(0, Number(merged.weapon ?? 1) * 1.1);
    merged.armor = Math.max(0, Number(merged.armor ?? 1) * 0.75);
    merged.consumable = Math.max(0, Number(merged.consumable ?? 1) * 1.2);
  } else if (roleValue === "brute") {
    merged.weapon = Math.max(0, Number(merged.weapon ?? 1) * 1.2);
    merged.armor = Math.max(0, Number(merged.armor ?? 1) * 1.25);
    merged.consumable = Math.max(0, Number(merged.consumable ?? 1) * 0.8);
  }
  merged.default = Math.max(0.01, Number(merged.default ?? 1) || 1);
  return merged;
}

function getLootBuilderItemTypeWeight(draft = {}, itemType = "") {
  const normalizedType = String(itemType ?? "").trim().toLowerCase();
  const map = (draft?.itemTypeWeights && typeof draft.itemTypeWeights === "object" && !Array.isArray(draft.itemTypeWeights))
    ? draft.itemTypeWeights
    : null;
  if (!map || !normalizedType) return 1;
  const raw = Number(map[normalizedType] ?? map.default ?? 1);
  if (!Number.isFinite(raw)) return 1;
  return Math.max(0, raw);
}

function buildAutoInventoryCurrencyBundle(crBand = "cr-0-1", scalarPercent = 100) {
  const table = {
    "cr-0-1": () => ({ gp: rollIntRange(0, 4), sp: rollIntRange(1, 10), cp: rollIntRange(0, 20) }),
    "cr-2-4": () => ({ gp: rollIntRange(2, 12), sp: rollIntRange(2, 18), cp: rollIntRange(0, 15) }),
    "cr-5-8": () => ({ gp: rollIntRange(8, 35), sp: rollIntRange(0, 20), cp: rollIntRange(0, 10) }),
    "cr-9-12": () => ({ pp: rollIntRange(0, 4), gp: rollIntRange(18, 65), sp: rollIntRange(0, 12), cp: 0 }),
    "cr-13+": () => ({ pp: rollIntRange(2, 12), gp: rollIntRange(45, 180), sp: rollIntRange(0, 10), cp: 0 })
  };
  const rolled = (table[crBand] ?? table["cr-0-1"])();
  const scale = autoInventoryPercentSettingToScale(scalarPercent, AUTO_INV_DEFAULT_CURRENCY_SCALAR);
  const apply = (value) => Math.max(0, Math.floor((Number(value) || 0) * scale));
  return {
    pp: apply(rolled.pp),
    gp: apply(rolled.gp),
    sp: apply(rolled.sp),
    cp: apply(rolled.cp)
  };
}

function buildAutoInventoryDraftForActor(actor, crValue, creatureType, role) {
  const cr = Math.max(0, Number(crValue) || 0);
  const challenge = getAutoInventoryChallengeFromCr(cr);
  const scale = cr >= 13 ? "major" : cr >= 6 ? "medium" : "small";
  const type = String(creatureType ?? "unknown").trim().toLowerCase();
  const roleValue = String(role ?? "none").trim().toLowerCase();

  let profile = "standard";
  if (["beast", "ooze", "plant", "construct", "elemental"].includes(type)) profile = "poor";
  if (["dragon", "fiend", "celestial"].includes(type) || roleValue === "caster") profile = "well";

  let itemScalar = cr >= 13 ? 135 : cr >= 9 ? 120 : cr >= 5 ? 105 : 88;
  let valueBudgetScalar = cr >= 13 ? 145 : cr >= 9 ? 120 : cr >= 5 ? 102 : 78;
  let valueStrictness = cr <= 1 ? 255 : cr <= 4 ? 235 : cr <= 8 ? 205 : cr <= 12 ? 180 : 150;

  if (roleValue === "caster") {
    itemScalar += 6;
    valueBudgetScalar += 8;
    valueStrictness -= 10;
  }
  if (roleValue === "brute") {
    itemScalar += 6;
    valueBudgetScalar += 4;
  }
  if (["beast", "ooze", "plant", "elemental", "construct"].includes(type)) {
    itemScalar = Math.max(60, itemScalar - 25);
    valueBudgetScalar = Math.max(45, valueBudgetScalar - 22);
    valueStrictness = Math.min(300, valueStrictness + 22);
  }

  const baseMaxItemValue = (() => {
    if (cr <= 0.125) return 30;
    if (cr <= 0.5) return 55;
    if (cr <= 1) return 90;
    if (cr <= 2) return 160;
    if (cr <= 4) return 280;
    if (cr <= 6) return 500;
    if (cr <= 8) return 750;
    if (cr <= 10) return 1000;
    if (cr <= 12) return 1600;
    if (cr <= 16) return 3000;
    return 8500;
  })();

  const maxItemValueGp = (() => {
    if (["dragon", "fiend", "celestial"].includes(type)) return Math.floor(baseMaxItemValue * 1.2);
    if (["beast", "ooze", "plant", "construct", "elemental"].includes(type)) return Math.floor(baseMaxItemValue * 0.65);
    return baseMaxItemValue;
  })();

  return {
    mode: "encounter",
    profile,
    challenge,
    scale,
    creatures: 1,
    actorCount: 1,
    currencyScalar: 100,
    itemScalar: Math.max(25, Math.min(300, Math.floor(itemScalar))),
    tableScalar: 25,
    valueBudgetScalar: Math.max(25, Math.min(300, Math.floor(valueBudgetScalar))),
    valueStrictness: Math.max(50, Math.min(300, Math.floor(valueStrictness))),
    maxItemValueGp: Math.max(0, Math.min(LOOT_PREVIEW_MAX_ITEM_VALUE_GP_LIMIT, Math.floor(maxItemValueGp))),
    itemTypeWeights: buildAutoInventoryTypeWeights(creatureType, role)
  };
}

async function buildAutoInventorySelectionPlan(actor, settings, context) {
  const plan = [];
  const existingNames = new Set((actor.items ?? []).map((item) => normalizeAutoInventoryName(item?.name ?? "")).filter(Boolean));
  const selectedNames = new Set();
  const crBand = context.crBand;
  const qualityBand = shiftAutoInventoryCrBand(crBand, settings?.qualityShift ?? AUTO_INV_DEFAULT_QUALITY_SHIFT);
  const creatureType = context.creatureType;
  const role = context.role;
  const itemChanceScalar = Number(settings?.itemChanceScalar ?? AUTO_INV_DEFAULT_ITEM_CHANCE_SCALAR);
  const consumableChanceScalar = Number(settings?.consumableChanceScalar ?? AUTO_INV_DEFAULT_CONSUMABLE_CHANCE_SCALAR);
  const rollItemChance = (baseChance) => rollChance(scaleAutoInventoryChance(baseChance, itemChanceScalar));
  const rollConsumableChance = (baseChance) => rollChance(scaleAutoInventoryChance(baseChance, consumableChanceScalar));
  const isHumanoidLike = ["humanoid", "fey", "giant", "fiend", "celestial", "monstrosity"].includes(creatureType)
    || (creatureType === "undead" && context.intelligent);

  const addPick = (packId, category, weightedChoices, quantity = 1) => {
    const targetName = pickWeightedEntryName(weightedChoices);
    if (!targetName) return;
    const normalized = normalizeAutoInventoryName(targetName);
    if (!normalized || existingNames.has(normalized) || selectedNames.has(normalized)) return;
    selectedNames.add(normalized);
    plan.push({ packId, category, name: targetName, quantity: Math.max(1, Math.floor(Number(quantity) || 1)) });
  };

  if (isHumanoidLike) {
    addPick(settings.weaponPackId, "weapon", UNLINKED_TOKEN_AUTO_INV_CURATED.weapon[qualityBand] ?? []);

    const armorChanceByBand = {
      "cr-0-1": role === "caster" ? 0.25 : 0.45,
      "cr-2-4": role === "caster" ? 0.42 : 0.62,
      "cr-5-8": role === "caster" ? 0.56 : 0.76,
      "cr-9-12": role === "caster" ? 0.62 : 0.82,
      "cr-13+": role === "caster" ? 0.68 : 0.86
    };
    if (rollItemChance(Number(armorChanceByBand[crBand] ?? 0.6))) {
      addPick(settings.armorPackId, "armor", UNLINKED_TOKEN_AUTO_INV_CURATED.armor[qualityBand] ?? []);
    }

    if (["cr-5-8", "cr-9-12", "cr-13+"].includes(crBand) && (role === "martial" || role === "brute") && rollItemChance(0.35)) {
      addPick(settings.armorPackId, "armor", [{ name: "Shield", weight: 100 }], 1);
    }

    if (rollItemChance(0.65)) addPick(settings.gearPackId, "gear", [{ name: "Rations", weight: 100 }], rollIntRange(1, 3));
    if (rollItemChance(0.7)) addPick(settings.gearPackId, "gear", [{ name: "Waterskin", weight: 100 }], 1);
    if (rollItemChance(0.6)) addPick(settings.gearPackId, "gear", [{ name: "Torch", weight: 100 }], rollIntRange(1, 4));
    if (rollItemChance(0.35)) addPick(settings.gearPackId, "gear", [{ name: "Lantern, Hooded", weight: 100 }], 1);
    if (rollItemChance(0.45)) addPick(settings.gearPackId, "gear", [{ name: "Rope, Hempen (50 feet)", weight: 100 }], 1);

    const healChance = Number(UNLINKED_TOKEN_AUTO_INV_HEALING_CHANCE_BY_BAND[crBand] ?? 0.1);
    if (rollConsumableChance(healChance)) {
      addPick(settings.consumablesPackId, "consumable", UNLINKED_TOKEN_AUTO_INV_CURATED.healingByBand[qualityBand] ?? [], 1);
    }

    const utilityChance = crBand === "cr-0-1" ? 0.05 : crBand === "cr-2-4" ? 0.1 : crBand === "cr-5-8" ? 0.18 : 0.24;
    if (rollConsumableChance(utilityChance)) {
      addPick(settings.consumablesPackId, "consumable", UNLINKED_TOKEN_AUTO_INV_CURATED.utilityConsumables ?? [], 1);
    }
  } else if (creatureType === "undead" && context.intelligent) {
    if (rollItemChance(0.55)) addPick(settings.weaponPackId, "weapon", UNLINKED_TOKEN_AUTO_INV_CURATED.weapon[qualityBand] ?? []);
    if (rollItemChance(0.25)) addPick(settings.armorPackId, "armor", UNLINKED_TOKEN_AUTO_INV_CURATED.armor[qualityBand] ?? []);
  }

  return plan;
}

async function resolveAutoInventoryPlanToItemData(plan = []) {
  const merged = new Map();
  for (const entry of Array.isArray(plan) ? plan : []) {
    const packId = String(entry?.packId ?? "").trim();
    const category = String(entry?.category ?? "gear").trim().toLowerCase();
    const name = String(entry?.name ?? "").trim();
    const quantity = Math.max(1, Math.floor(Number(entry?.quantity ?? 1) || 1));
    if (!packId || !name) continue;
    const key = `${packId}::${normalizeAutoInventoryName(name)}::${category}`;
    if (!merged.has(key)) merged.set(key, { packId, category, name, quantity });
    else merged.get(key).quantity += quantity;
  }

  const itemDataRows = [];
  for (const entry of merged.values()) {
    const itemData = await resolveAutoInventoryItemData(entry.packId, entry.name, entry.category);
    if (!itemData) continue;
    setAutoInventoryItemQuantity(itemData, entry.quantity);
    itemDataRows.push(itemData);
  }
  return itemDataRows;
}

async function applyAutoInventoryToUnlinkedToken(tokenDoc, options = {}, userId = null) {
  if (!canAccessAllPlayerOps()) return;
  if (!isPrimaryActiveGmForAutoInventory()) return;
  const settings = getAutoInventorySettingsSnapshot();
  if (!settings.enabled) return;

  const actorLinkState = tokenDoc?.actorLink ?? tokenDoc?.document?.actorLink ?? tokenDoc?._source?.actorLink;
  const isLinkedToken = actorLinkState === true;
  if (isLinkedToken) return;
  const alreadyApplied = Boolean(tokenDoc?.getFlag?.(MODULE_ID, "autoInvApplied"));
  if (alreadyApplied) return;

  const actor = await resolveTokenActorForAutoInventory(tokenDoc);
  if (!actor || actor.documentName !== "Actor" || !actor.isToken) {
    logAutoInventoryDebug("skipped: synthetic token actor not available", {
      tokenId: tokenDoc?.id,
      actorId: tokenDoc?.actorId
    });
    return;
  }
  if (String(actor.type ?? "").trim().toLowerCase() !== "npc") {
    await tokenDoc.setFlag(MODULE_ID, "autoInvApplied", true);
    return;
  }

  if (actorHasUsableInventory(actor)) {
    logAutoInventoryDebug("skipped: token actor already has usable inventory", { actor: actor.name, tokenId: tokenDoc.id });
    await tokenDoc.setFlag(MODULE_ID, "autoInvApplied", true);
    return;
  }

  const crValue = getActorCrForAutoInventory(actor);
  const creatureType = getActorCreatureTypeForAutoInventory(actor);
  const role = inferRole(actor);
  const intelligent = isLikelyIntelligentCreature(actor);
  const shouldApply = shouldAutoInventoryApplyForCreature(actor, creatureType, role);

  if (!shouldApply) {
    logAutoInventoryDebug("skipped: creature type does not receive auto inventory", {
      actor: actor.name,
      creatureType,
      role,
      crValue
    });
    await tokenDoc.setFlag(MODULE_ID, "autoInvApplied", true);
    return;
  }

  const crBand = getAutoInventoryCrBand(crValue);
  const draft = buildAutoInventoryDraftForActor(actor, crValue, creatureType, role);
  const plan = await buildAutoInventorySelectionPlan(actor, settings, {
    crValue,
    crBand,
    creatureType,
    role,
    intelligent,
    draft
  });
  const itemData = await resolveAutoInventoryPlanToItemData(plan);

  if (itemData.length > 0) {
    try {
      await actor.createEmbeddedDocuments("Item", itemData);
    } catch (error) {
      console.warn(`${MODULE_ID}: failed applying auto inventory to token actor`, {
        actor: actor.name,
        tokenId: tokenDoc.id,
        error
      });
    }
  }

  if (settings.currencyEnabled && (creatureType === "humanoid" || (creatureType === "undead" && intelligent))) {
    try {
      const currency = buildAutoInventoryCurrencyBundle(crBand, settings.currencyScalar);
      await awardCurrencyBundleToActor(actor, currency);
    } catch (error) {
      console.warn(`${MODULE_ID}: failed applying auto inventory currency`, {
        actor: actor.name,
        tokenId: tokenDoc.id,
        error
      });
    }
  }

  await tokenDoc.setFlag(MODULE_ID, "autoInvApplied", true);
  logAutoInventoryDebug("auto inventory applied", {
    actor: actor.name,
    tokenId: tokenDoc.id,
    crValue,
    crBand,
    creatureType,
    role,
    itemsApplied: itemData.map((entry) => entry.name).filter(Boolean)
  });
}

function normalizeLootRarity(value) {
  const raw = String(value ?? "").trim().toLowerCase();
  if (!raw) return "";
  if (["artifact", "artifacts", "artefact", "artefacts", "superrare", "super-rare", "super rare"].includes(raw)) return "very-rare";
  if (["veryrare", "very rare", "very_rare", "very-rare"].includes(raw)) return "very-rare";
  if (["legend", "legendary"].includes(raw)) return "legendary";
  if (["rare"].includes(raw)) return "rare";
  if (["uncommon"].includes(raw)) return "uncommon";
  if (["common"].includes(raw)) return "common";
  return "";
}

function getLootRarityFromData(data = {}) {
  const candidates = [
    data?.rarity,
    data?.system?.rarity,
    data?.system?.details?.rarity,
    data?.system?.traits?.rarity,
    data?.system?.properties?.rarity
  ];
  for (const candidate of candidates) {
    if (candidate === null || candidate === undefined) continue;
    if (typeof candidate === "object") {
      const nested = normalizeLootRarity(candidate.value ?? candidate.label ?? candidate.name ?? "");
      if (nested) return nested;
      continue;
    }
    const normalized = normalizeLootRarity(candidate);
    if (normalized) return normalized;
  }
  return "";
}

function getLootKeywordsFromData(data = {}) {
  const keywordCandidates = [
    data?.flags?.[MODULE_ID]?.keywords,
    data?.flags?.["party-operations"]?.keywords
  ];
  for (const candidate of keywordCandidates) {
    const normalized = normalizeLootKeywordTagList(candidate ?? []);
    if (normalized.length > 0) return normalized;
  }
  return [];
}

function getPartyOperationsItemFlags(data = {}) {
  const primary = data?.flags?.[MODULE_ID];
  if (primary && typeof primary === "object") return primary;
  const legacy = data?.flags?.["party-operations"];
  if (legacy && typeof legacy === "object") return legacy;
  return {};
}

function getLootItemFolderProfileFromData(data = {}) {
  const poFlags = getPartyOperationsItemFlags(data);
  const rawFolder = poFlags?.folder;
  if (!rawFolder || typeof rawFolder !== "object") return null;

  const path = (Array.isArray(rawFolder?.path) ? rawFolder.path : [])
    .map((entry, index) => {
      const key = String(entry?.key ?? "").trim().toLowerCase();
      const label = String(entry?.label ?? "").trim();
      const sort = Number(entry?.sort ?? ((index + 1) * 1000)) || ((index + 1) * 1000);
      if (!key || !label) return null;
      return { key, label, sort };
    })
    .filter(Boolean);

  if (path.length <= 0) return null;
  return {
    schema: String(rawFolder?.schema ?? "").trim().toLowerCase(),
    familyKey: String(rawFolder?.familyKey ?? path[0]?.key ?? "").trim().toLowerCase(),
    familyLabel: String(rawFolder?.familyLabel ?? path[0]?.label ?? "").trim(),
    sectionKey: String(rawFolder?.sectionKey ?? path[1]?.key ?? "").trim().toLowerCase(),
    sectionLabel: String(rawFolder?.sectionLabel ?? path[1]?.label ?? "").trim(),
    leafKey: String(rawFolder?.leafKey ?? path[2]?.key ?? "").trim().toLowerCase(),
    leafLabel: String(rawFolder?.leafLabel ?? path[2]?.label ?? "").trim(),
    path,
    pathKey: path.map((entry) => String(entry?.key ?? "").trim().toLowerCase()).filter(Boolean).join("/")
  };
}

function formatPartyOperationsWordLabel(value = "", fallback = "Unspecified") {
  const normalized = String(value ?? "").trim().toLowerCase();
  if (!normalized) return fallback;
  return normalized
    .split(/[-_.:/]+/)
    .filter(Boolean)
    .map((entry) => entry.charAt(0).toUpperCase() + entry.slice(1))
    .join(" ");
}

function formatPartyOperationsTierLabel(value = "") {
  const normalized = String(value ?? "").trim().toLowerCase();
  const tierMatch = normalized.match(/^tier\.t(\d+)$/);
  if (tierMatch) return `Tier ${tierMatch[1]}`;
  return formatPartyOperationsWordLabel(normalized, "No Tier");
}

function formatPartyOperationsValueBandLabel(value = "") {
  const normalized = String(value ?? "").trim().toLowerCase();
  const valueMatch = normalized.match(/^value\.v(\d+)$/);
  if (valueMatch) return `Value V${valueMatch[1]}`;
  return formatPartyOperationsWordLabel(normalized, "No Value Band");
}

function formatPartyOperationsPriceDenominationLabel(value = "") {
  const normalized = String(value ?? "").trim().toLowerCase();
  if (!normalized) return "Any Coin";
  return normalized.toUpperCase();
}

function formatPartyOperationsTagSchemaLabel(value = "") {
  const normalized = String(value ?? "").trim().toLowerCase();
  if (!normalized) return "Legacy Tags";
  if (normalized === "po-loot-v3") return "PO Loot V3";
  if (normalized === "po-loot-v2") return "PO Loot V2";
  return formatPartyOperationsWordLabel(normalized, "Legacy Tags");
}

function getLootItemMerchantCategoriesFromData(data = {}) {
  const poFlags = getPartyOperationsItemFlags(data);
  const explicit = Array.isArray(poFlags?.merchantCategories)
    ? poFlags.merchantCategories
    : [];
  const categories = explicit
    .map((entry) => String(entry ?? "").trim().toLowerCase())
    .filter(Boolean);
  if (categories.length > 0) return categories;
  return getLootKeywordsFromData(data)
    .filter((entry) => String(entry ?? "").trim().toLowerCase().startsWith("merchant."))
    .map((entry) => String(entry).trim().toLowerCase().slice("merchant.".length))
    .filter(Boolean);
}

function getLootItemTierFromData(data = {}) {
  const poFlags = getPartyOperationsItemFlags(data);
  const explicit = String(poFlags?.tier ?? "").trim().toLowerCase();
  if (explicit) return explicit;
  return getLootKeywordsFromData(data).find((entry) => String(entry ?? "").trim().toLowerCase().startsWith("tier.")) ?? "";
}

function getLootItemValueBandFromData(data = {}) {
  const poFlags = getPartyOperationsItemFlags(data);
  const explicit = String(poFlags?.valueBand ?? "").trim().toLowerCase();
  if (explicit) return explicit;
  return getLootKeywordsFromData(data).find((entry) => String(entry ?? "").trim().toLowerCase().startsWith("value.")) ?? "";
}

function getLootItemPriceDenominationFromData(data = {}) {
  const poFlags = getPartyOperationsItemFlags(data);
  const explicit = String(poFlags?.priceDenomination ?? "").trim().toLowerCase();
  if (explicit) return explicit;
  const keyword = getLootKeywordsFromData(data).find((entry) => String(entry ?? "").trim().toLowerCase().startsWith("price."));
  return keyword ? String(keyword).trim().toLowerCase().slice("price.".length) : "";
}

function getLootItemTagSchemaFromData(data = {}) {
  const poFlags = getPartyOperationsItemFlags(data);
  return String(poFlags?.tagSchema ?? "").trim().toLowerCase();
}

function normalizeLootVariableTreasureKind(value = "") {
  const normalized = String(value ?? "").trim().toLowerCase();
  if (normalized === "gem" || normalized === "gems" || normalized === "gemstone" || normalized === "gemstones") return "gem";
  if (normalized === "art" || normalized === "art-item" || normalized === "art-items" || normalized === "art-object" || normalized === "art-objects") return "art";
  return "";
}

function getLootVariableTreasureKindFromData(data = {}) {
  const explicit = normalizeLootVariableTreasureKind(
    data?.variableTreasureKind
    ?? data?.flags?.[MODULE_ID]?.variableTreasureKind
    ?? data?.flags?.["party-operations"]?.variableTreasureKind
  );
  if (explicit) return explicit;

  const keywords = getLootKeywordsFromData(data);
  if (keywords.some((entry) => {
    const text = String(entry ?? "").trim().toLowerCase();
    return text === "merchant.gem"
      || text === "merchant.gemstone"
      || text === "folder.leaf.gemstones"
      || text.endsWith(".gemstones");
  })) {
    return "gem";
  }
  if (keywords.some((entry) => {
    const text = String(entry ?? "").trim().toLowerCase();
    return text === "merchant.art"
      || text === "merchant.art-object"
      || text === "merchant.art-objects"
      || text === "folder.leaf.art-objects"
      || text.endsWith(".art-objects");
  })) {
    return "art";
  }
  const itemName = String(data?.name ?? "").trim().toLowerCase();
  if (itemName) {
    if (/\b(amber|agate|alexandrite|amethyst|aquamarine|beryl|bloodstone|carnelian|chalcedony|chrysoberyl|chrysoprase|citrine|coral|diamond|emerald|garnet|gem|gemstone|heliotrope|jade|jasper|jet|moonstone|obsidian|onyx|opal|pearl|peridot|quartz|ruby|sapphire|sardonyx|spinel|sunstone|topaz|tourmaline|turquoise|zircon)\b/.test(itemName)) {
      return "gem";
    }
    if (/\b(art|artwork|painting|portrait|tapestry|statue|statuette|idol|vase|chalice|goblet|candelabra|figurine|bust|sculpture|carving)\b/.test(itemName)) {
      return "art";
    }
  }
  return "";
}

function getLootSourceClassFromData(
  data = {},
  fallback = LOOT_SOURCE_CLASSES.GENERATED,
  keywordsOverride = null,
  poFlagsOverride = null
) {
  const poFlags = (poFlagsOverride && typeof poFlagsOverride === "object")
    ? poFlagsOverride
    : getPartyOperationsItemFlags(data);
  const explicit = normalizeLootSourceClass(poFlags?.sourceClass ?? "", "");
  if (explicit) return explicit;
  const keywords = Array.isArray(keywordsOverride)
    ? keywordsOverride
    : getLootKeywordsFromData(data);
  if (keywords.some((entry) => String(entry ?? "").trim().toLowerCase() === "source.party.operations.party.operations.loot.manifest")) {
    return LOOT_SOURCE_CLASSES.CURATED;
  }
  if (keywords.some((entry) => String(entry ?? "").trim().toLowerCase() === "source.curated")) {
    return LOOT_SOURCE_CLASSES.CURATED;
  }
  return normalizeLootSourceClass(fallback, LOOT_SOURCE_CLASSES.GENERATED);
}

function roundLootWeightLb(value = 0) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric) || numeric <= 0) return 0;
  return Number(numeric.toFixed(4));
}

function formatLootWeightLabel(weightLb = 0) {
  const numeric = roundLootWeightLb(weightLb);
  if (numeric <= 0) return "";
  return `${numeric.toLocaleString(undefined, { maximumFractionDigits: 4 })} lb`;
}

function hasLootPreviewEntryWeightAutoScale(entry = {}) {
  const kind = normalizeLootVariableTreasureKind(entry?.variableTreasureKind);
  const baseValueGp = Math.max(0, Number(entry?.baseItemValueGp ?? 0) || 0);
  const baseWeightLb = Math.max(0, Number(entry?.baseItemWeightLb ?? 0) || 0);
  return Boolean(kind && baseValueGp > 0 && baseWeightLb > 0);
}

function calculateLootPreviewScaledWeight(entry = {}, totalValueGp = 0, fallbackWeightLb = 0) {
  if (!hasLootPreviewEntryWeightAutoScale(entry)) {
    return roundLootWeightLb(Math.max(0, Number(fallbackWeightLb ?? entry?.itemWeightLb ?? 0) || 0));
  }
  const baseValueGp = Math.max(0.0001, Number(entry?.baseItemValueGp ?? 0) || 0.0001);
  const baseWeightLb = Math.max(0, Number(entry?.baseItemWeightLb ?? 0) || 0);
  const scaledValueGp = Math.max(0, Number(totalValueGp ?? entry?.itemValueGp ?? 0) || 0);
  return roundLootWeightLb(baseWeightLb * (scaledValueGp / baseValueGp));
}

function buildLootVariableTreasurePools(entries = []) {
  return buildVariableTreasureRollPools((Array.isArray(entries) ? entries : []).map((entry) => ({
    ...entry,
    variableTreasureKind: normalizeLootVariableTreasureKind(entry?.variableTreasureKind),
    intrinsicItemValueGp: Math.max(0, Number(
      entry?.intrinsicItemValueGp
      ?? entry?.baseItemValueGp
      ?? entry?.itemValueGp
      ?? 0
    ) || 0),
    intrinsicItemWeightLb: roundLootWeightLb(Math.max(0, Number(
      entry?.intrinsicItemWeightLb
      ?? entry?.baseItemWeightLb
      ?? entry?.itemWeightLb
      ?? 0
    ) || 0))
  })));
}

function estimateLootVariableTreasureBudgetOutcome(entry = {}, pools = {}) {
  const kind = normalizeLootVariableTreasureKind(entry?.variableTreasureKind);
  if (kind !== "gem" && kind !== "art") return null;
  return estimateVariableTreasureOutcome({
    ...entry,
    variableTreasureKind: kind,
    intrinsicItemValueGp: Math.max(0, Number(
      entry?.intrinsicItemValueGp
      ?? entry?.baseItemValueGp
      ?? entry?.itemValueGp
      ?? 0
    ) || 0),
    intrinsicItemWeightLb: roundLootWeightLb(Math.max(0, Number(
      entry?.intrinsicItemWeightLb
      ?? entry?.baseItemWeightLb
      ?? entry?.itemWeightLb
      ?? 0
    ) || 0))
  }, pools);
}

function rollLootVariableTreasureSelection(entry = {}, pools = {}, randomFn = Math.random) {
  const kind = normalizeLootVariableTreasureKind(entry?.variableTreasureKind);
  if (kind !== "gem" && kind !== "art") return null;
  return rollVariableTreasureOutcome({
    ...entry,
    variableTreasureKind: kind,
    intrinsicItemValueGp: Math.max(0, Number(
      entry?.intrinsicItemValueGp
      ?? entry?.baseItemValueGp
      ?? entry?.itemValueGp
      ?? 0
    ) || 0),
    intrinsicItemWeightLb: roundLootWeightLb(Math.max(0, Number(
      entry?.intrinsicItemWeightLb
      ?? entry?.baseItemWeightLb
      ?? entry?.itemWeightLb
      ?? 0
    ) || 0))
  }, pools, randomFn);
}

function isLootValuableEntry(entry = {}) {
  const kind = normalizeLootVariableTreasureKind(entry?.variableTreasureKind);
  return kind === "gem" || kind === "art";
}

function getLootValuablesBudgetRatio(draft = {}) {
  const mode = String(draft?.mode ?? "horde").trim().toLowerCase();
  if (mode !== "horde") return 0;
  const challenge = String(draft?.challenge ?? "mid").trim().toLowerCase();
  const scale = String(draft?.scale ?? "medium").trim().toLowerCase();
  const profile = String(draft?.profile ?? "standard").trim().toLowerCase();
  const baseByChallenge = {
    low: 0.18,
    mid: 0.24,
    high: 0.32,
    epic: 0.42
  };
  let ratio = Number(baseByChallenge[challenge] ?? baseByChallenge.mid);
  if (scale === "small") ratio -= 0.04;
  else if (scale === "major") ratio += 0.12;
  if (profile === "poor") ratio -= 0.03;
  else if (profile === "well") ratio += 0.03;
  return Math.max(0.08, Math.min(0.65, Number(ratio.toFixed(4))));
}

function getLootValuablesArtAllocationRatio(draft = {}) {
  const mode = String(draft?.mode ?? "horde").trim().toLowerCase();
  if (mode !== "horde") return 0;
  const challenge = String(draft?.challenge ?? "mid").trim().toLowerCase();
  const scale = String(draft?.scale ?? "medium").trim().toLowerCase();
  const profile = String(draft?.profile ?? "standard").trim().toLowerCase();
  const baseByChallenge = {
    low: 0.48,
    mid: 0.56,
    high: 0.62,
    epic: 0.7
  };
  let ratio = Number(baseByChallenge[challenge] ?? baseByChallenge.mid);
  if (scale === "small") ratio -= 0.08;
  else if (scale === "major") ratio += 0.08;
  if (profile === "poor") ratio -= 0.05;
  else if (profile === "well") ratio += 0.04;
  return Math.max(0.25, Math.min(0.85, Number(ratio.toFixed(4))));
}

function getLootSelectionTotalValueGp(entries = []) {
  return Number((Array.isArray(entries) ? entries : []).reduce((sum, entry) => {
    return sum + Math.max(0, Number(entry?.itemValueGp ?? 0) || 0);
  }, 0).toFixed(2));
}

function getRemainingLootBudgetGp(targetBudgetGp = 0, spentValueGp = 0) {
  const safeTargetBudgetGp = Math.max(0, Number(targetBudgetGp) || 0);
  const safeSpentValueGp = Math.max(0, Number(spentValueGp) || 0);
  return Math.max(0, Number((safeTargetBudgetGp - safeSpentValueGp).toFixed(2)));
}

function getLootRemainingSelectionBudgetGp(targetBudgetGp = 0, entries = []) {
  return getRemainingLootBudgetGp(targetBudgetGp, getLootSelectionTotalValueGp(entries));
}

function buildLootCurrencyBudgetContext(budgetContext = {}, selectedValuablesValueGp = 0) {
  const targetCurrencyBudgetGp = Math.max(0, Number(budgetContext?.targetCurrencyBudgetGp ?? 0) || 0);
  return {
    ...budgetContext,
    targetCoinBudgetGp: getRemainingLootBudgetGp(targetCurrencyBudgetGp, selectedValuablesValueGp)
  };
}

function buildLootValuablesLaneTargets(draft = {}, budgetContext = {}, valuablesPool = [], targetCount = 0) {
  const valuablesBudgetGp = Math.max(0, Number(budgetContext?.targetValuablesBudgetGp ?? 0) || 0);
  const safeTargetCount = Math.max(0, Math.floor(Number(targetCount) || 0));
  const artPool = (Array.isArray(valuablesPool) ? valuablesPool : [])
    .filter((entry) => normalizeLootVariableTreasureKind(entry?.variableTreasureKind) === "art");
  const gemPool = (Array.isArray(valuablesPool) ? valuablesPool : [])
    .filter((entry) => normalizeLootVariableTreasureKind(entry?.variableTreasureKind) === "gem");
  if (safeTargetCount <= 0 || valuablesBudgetGp <= 0) {
    return {
      artPool,
      gemPool,
      artCountTarget: 0,
      gemCountTarget: 0,
      artBudgetTargetGp: 0,
      gemBudgetTargetGp: 0
    };
  }

  if (!artPool.length) {
    return {
      artPool,
      gemPool,
      artCountTarget: 0,
      gemCountTarget: safeTargetCount,
      artBudgetTargetGp: 0,
      gemBudgetTargetGp: valuablesBudgetGp
    };
  }

  if (!gemPool.length) {
    return {
      artPool,
      gemPool,
      artCountTarget: safeTargetCount,
      gemCountTarget: 0,
      artBudgetTargetGp: valuablesBudgetGp,
      gemBudgetTargetGp: 0
    };
  }

  const artRatio = getLootValuablesArtAllocationRatio(draft);
  const cheapestArtValueGp = Math.min(...artPool.map((entry) => Math.max(1, Number(entry?.itemValueGp ?? 1) || 1)));
  const artBudgetTargetGp = Math.max(cheapestArtValueGp, Number((valuablesBudgetGp * artRatio).toFixed(2)));
  const gemBudgetTargetGp = Math.max(0, Number((valuablesBudgetGp - artBudgetTargetGp).toFixed(2)));
  const desiredArtCount = Math.max(1, Math.round(safeTargetCount * artRatio));
  const artCountTarget = Math.min(
    safeTargetCount,
    deriveLootBucketTargetCount(
      artPool,
      artBudgetTargetGp,
      desiredArtCount,
      1
    )
  );
  const remainingCount = Math.max(0, safeTargetCount - artCountTarget);
  const gemCountTarget = remainingCount > 0
    ? Math.min(
      remainingCount,
      deriveLootBucketTargetCount(
        gemPool,
        Math.max(0, gemBudgetTargetGp),
        remainingCount,
        0
      )
    )
    : 0;
  return {
    artPool,
    gemPool,
    artCountTarget,
    gemCountTarget,
    artBudgetTargetGp,
    gemBudgetTargetGp
  };
}

function getLootTreasureKindWeightModifier(draft = {}, entry = {}, selectionCategory = "") {
  const kind = normalizeLootVariableTreasureKind(entry?.variableTreasureKind);
  if (!kind) return 1;
  const mode = String(draft?.mode ?? "horde").trim().toLowerCase();
  const challenge = String(draft?.challenge ?? "mid").trim().toLowerCase();
  const category = String(selectionCategory ?? "").trim().toLowerCase();
  if (category === "valuables") {
    const artBias = {
      low: 1.08,
      mid: 1.18,
      high: 1.32,
      epic: 1.45
    };
    const gemBias = {
      low: 1.02,
      mid: 1,
      high: 0.98,
      epic: 0.95
    };
    return kind === "art"
      ? Number(artBias[challenge] ?? artBias.mid)
      : Number(gemBias[challenge] ?? gemBias.mid);
  }
  if (mode === "encounter") return kind === "art" ? 0.45 : 0.65;
  if (mode === "defeated") return kind === "art" ? 0.55 : 0.75;
  return kind === "art" ? 0.8 : 0.9;
}

function buildLootBucketBudgetContext(base = {}, targetGp = 0, targetCount = 0, options = {}) {
  const safeTargetGp = Math.max(0, Number(targetGp) || 0);
  const safeTargetCount = Math.max(1, Math.floor(Number(targetCount) || 1));
  const toleranceRatio = Math.max(0.05, Math.min(0.45, Number(base?.overshootAllowanceRatio ?? 0.2) || 0.2));
  const toleranceGp = Math.max(1, Number((safeTargetGp * toleranceRatio).toFixed(2)));
  const maxItemsRaw = Number(options?.maxItems ?? base?.maxItems ?? 0);
  const maxItems = Number.isFinite(maxItemsRaw) ? Math.max(0, Math.floor(maxItemsRaw)) : 0;
  return {
    ...base,
    selectionCategory: String(options?.selectionCategory ?? base?.selectionCategory ?? "").trim().toLowerCase(),
    effectiveTotalTargetGp: safeTargetGp,
    totalBudgetGp: safeTargetGp,
    targetItemBudgetGp: safeTargetGp,
    targetCount: safeTargetCount,
    desiredItemCount: safeTargetCount,
    targetPerItemGp: Math.max(0.5, Number((safeTargetGp / Math.max(1, safeTargetCount)).toFixed(2))),
    targetValueRangeMinGp: Math.max(0, Number((safeTargetGp - toleranceGp).toFixed(2))),
    targetValueRangeMaxGp: Number((safeTargetGp + toleranceGp).toFixed(2)),
    itemTargetValueRangeMinGp: Math.max(0, Number((safeTargetGp - toleranceGp).toFixed(2))),
    itemTargetValueRangeMaxGp: Number((safeTargetGp + toleranceGp).toFixed(2)),
    toleranceGp,
    itemToleranceGp: toleranceGp,
    maxItems,
    effectiveMaxItemValueGp: Math.max(
      Math.max(0, Number(base?.effectiveMaxItemValueGp ?? 0) || 0),
      Math.max(1, Number((safeTargetGp * 1.15).toFixed(2)))
    )
  };
}

function deriveLootBucketTargetCount(pool = [], targetGp = 0, fallbackCount = 1, minimum = 0) {
  const entries = (Array.isArray(pool) ? pool : []).filter((entry) => Math.max(0, Number(entry?.itemValueGp ?? 0) || 0) > 0);
  if (!entries.length || targetGp <= 0) return Math.max(0, Math.floor(Number(minimum) || 0));
  const sortedValues = entries
    .map((entry) => Math.max(0, Number(entry?.itemValueGp ?? 0) || 0))
    .sort((left, right) => left - right);
  const medianValue = sortedValues[Math.floor(sortedValues.length / 2)] ?? sortedValues[0] ?? 1;
  const desired = Math.round(targetGp / Math.max(1, medianValue));
  const cap = Math.max(Math.floor(Number(minimum) || 0), Math.max(1, Math.floor(Number(fallbackCount) || 1)));
  return Math.max(Math.floor(Number(minimum) || 0), Math.min(cap, Math.max(1, desired)));
}

function isLootPremiumRarity(entry = {}) {
  const bucket = getLootRarityBucket(entry?.rarity);
  return bucket === "uncommon" || bucket === "rare" || bucket === "very-rare" || bucket === "legendary";
}

function normalizeLootHordeUncommonPlusChanceMode(value, fallback = LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.BOOSTED) {
  const normalized = String(value ?? "").trim().toLowerCase();
  if (normalized === LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.STANDARD) return LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.STANDARD;
  if (normalized === LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.HIGH) return LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.HIGH;
  if (normalized === LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.GUARANTEED) return LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.GUARANTEED;
  if (normalized === LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.BOOSTED) return LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.BOOSTED;
  return fallback;
}

function getLootHordeUncommonPlusChanceMode() {
  try {
    return normalizeLootHordeUncommonPlusChanceMode(
      game.settings?.get?.(MODULE_ID, SETTINGS.LOOT_HORDE_UNCOMMON_PLUS_CHANCE),
      LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.BOOSTED
    );
  } catch {
    return LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.BOOSTED;
  }
}

function buildLootPremiumLaneConfig(draft = {}, budgetContext = {}, premiumPool = [], randomFn = Math.random) {
  const mode = String(draft?.mode ?? budgetContext?.mode ?? "horde").trim().toLowerCase();
  if (mode !== "horde") return { enabled: false, reason: "mode" };
  const pool = Array.isArray(premiumPool) ? premiumPool : [];
  if (!pool.length) return { enabled: false, reason: "pool" };
  const challenge = String(draft?.challenge ?? budgetContext?.challenge ?? "mid").trim().toLowerCase();
  const scale = String(draft?.scale ?? "medium").trim().toLowerCase();
  const profile = String(draft?.profile ?? "standard").trim().toLowerCase();
  const chanceByChallenge = { low: 0.16, mid: 0.32, high: 0.56, epic: 0.78 };
  const ratioByChallenge = { low: 0.16, mid: 0.26, high: 0.34, epic: 0.42 };
  let chance = Number(chanceByChallenge[challenge] ?? chanceByChallenge.mid);
  let ratio = Number(ratioByChallenge[challenge] ?? ratioByChallenge.mid);
  const uncommonPlusChanceMode = normalizeLootHordeUncommonPlusChanceMode(
    draft?.hordeUncommonPlusChance ?? budgetContext?.hordeUncommonPlusChance ?? getLootHordeUncommonPlusChanceMode(),
    LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.BOOSTED
  );
  if (scale === "small") {
    chance -= 0.08;
    ratio -= 0.04;
  } else if (scale === "major") {
    chance += 0.22;
    ratio += 0.16;
  }
  if (profile === "poor") {
    chance -= 0.04;
    ratio -= 0.02;
  } else if (profile === "well") {
    chance += 0.06;
    ratio += 0.03;
  }
  if (uncommonPlusChanceMode === LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.BOOSTED) {
    chance += 0.09;
    ratio += 0.03;
  } else if (uncommonPlusChanceMode === LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.HIGH) {
    chance += 0.2;
    ratio += 0.06;
  } else if (uncommonPlusChanceMode === LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.GUARANTEED) {
    chance = 1;
    ratio += 0.1;
  }
  const itemBudgetGp = Math.max(0, Number(budgetContext?.targetItemBudgetGp ?? 0) || 0);
  const targetCountRaw = Number(budgetContext?.targetCount ?? 0);
  const targetCount = Number.isFinite(targetCountRaw) && targetCountRaw > 0
    ? Math.max(1, targetCountRaw)
    : 0;
  const targetPerItemGp = Math.max(0, Number(
    budgetContext?.targetPerItemGp
    ?? (itemBudgetGp > 0 && targetCount > 0 ? itemBudgetGp / Math.max(1, targetCount) : 0)
    ?? 0
  ) || 0);
  if (targetPerItemGp >= 140 || itemBudgetGp >= 1200) {
    chance += 0.06;
    ratio += 0.04;
  }
  if (targetPerItemGp >= 260 || itemBudgetGp >= 2200) {
    chance += 0.1;
    ratio += 0.06;
  }
  if (targetPerItemGp >= 420 || itemBudgetGp >= 3600) {
    chance += 0.12;
    ratio += 0.08;
  }
  if (scale === "major") chance = Math.max(chance, 0.95);
  const normalizedChance = uncommonPlusChanceMode === LOOT_HORDE_UNCOMMON_PLUS_CHANCE_MODES.GUARANTEED
    ? 1
    : Math.max(0.02, Math.min(0.96, Number(chance.toFixed(4))));
  const normalizedRatio = Math.max(0.08, Math.min(0.55, Number(ratio.toFixed(4))));
  const roll = Math.max(0, Math.min(0.999999, Number(typeof randomFn === "function" ? randomFn() : Math.random()) || 0));
  const enabled = roll < normalizedChance;
  const targetBudgetGp = Number((itemBudgetGp * normalizedRatio).toFixed(2));
  const targetCountBase = challenge === "epic" ? 3 : challenge === "high" ? 2 : challenge === "mid" ? 2 : 1;
  const premiumTargetCount = Math.max(1, Math.min(
    scale === "major" ? targetCountBase + 1 : targetCountBase,
    pool.length
  ));
  return {
    enabled,
    roll,
    uncommonPlusChanceMode,
    chance: normalizedChance,
    budgetRatio: normalizedRatio,
    targetBudgetGp,
    targetCount: premiumTargetCount
  };
}

function buildLootPremiumLaneRarityCaps(targetCount = 0) {
  const cap = Math.max(1, Math.floor(Number(targetCount) || 1));
  return {
    uncommon: cap,
    rare: cap,
    "very-rare": cap,
    legendary: cap
  };
}

function isLootPracticalHoardFiller(entry = {}) {
  const itemType = String(entry?.itemType ?? "").trim().toLowerCase();
  const categories = new Set((Array.isArray(entry?.merchantCategories) ? entry.merchantCategories : [])
    .map((value) => String(value ?? "").trim().toLowerCase())
    .filter(Boolean));
  const keywords = new Set((Array.isArray(entry?.keywords) ? entry.keywords : [])
    .map((value) => String(value ?? "").trim().toLowerCase())
    .filter(Boolean));
  const folderPath = String(entry?.folderPathKey ?? entry?.folderProfile?.pathKey ?? "").trim().toLowerCase();
  const name = String(entry?.name ?? "").trim().toLowerCase();

  if (itemType === "consumable" || itemType === "ammo" || itemType === "ammunition") return true;
  if (categories.has("consumable") || categories.has("alchemy") || categories.has("ammunition")) return true;
  if (keywords.has("merchant.consumable") || keywords.has("merchant.ammunition")) return true;
  if (folderPath.includes("consumables/")) return true;
  if (/\b(potion|philter|elixir|tonic|scroll|ammunition|ammo|arrow|bolt|bullet|shot|ration|bandage|antitoxin|healing)\b/.test(name)) return true;
  return false;
}

function getLootGeneralLanePool(pool = [], draft = {}) {
  const mode = String(draft?.mode ?? "horde").trim().toLowerCase();
  if (mode !== "horde") return Array.isArray(pool) ? pool : [];
  const sourcePool = Array.isArray(pool) ? pool : [];
  const scale = String(draft?.scale ?? "medium").trim().toLowerCase();
  const budgetContext = buildLootValueBudgetContext(draft, 0);
  const targetItemBudgetGp = Math.max(0, Number(
    draft?.targetItemBudgetGp
    ?? budgetContext?.targetItemBudgetGp
    ?? 0
  ) || 0);
  const targetPerItemGp = Math.max(0, Number(
    draft?.targetPerItemGp
    ?? budgetContext?.targetPerItemGp
    ?? 0
  ) || 0);
  const allowBroaderPool = scale === "major" || targetPerItemGp >= 220 || targetItemBudgetGp >= 1800;
  const suppressFillerCollapse = allowBroaderPool || targetPerItemGp >= 110 || targetItemBudgetGp >= 900;
  if (allowBroaderPool) {
    return sourcePool.length > 0 ? sourcePool : [];
  }
  const practicalPool = sourcePool.filter((entry) => {
    if (isLootPremiumRarity(entry)) return false;
    return isLootPracticalHoardFiller(entry);
  });
  if (!suppressFillerCollapse && practicalPool.length >= Math.max(3, Math.floor(sourcePool.length * 0.15))) return practicalPool;
  const nonPremiumPool = sourcePool.filter((entry) => !isLootPremiumRarity(entry));
  return nonPremiumPool.length > 0 ? nonPremiumPool : sourcePool;
}

function buildPartyOperationsMetaPillsFromData(data = {}, options = {}) {
  const maxPillsRaw = Number(options?.maxPills ?? 4);
  const maxPills = Number.isFinite(maxPillsRaw) ? Math.max(1, Math.floor(maxPillsRaw)) : 4;
  const categories = getLootItemMerchantCategoriesFromData(data);
  const rarity = normalizeLootRarity(getLootRarityFromData(data));
  const tier = getLootItemTierFromData(data);
  const valueBand = getLootItemValueBandFromData(data);
  const priceDenomination = getLootItemPriceDenominationFromData(data);
  const pills = [];
  if (rarity) pills.push({ label: formatPartyOperationsWordLabel(rarity), kind: "rarity" });
  if (categories[0]) pills.push({ label: formatPartyOperationsWordLabel(categories[0]), kind: "category" });
  if (tier) pills.push({ label: formatPartyOperationsTierLabel(tier), kind: "tier" });
  if (valueBand) pills.push({ label: formatPartyOperationsValueBandLabel(valueBand), kind: "value" });
  if (priceDenomination) pills.push({ label: formatPartyOperationsPriceDenominationLabel(priceDenomination), kind: "price" });
  return pills.slice(0, maxPills);
}

function pushPartyOperationsTaxonomyCount(map, key, formatter) {
  const normalized = String(key ?? "").trim().toLowerCase();
  if (!normalized) return;
  const current = map.get(normalized) ?? {
    value: normalized,
    label: typeof formatter === "function" ? formatter(normalized) : normalized,
    count: 0
  };
  current.count += 1;
  map.set(normalized, current);
}

function finalizePartyOperationsTaxonomyRows(map, limit = 6) {
  return Array.from(map.values())
    .sort((left, right) => {
      const countDelta = Number(right?.count ?? 0) - Number(left?.count ?? 0);
      if (countDelta !== 0) return countDelta;
      return String(left?.label ?? "").localeCompare(String(right?.label ?? ""));
    })
    .slice(0, limit);
}

function buildPartyOperationsTaxonomySummaryFromDocuments(documents = []) {
  const rows = Array.isArray(documents) ? documents : [];
  const schemaCounts = new Map();
  const categoryCounts = new Map();
  const rarityCounts = new Map();
  const tierCounts = new Map();
  const valueCounts = new Map();
  const priceCounts = new Map();
  let itemCount = 0;

  for (const documentRef of rows) {
    const data = getMerchantItemData(documentRef);
    const itemType = String(data?.type ?? "").trim().toLowerCase();
    if (!itemType) continue;
    const poFlags = getPartyOperationsItemFlags(data);
    if (poFlags?.lootEligible === false) continue;
    itemCount += 1;

    pushPartyOperationsTaxonomyCount(
      schemaCounts,
      getLootItemTagSchemaFromData(data) || "legacy",
      (value) => value === "legacy" ? "Legacy Tags" : formatPartyOperationsTagSchemaLabel(value)
    );

    for (const category of getLootItemMerchantCategoriesFromData(data)) {
      pushPartyOperationsTaxonomyCount(categoryCounts, category, (value) => formatPartyOperationsWordLabel(value));
    }

    const rarity = normalizeLootRarity(getLootRarityFromData(data));
    if (rarity) pushPartyOperationsTaxonomyCount(rarityCounts, rarity, (value) => formatPartyOperationsWordLabel(value));

    const tier = getLootItemTierFromData(data);
    if (tier) pushPartyOperationsTaxonomyCount(tierCounts, tier, (value) => formatPartyOperationsTierLabel(value));

    const valueBand = getLootItemValueBandFromData(data);
    if (valueBand) pushPartyOperationsTaxonomyCount(valueCounts, valueBand, (value) => formatPartyOperationsValueBandLabel(value));

    const priceDenomination = getLootItemPriceDenominationFromData(data);
    if (priceDenomination) {
      pushPartyOperationsTaxonomyCount(priceCounts, priceDenomination, (value) => formatPartyOperationsPriceDenominationLabel(value));
    }
  }

  const schemaRows = finalizePartyOperationsTaxonomyRows(schemaCounts, 3);
  const primarySchema = schemaRows[0] ?? null;
  return {
    itemCount,
    schemaLabel: primarySchema?.label ?? "Legacy Tags",
    schemaCount: schemaRows.length,
    hasMultipleSchemas: schemaRows.length > 1,
    schemaRows,
    categoryRows: finalizePartyOperationsTaxonomyRows(categoryCounts, 8),
    rarityRows: finalizePartyOperationsTaxonomyRows(rarityCounts, 5),
    tierRows: finalizePartyOperationsTaxonomyRows(tierCounts, 5),
    valueRows: finalizePartyOperationsTaxonomyRows(valueCounts, 6),
    priceRows: finalizePartyOperationsTaxonomyRows(priceCounts, 4)
  };
}

function isLootKeywordMatch(
  itemKeywords = [],
  includeTags = [],
  excludeTags = [],
  includeMode = LOOT_KEYWORD_INCLUDE_MODES.ALL,
  options = {}
) {
  const keywords = new Set(normalizeLootKeywordTagList(itemKeywords));
  const filtersAlreadyNormalized = options?.normalizedFilters === true;
  const include = filtersAlreadyNormalized
    ? (Array.isArray(includeTags) ? includeTags : [])
    : normalizeLootKeywordTagList(includeTags);
  const exclude = filtersAlreadyNormalized
    ? (Array.isArray(excludeTags) ? excludeTags : [])
    : normalizeLootKeywordTagList(excludeTags);
  const mode = filtersAlreadyNormalized
    ? (
      String(includeMode ?? LOOT_KEYWORD_INCLUDE_MODES.ALL).trim().toLowerCase() === LOOT_KEYWORD_INCLUDE_MODES.ANY
        ? LOOT_KEYWORD_INCLUDE_MODES.ANY
        : LOOT_KEYWORD_INCLUDE_MODES.ALL
    )
    : normalizeLootKeywordIncludeMode(includeMode, LOOT_KEYWORD_INCLUDE_MODES.ALL);
  if (include.length > 0) {
    if (mode === LOOT_KEYWORD_INCLUDE_MODES.ANY) {
      if (!include.some((tag) => keywords.has(tag))) return false;
    } else if (include.some((tag) => !keywords.has(tag))) {
      return false;
    }
  }
  if (exclude.some((tag) => keywords.has(tag))) return false;
  return true;
}

function isLootRarityAllowed(rarity, floor, ceiling) {
  const rankMap = {
    common: 1,
    uncommon: 2,
    rare: 3,
    "very-rare": 4,
    legendary: 5
  };
  const normalized = normalizeLootRarity(rarity);
  if (!normalized) return true;
  const value = Number(rankMap[normalized] ?? 0);
  if (!value) return true;
  const floorValue = Number(rankMap[normalizeLootRarity(floor)] ?? 0);
  const ceilingValue = Number(rankMap[normalizeLootRarity(ceiling)] ?? 0);
  if (floorValue > 0 && value < floorValue) return false;
  if (ceilingValue > 0 && value > ceilingValue) return false;
  return true;
}

async function loadItemsFromPack(packId, options = {}) {
  const resolvedPackId = String(packId ?? "").trim();
  if (!resolvedPackId) return [];
  const pack = game.packs?.get(resolvedPackId);
  if (!pack) {
    if (Array.isArray(options.warnings)) {
      options.warnings.push(`Item source missing: ${String(options.sourceLabel ?? resolvedPackId)}.`);
    }
    if (isModuleDebugEnabled()) {
      console.warn(`${MODULE_ID}: loadItemsFromPack missing pack`, { packId: resolvedPackId });
    }
    return [];
  }

  try {
    if (typeof pack.getDocuments === "function") {
      const docs = await pack.getDocuments();
      return Array.isArray(docs) ? docs : [];
    }
    const index = await pack.getIndex({
      fields: ["type", "name", "img", "system.description.value", "system.rarity", "system.details.rarity", "system.traits.rarity", "rarity", "flags.party-operations.keywords", "flags"]
    });
    return getCollectionValues(index);
  } catch (error) {
    if (Array.isArray(options.warnings)) {
      options.warnings.push(`Could not read item source: ${String(options.sourceLabel ?? resolvedPackId)}.`);
    }
    if (isModuleDebugEnabled()) {
      console.warn(`${MODULE_ID}: loadItemsFromPack failed`, { packId: resolvedPackId, error });
    }
    return [];
  }
}

function filterItems(items, options = {}) {
  const rows = Array.isArray(items) ? items : [];
  const typeWhitelist = Array.isArray(options?.typeWhitelist)
    ? options.typeWhitelist.map((entry) => String(entry ?? "").trim()).filter(Boolean)
    : [];
  const nameIncludes = Array.isArray(options?.nameIncludes)
    ? options.nameIncludes.map((entry) => String(entry ?? "").trim().toLowerCase()).filter(Boolean)
    : [];
  const rarityKeywords = Array.isArray(options?.rarityKeywords)
    ? options.rarityKeywords.map((entry) => String(entry ?? "").trim().toLowerCase()).filter(Boolean)
    : [];

  return rows.filter((item) => {
    const data = (item && typeof item?.toObject === "function") ? item.toObject() : item;
    const itemType = String(data?.type ?? "").trim();
    const itemName = String(data?.name ?? "").trim().toLowerCase();
    const description = String(data?.system?.description?.value ?? "")
      .replace(/<[^>]+>/g, " ")
      .replace(/\s+/g, " ")
      .trim()
      .toLowerCase();

    if (typeWhitelist.length > 0 && !typeWhitelist.includes(itemType)) return false;
    if (nameIncludes.length > 0 && !nameIncludes.some((term) => itemName.includes(term))) return false;
    if (rarityKeywords.length > 0 && !rarityKeywords.some((term) => itemName.includes(term) || description.includes(term))) return false;
    return true;
  });
}

function buildWeightedPool(items, weightFn) {
  const rows = Array.isArray(items) ? items : [];
  const compute = typeof weightFn === "function" ? weightFn : ((entry) => Number(entry?.weight ?? 1));
  const pool = [];
  for (const item of rows) {
    const raw = Number(compute(item));
    const weight = Number.isFinite(raw) ? Math.max(0, raw) : 0;
    if (weight <= 0) continue;
    pool.push({ item, weight });
  }
  return pool;
}

function getLootItemGpValueFromData(data = {}) {
  const toNumber = (value) => {
    const parsed = Number(value);
    if (!Number.isFinite(parsed)) return 0;
    return Math.max(0, parsed);
  };
  const priceNode = data?.system?.price;
  if (priceNode && typeof priceNode === "object") {
    const amount = toNumber(priceNode.value ?? priceNode.amount ?? 0);
    const denomRaw = String(priceNode.denomination ?? priceNode.currency ?? "gp").trim().toLowerCase();
    const denomMap = { pp: 10, gp: 1, ep: 0.5, sp: 0.1, cp: 0.01 };
    const mult = Number(denomMap[denomRaw] ?? 1);
    return Math.max(0, amount * mult);
  }
  if (priceNode !== null && priceNode !== undefined) return toNumber(priceNode);
  if (data?.price && typeof data.price === "object") {
    const amount = toNumber(data.price.value ?? data.price.amount ?? 0);
    const denomRaw = String(data.price.denomination ?? data.price.currency ?? "gp").trim().toLowerCase();
    const denomMap = { pp: 10, gp: 1, ep: 0.5, sp: 0.1, cp: 0.01 };
    const mult = Number(denomMap[denomRaw] ?? 1);
    return Math.max(0, amount * mult);
  }
  return toNumber(data?.price ?? 0);
}

function summarizeLootCandidateValueStats(candidates = []) {
  const values = (Array.isArray(candidates) ? candidates : [])
    .map((entry) => Math.max(0, Number(entry?.itemValueGp ?? 0) || 0))
    .filter((value) => value > 0)
    .sort((a, b) => a - b);
  if (!values.length) {
    return {
      hasValues: false,
      targetValuePerItem: 0,
      spread: 1
    };
  }
  const middleIndex = Math.floor(values.length / 2);
  const median = values.length % 2 === 0
    ? (values[middleIndex - 1] + values[middleIndex]) / 2
    : values[middleIndex];
  const minValue = values[0];
  const maxValue = values[values.length - 1];
  const spread = Math.max(1, ((maxValue - minValue) * 0.6) + 1);
  return {
    hasValues: true,
    targetValuePerItem: Math.max(0.01, Number(median) || 0.01),
    spread
  };
}

