function openRestWatchPlayerApp() {
  if (canAccessAllPlayerOps()) {
    const app = openMainTab("rest-watch", { force: true });
    app?.bringToTop?.();
    return app;
  }
  const existing = Object.values(ui.windows).find((app) => app instanceof RestWatchPlayerApp);
  if (existing) {
    existing.bringToTop?.();
    return existing;
  }
  const app = new RestWatchPlayerApp(getResponsiveWindowOptions("rest-watch-player"));
  app.render({ force: true });
  return app;
}

export function emitSocketRefresh(options = {}) {
  const scopes = normalizeRefreshScopeList(options?.scopes ?? options?.scope);
  const payload = {
    type: "refresh",
    userId: game.user.id
  };
  if (scopes.length > 0) payload.scopes = scopes;
  emitModuleSocket(payload, { channel: SOCKET_CHANNEL });
}

function emitOpenRestPlayers() {
  emitModuleSocket({ type: "players:openRest" }, { channel: SOCKET_CHANNEL });
}
